import type { Sentence } from '../types/content'

export interface PassageReadingAid {
  translation: string
  analysis: string
}

// 章節輔讀採「一段原文對一段白話」；避免把語意相連的分句拆成零散提示。
const PASSAGE_AIDS: Record<string, PassageReadingAid> = {
  'dao-de-jing_ch-1_p-1': {
    translation: '能夠用言語說清楚的「道」，不是永恆常在的道；能夠用名稱完全界定的「名」，不是永恆不變的名。無名是天地開始時的狀態；有名則是萬物生長、顯現形體後的根源。常保無私無欲，能體會道無形無相的奧妙；帶著探求的意欲，則能觀察道在具體事物中所呈現的邊界與軌跡。無與有名稱不同，卻同出於道，同樣深奧玄妙；層層深入這種玄妙，便是通往萬物奧祕的門戶。',
    analysis: '「道」不是一個可以被概念完全框住的物件；老子以「無／有」說明同一根源的兩種觀看方式。無欲不是排斥一切行動，而是暫時放下私心與成見，以體會事物未分化時的根本；有欲則是從具體現象觀察道的作用。「玄之又玄」提醒人不要把一次理解當作終點。',
  },
  'dao-de-jing_ch-2_p-1': { translation: '人人都認定美是美，醜便隨之出現；人人都認定善是善，不善便隨之出現。有與無互相生成，難與易互相成就，長短、高下、聲音、前後都在對比中成立。聖人順其自然做事，不靠空話教導；讓萬物自行生長而不據為己有，成就事情而不居功。正因不居功，功業才不會失去。', analysis: '本章批判把價值絕對化；對待萬物宜少強制、多成全。' },
  'dao-de-jing_ch-3_p-1': { translation: '不過度推崇賢能，人民就不互相爭逐；不把稀有財物看得太貴重，人民就不會偷盜；不刻意展示足以引起貪欲的東西，人心便不會紛亂。好的治理讓人心少受欲望擾動、生活有所供養、意志不逞強、身體有力量；以無為的方式治理，便沒有治不好的事。', analysis: '「無知無欲」是降低權力與欲望煽動的政治語境，不是反對教育。' },
  'dao-de-jing_ch-4_p-1': { translation: '天地沒有偏愛，對萬物一視同仁，如同祭祀後任人處置的芻狗；聖人對百姓也不以私情偏待。天地之間像風箱：空虛卻不枯竭，越鼓動越能生出作用。話說得太多，反而容易陷入困境；不如守住內在的平衡。', analysis: '「不仁」指不以私愛偏私，並非殘酷無情。' },
  'dao-de-jing_ch-5_p-1': { translation: '最高的善像水。水滋養萬物而不爭，停留在人們厭惡的低處，因此最接近道。居處要選適當地方，心要深沉，待人要仁厚，說話要守信，治理要有條理，做事要有能力，行動要合時。因為不爭，所以少有怨尤。', analysis: '以水的柔、低、利物而不爭，說明理想人格的行事方式。' },
  'dao-de-jing_ch-6_p-1': { translation: '持有事物而想使它過滿，不如及時停止；把東西磨得太尖銳，無法長久保持。金玉滿堂也守不住；富貴而驕傲，是替自己留下禍患。功業完成後懂得退身，才合乎自然之道。', analysis: '本章重點是節制：過度累積與炫耀都會反噬。' },
  'dao-de-jing_ch-7_p-1': { translation: '三十根車輻匯在一個輪轂，正因中央留空，車才有載運的作用；揉土做成器皿，正因中間是空的，器皿才可盛物；開門窗建房屋，正因室內留空，房屋才可居住。所以有形的部分帶來便利，無形的空處才產生真正的用途。', analysis: '老子以器物說明「無」不是虛無，而是使功能得以發揮的條件。' },
  'dao-de-jing_ch-8_p-1': { translation: '把虛靜推到極處，牢牢守住寧靜。萬物一同生長，我看見它們終會回歸根本；回歸根本叫作靜，這是回到本來的生命秩序。知道這個常理才算明白；不知道而妄動，便有凶險。明白常理就能包容，包容而公正，公正而有統御能力，進而合於天、合於道，便能長久而終身無危。', analysis: '「復」是萬物由盛轉歸根的循環；知常使人不被一時變化牽動。' },
  'dao-de-jing_ch-9_p-1': { translation: '大道被廢棄後，才特別標舉仁義；巧智出現後，大偽詐也隨之出現；家人不和，才特別講孝慈；國家昏亂，才特別顯出忠臣。', analysis: '老子指出：某種德目被高聲標榜，往往正反映其自然秩序已受損。' },
  'dao-de-jing_ch-10_p-1': { translation: '能委曲便能保全，能彎曲便能伸直；低窪便能充盈，破舊便能更新；少反而有所得，貪多反而迷惑。聖人守住根本作為天下準則：不自我表現所以明白，不自以為是所以顯著，不自我誇伐所以有功，不自滿所以能長久。不爭，所以天下沒有人能與他爭。', analysis: '「曲則全」不是無原則退讓，而是以柔韌避免自我膨脹。' },
  'dao-de-jing_ch-11_p-1': { translation: '有一個渾然形成的存在，先於天地而生；它寂靜空闊，獨自存在而不改變，周遍運行而不窮竭，可作天下萬物的母親。我不知它的真名，姑且叫它道，又勉強稱它為大。人取法於地，地取法於天，天取法於道，道取法於自然。', analysis: '「自然」意為自己如此、順其本然，不等同於自然界。' },
  'dao-de-jing_ch-12_p-1': { translation: '能了解別人是聰明，能了解自己才算明白；能勝過別人是有力量，能戰勝自己才算強。懂得知足就是富有，能堅定實行就是有志；不失去安身立命之處便能長久，肉身雖死而精神不滅才算長壽。', analysis: '價值的中心從外在勝負轉到自知、自勝與知足。' },
  'dao-de-jing_ch-13_p-1': { translation: '道常常不以強制方式作為，卻沒有什麼不能成就。侯王若能守住它，萬物便會自行化育；若化育中又生出貪欲，就以未經雕琢的樸素來安定它。守住樸素便能少欲；少欲而安靜，天下自然安定。', analysis: '「無為」是減少妄為與干預，讓事物按其條件自我完成。' },
  'dao-de-jing_ch-14_p-1': { translation: '回返，是道運行的動態；柔弱，是道發揮作用的方式。天下萬物從有形而生，有形又從無形而來。', analysis: '老子以反轉與柔弱描述變化的根本規律。' },
  'dao-de-jing_ch-15_p-1': { translation: '名聲和生命哪個更親近？生命和財貨哪個更重要？得到和失去，哪個更使人困苦？過分愛惜必有大耗費，收藏太多必有重大損失。知足便不受辱，知道停止便沒有危險，才能長久。', analysis: '透過連串反問，提醒人重新排列生命、名利與財物的優先順序。' },
  'dao-de-jing_ch-16_p-1': { translation: '求學每天增加知識；求道每天減少私欲與人為造作。減少又減少，直到無為。無為卻沒有做不成的事。治理天下常靠少事少擾；一旦過度有為，就不足以治理天下。', analysis: '「損」是去除遮蔽本心的多餘執著，不是放棄學習或責任。' },
  'dao-de-jing_ch-17_p-1': { translation: '以無為的態度行事，把無事當作要事，把平淡當作滋味；由小看大、由少看多，以德回報怨恨。困難要在容易時處理，大事要從細微處做起。聖人不自居做大事，因此能完成大事；輕易許諾必少信用，把事看得太容易必多困難，所以聖人總把事看難，終究便沒有難事。', analysis: '本章是實踐方法：及早、從小、審慎，並以不爭回應衝突。' },
  'dao-de-jing_ch-18_p-1': { translation: '安定的事容易維持，還沒露出徵兆的事容易謀劃，脆弱的東西容易消散，細微的東西容易處理。要在事情尚未發生時著手，在混亂尚未形成時治理。合抱的大樹從細芽長起，九層高臺從一筐筐土堆起，千里遠行從腳下第一步開始。強行作為往往失敗，緊抓不放反而失去；人們做事常在快成功時失敗，若結尾也像開始一樣謹慎，便不會失敗。', analysis: '本章把無為落在務實的預防與慎終：不是不做，而是不以控制欲破壞事物的自然發展。' },
  'dao-de-jing_ch-19_p-1': { translation: '人活著時身體柔軟，死後就僵硬；草木活著時柔嫩，死後就枯槁。因此剛硬屬於死亡的一邊，柔弱屬於生命的一邊。軍隊太強盛反而不易取勝，樹木太粗壯反而容易被砍伐；強大的處在下位，柔弱的反而居上。', analysis: '老子以生命現象說明柔韌不是軟弱，而是能夠生長、適應與持久的力量。' },
  'dao-de-jing_ch-20_p-1': { translation: '天道像拉弓：高的壓低，低的抬高；多餘的減少，不足的補足。天道減去有餘以補不足；人的做法卻常相反，拿不足者的去供奉有餘者。誰能把自己的富餘用來供給天下？只有得道的人。聖人做事卻不倚仗，不停留在功勞上，也不想顯示自己賢能。', analysis: '本章以張弓比喻平衡與調節，批判資源向既得者集中的人間秩序。' },
  'dao-de-jing_ch-21_p-1': { translation: '真實可信的話通常不華麗，華麗討好的話往往不可靠；真正善良的人不靠辯駁取勝，巧辯的人未必善良；真正有見識的人不求樣樣博雜，樣樣炫示的人未必真正明白。聖人不積藏：越是替人著想，自己反而越充足；越是給予他人，自己反而越富有。天道利益萬物而不傷害；聖人做事而不爭奪。', analysis: '本章把真、善、知與分享連在一起，反對以修辭、占有或競爭作為價值尺度。' },
  'zhuangzi_ch-1_p-1': { translation: '北方幽深的大海有一條魚，叫鯤；牠大得不知有幾千里。鯤變成鳥，叫鵬；鵬的背也大得不可測量，奮力飛起時，翅膀像垂在天邊的雲。每當海上風浪轉動，牠就要遷往南方的大海；南冥就是天然的大池。', analysis: '鯤鵬的巨大與遷徙，開啟了〈逍遙遊〉對不同生命尺度與自由境界的討論。' },
  'zhuangzi_ch-1_p-2': { translation: '《齊諧》是記錄奇異事物的書，書中說：鵬遷往南冥時，拍水三千里，乘著旋風直上九萬里，憑藉六月的大風離開。地面的霧氣、塵埃和萬物，都靠氣息互相吹動。天空蒼青，真是它本來的顏色嗎？還是因為高遠而看不到盡頭？鵬從高處往下看，大概也像我們看天空一樣。', analysis: '莊子以視角的互換說明：我們以為確定的大小、遠近與顏色，都受位置限制。' },
  'zhuangzi_ch-1_p-3': { translation: '小的智慧比不上大的智慧，短暫的生命比不上長久的生命。早晨生長的菌不知道一個月的始末，寒蟬不知道四季，這是生命短促的例子。楚地的冥靈以五百年為一春、五百年為一秋；上古大椿以八千年為一春、八千年為一秋。彭祖只是因為長壽而被人稱道，眾人卻想和他相比，豈不可悲嗎？', analysis: '不同生命的時間尺度差異極大；不必拿單一標準衡量一切。' },
  'zhuangzi_ch-1_p-4': { translation: '若能順著天地的正道，駕馭陰陽風雨等自然變化，在無窮的境界中遊行，他還要依賴什麼呢？所以說：境界極高的人忘卻自我，神人不把功業據為己有，聖人不求名聲。', analysis: '「無己、無功、無名」不是沒有行動，而是不受自我、功勞與名聲束縛。' },
  'zhuangzi_ch-1_p-5': { translation: '惠子說：我有一棵大樹，人們叫它臭椿；樹幹腫大不合墨線，枝條彎曲不合規矩，長在路邊，木匠都不看。你的話也大而無用，人人都丟棄。莊子回答：你何不把大樹種在無何有之鄉、廣闊荒野，在旁邊無所作為地徘徊，在樹下自在躺臥？它不會被斧頭砍伐，萬物也不會傷害它；正因無所謂功用，又有什麼困苦呢？', analysis: '莊子反轉「有用」的標準：不合世俗用途，反而可能免於傷害，保有自在。' },
  'zhuangzi_ch-2_p-1': { translation: '南郭子綦靠著几案坐著，仰天長嘆，恍惚像失去了與自己相對的另一半。顏成子游侍立在旁，問他：人的形體真能像枯木，心真能像死灰嗎？今天靠几而坐的你，已不是從前的你。子綦說：偃，你問得好；我今天失去了「我」，你明白嗎？', analysis: '「喪我」是放下固著的自我立場，進入齊物思想的起點。' },
  'zhuangzi_ch-2_p-2': { translation: '言語不是風聲；說話的人有所要說，但所說的意義未必固定。道怎會被遮蔽而出現真偽？言語怎會被遮蔽而出現是非？道在哪裡不存在，言語又怎會有不可成立之處？道被小小的成見遮蔽，言語被華麗辭采遮蔽，因此儒家、墨家各自肯定所肯定的、否定所否定的。', analysis: '莊子指出是非爭論常由立場與修辭造成，並非道本身必然分裂。' },
  'zhuangzi_ch-2_p-3': { translation: '每件事沒有不屬於「彼」的一面，也沒有不屬於「是」的一面；從對方立場看便看不見自己，從自己立場看才知道。彼從是生，是也因彼而起；生死、可與不可也在相互轉化。聖人不執著其中一邊，而以自然之理照看它們。', analysis: '這是〈齊物論〉的核心：承認立場互生，減少把相對判斷絕對化。' },
  'zhuangzi_ch-2_p-4': { translation: '從前莊周夢見自己變成蝴蝶，飛得自在快樂，完全不知道自己是莊周。忽然醒來，才驚覺自己是莊周。不知道是莊周夢成蝴蝶，還是蝴蝶夢成莊周；莊周與蝴蝶當然有區別，這就叫萬物的變化。', analysis: '夢蝶不是否認現實，而是追問固定自我與固定界線是否可靠。' },
  'zhuangzi_ch-3_p-1': { translation: '人的生命有限，知識卻無窮；拿有限生命去追逐無窮知識，危險。已經如此還一味追求知識，更加危險。行善不要接近名聲，作惡不要接近刑罰；依循事物的中道而行，便可保全自身、養護生命、奉養父母、安享天年。', analysis: '莊子並非反對求知，而是反對無止境的外逐與名利競逐。' },
  'zhuangzi_ch-3_p-2': { translation: '庖丁替文惠君分解牛，手、肩、腳、膝與刀的動作都合乎節奏，如同舞樂。文惠君讚嘆技藝高超。庖丁說：我所喜好的是道，已超過技術。剛開始解牛時眼中只有整頭牛；三年後不再看見完整的牛。如今我用心神感應而不只用眼睛，順著牛本來的紋理，在骨節空隙下刀，因此從不碰到筋骨相連的難處。', analysis: '庖丁解牛以熟練呈現「依乎天理」：理解結構、順勢而為，便能游刃有餘。' },
  'zhuangzi_ch-3_p-3': { translation: '好廚師一年換一次刀，因為用刀切肉；普通廚師一月換一次刀，因為用刀砍骨。我這把刀用了十九年，分解數千頭牛，刀刃仍像剛磨好。骨節間有空隙，刀刃沒有厚度；以沒有厚度的刀進入有空隙處，活動空間自然很大，所以刀刃能長久如新。', analysis: '寓言以刀與縫隙說明：若能找到事物的間隙與規律，便能少耗損地處理複雜問題。' },
  'zhuangzi_ch-3_p-4': { translation: '文惠君說：說得好！我從庖丁的話中，領悟到養生之道。', analysis: '養生不只是養身，而是順著生命與事物的紋理，避免無謂耗損。' },
  'zhuangzi_ch-4_p-1': { translation: '孔子說：天下有兩件最大的戒律：一是命，二是義。子女愛父母是天性，心中不能解除；臣子事奉君主是職分，無論到哪裡都在君主的範圍之內，逃不出天地之間，這便是大戒。', analysis: '莊子在此先承認人所處的關係與限制，接著才尋找安頓內心的方法。' },
  'zhuangzi_ch-4_p-2': { translation: '順著外在處境來安遊內心，把不得已的遭遇當作養護中心的條件，已是最高境界。還要用什麼作為回報呢？不如安然接受命運；這正是困難之處。', analysis: '「託不得已以養中」不是消極屈服，而是在不能改變的處境中守住內在。' },
  'zhuangzi_ch-5_p-1': { translation: '申徒嘉說：先生門下難道也有像你這樣掌權的人嗎？你是因為自己執政才把別人看在後面嗎？我聽說：鏡子明亮時灰塵不會停留，灰塵停留便不明亮；長久和賢人相處就不會有過失。', analysis: '以明鏡比喻修養：不讓權位與私心遮蔽自己，才能保持清明。' },
  'zhuangzi_ch-5_p-2': { translation: '孔子說：生死本是極大的事，卻不能隨自己的意志改變；即使天地傾覆，也不因此遺失根本。能看清不假借外物的本真，不跟著萬物遷流，任憑萬物變化而守住根源。', analysis: '重點在安住於不受外物支配的根本，而非否認生死的重大。' },
  'zhuangzi_ch-6_p-1': { translation: '知道天所作為的，也知道人所作為的，才算達到最高的認識。知道天所作為，便能順著天性而生；知道人所作為，便用已知的來養護未知的，活盡天年而不半途夭折，這是知識的極致。', analysis: '莊子不否定人的知識，但要求知道知識的界限，並使其順應生命。' },
  'zhuangzi_ch-6_p-2': { translation: '古代的真人不特別貪戀生，也不特別厭惡死；出生時不歡欣迎接，死亡時不抗拒阻攔，只是自在來去。不忘生命的起點，不強求生命的終局；接受來臨的一切而安然，忘掉執著又回歸本然。這叫不以人心損害道，也不以人為強助天。', analysis: '「真人」不是冷漠，而是放下對生死的過度控制與恐懼。' },
  'zhuangzi_ch-6_p-3': { translation: '泉水乾涸時，魚在陸地上彼此用口氣潤濕、用泡沫相濡，還不如在江湖裡彼此忘卻。與其稱讚堯、批評桀，不如把兩者都忘掉而融入道。', analysis: '困境中的互助可貴，但莊子更嚮往使生命自然舒展、無須勉強互救的境界。' },
  'zhuangzi_ch-7_p-1': { translation: '南海的帝王叫儵，北海的帝王叫忽，中央的帝王叫渾沌。儵和忽常在渾沌之地相會，渾沌待他們很好。二人想報答恩德，說：人都有七個孔竅用來看、聽、吃、呼吸，只有渾沌沒有，我們試著替他鑿開。每天鑿一竅，第七天渾沌就死了。', analysis: '好意若以自己的標準改造他者，可能破壞其完整；寓言批判強加規範。' },
  'zhuangzi_ch-8_p-1': { translation: '秋水到來，百川灌入黃河，水勢浩大，兩岸與洲渚之間幾乎分不清牛馬。河伯因此自滿，以為天下的壯美都集中在自己身上。沿河向東到了北海，面向東方卻望不見海水盡頭，才回頭向海神若嘆息：俗話說聽到一點道理就以為沒有人比得上自己，說的正是我。', analysis: '河伯的轉變說明：視野擴大後，先前的自滿會顯出侷限。' },
  'zhuangzi_ch-8_p-2': { translation: '不能和井底的青蛙談大海，因為牠受限於狹小的住處；不能和夏天的蟲談冰，因為牠受限於短暫的季節；不能和見識偏狹的人談道，因為他受限於既有教育與觀念。', analysis: '這不是貶低任何人，而是提醒理解受經驗範圍限制，應先擴張視野。' },
  'zhuangzi_ch-9_p-1': { translation: '莊子在山中行走，看見一棵枝葉茂盛的大樹，伐木者停在旁邊卻不砍它。問原因，回答說：沒有可用之處。莊子說：這棵樹正因為不成材，才得以活盡天年。', analysis: '再次以「無用之用」挑戰功利標準：不被利用，有時正是保存生命的條件。' },
  'da-xue_ch-1_p-1': { translation: '程子說：《大學》是孔門留下的著作，是初學者進入德性修養的大門。今天要了解古人求學的步驟，主要靠此篇保存下來；依此學習，大概便不會走偏。', analysis: '這是朱熹《大學章句》的序說，交代《大學》在理學修養次第中的位置。' },
  'da-xue_ch-1_p-2': { translation: '大學的宗旨，在彰顯本有的光明德性，使人民更新向善，安住於最高的善。知道應止於何處，心志才安定；安定後才能寧靜、安穩、周詳思慮而有所得。古人要把光明德性推及天下，必先治國、齊家、修身、正心、誠意、致知，而致知在格物；從格物到天下平，根本都在修身。', analysis: '本段提出三綱領與八條目：個人修養是家庭、政治與天下秩序的根本。' },
  'da-xue_ch-2_p-3': { translation: '《康誥》說要能彰明德性；《大甲》說要回顧並敬奉天所賦的光明使命；《帝典》說要彰顯崇高德性。這些都是要求人自己把德性發揚出來。', analysis: '以古書證明「明明德」是自我修養。' },
  'da-xue_ch-3_p-4': { translation: '商湯的盤銘說：如果一天能自我更新，就要日日更新，又天天更新。《康誥》說要使人民更新；《詩經》說周雖是舊邦，天命卻常更新。所以君子修養沒有一處不盡力做到最好。', analysis: '「日日新」把修養理解為持續的自我更新。' },
  'da-xue_ch-4_p-5': { translation: '人要知道自己應安止的所在：君主安止於仁，臣子安止於敬，子女安止於孝，父母安止於慈，與人交往安止於信。君子的學問如切磋琢磨，修身使他既莊敬又有威儀，盛德至善使人民不能忘懷。', analysis: '「止於至善」落實在不同身分關係中各盡其適當德行。' },
  'da-xue_ch-5_p-6': { translation: '孔子說：審理訴訟，我和別人差不多；重要的是使人沒有訴訟。讓心術不正的人不能任意辯飾，使人民敬畏正道，這才是知道根本。', analysis: '理想治理不只在判案公平，更在形成使爭訟減少的秩序。' },
  'da-xue_ch-6_p-7': { translation: '這就叫知道根本，也就是知識達到極處。', analysis: '承接前段：先辨明根本，才算真正的致知。' },
  'da-xue_ch-7_p-8': { translation: '使意念誠實，就是不欺騙自己；君子在獨處時尤其謹慎。小人獨處時無惡不作，見到君子才掩飾；內心終會表現於外，無法長久欺瞞。財富能潤飾房屋，德性能潤飾自身，心胸寬廣身體也安舒，因此君子必須誠實自己的意念。', analysis: '「慎獨」要求即使無人看見，也不讓意念自欺。' },
  'da-xue_ch-8_p-9': { translation: '修身在於端正內心；被憤怒、恐懼、偏好或憂患牽制時，心就不正。心不在當下，看也看不見、聽也聽不聞、吃東西也不知滋味。', analysis: '本段說明情緒與注意力如何使判斷失衡，正心是修身的心理基礎。' },
  'da-xue_ch-9_p-10': { translation: '要齊家先修身，因為人對親愛、厭惡、敬畏、憐憫或輕視的人都容易有偏見。喜愛一個人卻能看見缺點，厭惡一個人卻能看見優點，天下很少有人能做到。', analysis: '家庭倫理的難點在克服親疏好惡造成的盲點。' },
  'da-xue_ch-10_p-11': { translation: '要治國先齊家，因為自己的家都不能教好，就不能教化別人。孝可用來事君，敬兄可用來事長，慈愛可用來使眾。君子必先做到自己要求別人的事，自己沒有去除的過失不可先責人，所以治國在齊家。', analysis: '重點是上位者以身作則，而非單向要求他人。' },
  'da-xue_ch-11_p-12': { translation: '要平天下先治國：上位者敬老，人民便興孝；敬長，人民便興弟；憐恤孤弱，人民便不背叛。不要把自己厭惡的事加諸他人，這叫絜矩之道。得民心便得國，失民心便失國；德是根本，財是末節。聚財於上使民離散，散財利民則民聚集；治國不應以利益為最高利益，而應以義為利。', analysis: '推己及人、民心、德財次序與政治正當性在本段構成完整論證。' },
  'zhong-yong_ch-1_p-1': { translation: '天所賦予人的叫作本性；依循本性而行叫作道；修養這條道叫作教。道不能片刻離開，能離開的就不是真道。喜怒哀樂還未發作叫中，發作而合乎節度叫和；中是天下的大本，和是天下通行的道路。中和達到極處，天地各安其位，萬物都能生長。', analysis: '開篇以性、道、教與中、和建立《中庸》的核心架構。' },
  'zhong-yong_ch-2_p-2': { translation: '仲尼說：君子依循中庸，小人反而違背中庸。君子能時時合乎中庸，是因為他保持警覺；小人違背中庸，是因為沒有忌憚。', analysis: '中庸不是折衷，而是對情境保持清醒的恰當判斷。' },
  'zhong-yong_ch-3_p-3': { translation: '仲尼說：中庸真是最高的德行了！人們長久缺少它。', analysis: '孔子感嘆中庸難行，因為它要求持續而非偶然的恰當。' },
  'zhong-yong_ch-4_p-4': { translation: '仲尼說：我知道中庸為何行不通：聰明人做得太過，愚昧人又達不到；賢德的人做得太過，不賢的人又做不到。人都愛吃喝，卻少有人能真正辨別味道。', analysis: '本章指出偏高與偏低都會失中；中庸要求在可實踐的尺度中辨味。' },
  'zhong-yong_ch-5_p-5': { translation: '仲尼說：道不能實行，我明白了：有智慧的人過度追求，愚昧的人又不肯及；道不能彰明，我明白了：賢人做得過頭，不賢者又做不到。', analysis: '再次說明中庸的難處，在於避免過與不及。' },
  'zhong-yong_ch-6_p-6': { translation: '仲尼說：舜真是大智慧的人！他喜歡問問題、善於察看淺近的話，隱藏別人的不好、表揚別人的好，抓住兩端而在百姓中取其中道，這就是舜能成為舜的原因。', analysis: '舜的智慧表現為謙問、包容與在兩端間作恰當選擇。' },
  'zhong-yong_ch-7_p-7': { translation: '仲尼說：人都說自己有智慧，卻被驅趕進網羅陷阱而不知躲避；人都說自己有智慧，選到中庸之道卻不能守一個月。', analysis: '知道與能守不同；中庸的考驗在長久實行。' },
  'zhong-yong_ch-8_p-8': { translation: '仲尼說：顏回大概接近中庸了。他選擇了善，就牢牢守在心中而不失去。', analysis: '顏回的可貴不只在知善，更在內化並持守。' },
  'zhong-yong_ch-9_p-9': { translation: '仲尼說：天下國家可以治理，爵位俸祿可以辭去，利刃可以踩過；但中庸卻未必能做到。', analysis: '以看似困難的事反襯中庸更難，因其是日常心行的工夫。' },
  'zhong-yong_ch-10_p-10': { translation: '子路問什麼是強。孔子問他要問南方的強還是北方的強，還是你自己的強？寬和教人、不報復無理，這是南方的強；披甲枕戈、死而不厭，是北方的強。君子則和而不流、獨立不懼，在國家有道時不改志，在國家無道時至死不變。', analysis: '中庸重視的強，是有原則的平和與堅守，不是逞勇。' },
  'zhong-yong_ch-11_p-11': { translation: '仲尼說：君子能安於窮困，小人一遇窮困便胡作非為。', analysis: '處境考驗人格；君子不因困厄放棄準則。' },
  'zhong-yong_ch-12_p-12': { translation: '君子遵循中庸，隱遁不被人知也不後悔；只有聖人能做到。道從夫婦日用中也能明白，但最極致處連聖人也有所不知不能行。天地雖大仍有不足，君子談大事天下容不下，談小事天下又離不開。', analysis: '中庸同時根植日用又無限深廣，拒絕把道只當作抽象高論。' },
  'zhong-yong_ch-13_p-13': { translation: '《詩經》說老鷹飛到天上，魚躍在深淵，說明道上下都能察見。君子之道從夫婦也能實行，推到高深處仍有難處。', analysis: '道遍在不同層次的生活與自然中。' },
  'zhong-yong_ch-14_p-14': { translation: '君子依照自己所處的位置做該做的事，不想越出本分。富貴時做富貴者該做的事，貧賤時做貧賤者該做的事，夷狄或患難處境也各安其位；不怨天、不尤人。', analysis: '「素位而行」是承擔當下角色，不以外在條件作為失德藉口。' },
  'zhong-yong_ch-15_p-15': { translation: '君子走得遠必從近處開始，登得高必從低處開始。詩說妻子兒女和樂如琴瑟，兄弟融洽而後家道安樂；父母歡喜，這就是孝的落實。', analysis: '大德行須由最近的人倫關係開始實踐。' },
  'zhong-yong_ch-16_p-16': { translation: '鬼神的德行多麼盛大！看不見也聽不見，卻體現在萬物之中而不可離。祭祀時人人齋戒整肅，如同鬼神在上在旁。詩說鬼神不可度量，怎能不敬畏。', analysis: '鬼神在此強調超越人眼所見的秩序與敬畏感。' },
  'zhong-yong_ch-17_p-17': { translation: '舜多麼孝！有大德、尊位、厚祿、長壽，並保全名聲。天下的父母都希望子女富貴長壽有名，唯有舜真正具備德行，因此得到這些。', analysis: '本章把德與福的理想關係表現為舜的典範。' },
  'zhong-yong_ch-18_p-18': { translation: '無憂的武王與周公能盡孝：武王承繼祖業，周公完成其事，祭祀先祖、追尊父王。周公依禮安排宗廟、爵祿、服制與祭享，使上下各得其分。', analysis: '孝被擴展為承繼文化、制度與歷史責任。' },
  'zhong-yong_ch-19_p-19': { translation: '哀公問政。孔子說：文王武王的政事都記在典籍裡；有好的人就能推行，沒有人就會廢棄。人道敏於政事，地道敏於生長；治理如蘆葦一般，須靠人培養。修身靠道，修道靠仁。', analysis: '政治制度不能離開具德之人，修身是政事的根基。' },
  'zhong-yong_ch-20_p-20': { translation: '仁是人的本性，親愛父母是仁的核心；義是合宜，尊敬賢者是義的核心。親疏、尊卑的等差，禮文的規則，都是依此而生。治理天下國家的九條要領是修身、尊賢、親親、敬大臣、體恤群臣、愛民、勸百工、柔遠人、懷諸侯。', analysis: '本章把仁義禮與政治治理連成九項可操作的綱領。' },
  'zhong-yong_ch-21_p-21': { translation: '誠是天道；努力達到誠是人道。天生就誠的人，不思考也能合乎中道；靠學習而誠的人，要選擇善並牢牢守住。', analysis: '「誠」既是宇宙的真實原理，也是人的修養目標。' },
  'zhong-yong_ch-22_p-22': { translation: '只有天下最誠的人，能盡其本性；能盡己性就能盡人性，能盡人性就能盡萬物之性，進而協助天地化育，與天地並立。', analysis: '誠由個人真實擴展為理解並成全他人與萬物。' },
  'zhong-yong_ch-23_p-23': { translation: '其次的人能在一件善事上做到誠；誠便會顯現，顯現便明著，明著便能感動，感動便能改變，改變便能化育。只有誠能改變。', analysis: '修養不必等到完美才有影響；一事真誠可逐步擴大。' },
  'zhong-yong_ch-24_p-24': { translation: '最高的誠如神明：國家將興必有吉兆，將亡必有凶兆，往往見於蓍龜與人的行動。最誠的人不必等候卜筮，也不必預先思量，便能明白、自在合中道。', analysis: '以古代語言表達深厚誠意所帶來的敏銳判斷。' },
  'zhong-yong_ch-25_p-25': { translation: '誠者自成，也能成就萬物；成己是仁，成物是知。仁知都是德性，也是合於外在世界的道理。', analysis: '誠不是內心感受而已，還包含成全自我與他物的行動。' },
  'zhong-yong_ch-26_p-26': { translation: '最誠的人不停止自己；不停止便長久，長久便能彰顯，彰顯便能廣大、厚重、高明、悠久。厚重能承載萬物，高明能覆蓋萬物，悠久能成全萬物。', analysis: '誠的持續性被比擬為天地的廣大與化育力量。' },
  'zhong-yong_ch-27_p-27': { translation: '大哉聖人的道路！洋洋盛大，發育萬物，與天同高。禮儀三百、威儀三千，等候適當的人才實行。人不修德，道就不行。', analysis: '道既有宏大原理，也有具體禮儀；必須靠有德者實踐。' },
  'zhong-yong_ch-28_p-28': { translation: '愚昧而喜歡自作主張，地位低而喜歡擅定制度，生在今世卻回復古制，這樣的人難免有禍。不是天子不可制定禮樂、制度文字；今天下車同軌、書同文、行同倫。', analysis: '本章討論制度正當性與權責，反對未具條件者任意改制。' },
  'zhong-yong_ch-29_p-29': { translation: '王者修成大道，天下遵循；行為可作準則，言語可作法則，行動可作典範。遠方的人盼望，近處的人不厭。', analysis: '政治理想在德行與制度能使遠近信服。' },
  'zhong-yong_ch-30_p-30': { translation: '仲尼繼承堯舜，以上古文王武王為典範；向上合於天時，向下合於水土。像天地一樣沒有不承載、不覆蓋的，像四時一樣運行，像日月一樣照臨。', analysis: '以天地、四時、日月比喻孔子之道的普遍與秩序。' },
  'zhong-yong_ch-31_p-31': { translation: '只有天下最聖的人，有足以統御天下的聰明、寬厚、剛毅、莊敬、文理；廣大深厚如天，淵泉不竭如淵。德行顯現時，人民敬服；言語發出時，人民相信；行動時，人民悅服。', analysis: '描繪理想聖王的德性與感召力。' },
  'zhong-yong_ch-32_p-32': { translation: '只有天下最誠的人能經綸天下的大經、立天下的大本、知天地化育。這樣的人不靠權位就尊貴，不靠財富就富足，不靠言語就受信任。', analysis: '誠被呈現為超越外在權力與財富的內在權威。' },
  'zhong-yong_ch-33_p-33': { translation: '《詩經》說衣服的華美不如內裡的素樸，君子重視內在而小人重外在。君子的道日益幽微而日益顯著；真正的德行不靠聲色，卻能感化天下。', analysis: '全篇以質勝於文收束：最高德行安靜、內在而有深遠感化。' },
  'lun-yu_ch-1_p-1': { translation: '孔子說：學習後按時溫習實踐，不也愉快嗎？有朋友從遠方來，不也快樂嗎？別人不了解自己卻不怨恨，不正是君子嗎？', analysis: '把學習、交友與不求被理解並列，作為君子修養的起點。' },
  'lun-yu_ch-1_p-2': { translation: '有子說：孝順父母、敬愛兄長卻喜歡冒犯上位者的人很少；不喜歡冒犯上位者卻喜歡作亂的人從未有過。君子先致力於根本，根本建立後道就生出；孝弟就是仁的根本。', analysis: '儒家把家庭中的敬愛看作推展仁與社會秩序的根基。' },
  'lun-yu_ch-1_p-3': { translation: '孔子說：花言巧語、裝出和善面貌的人，很少有真正的仁。', analysis: '不是反對禮貌，而是警惕以外表掩蓋內在德行的偽飾。' },
  'lun-yu_ch-1_p-4': { translation: '曾子說：我每天多次反省自己：替人辦事是否盡心？與朋友交往是否守信？老師傳授的內容是否溫習？', analysis: '日省聚焦責任、信用與學習，將修養落在可檢核的日常。' },
  'lun-yu_ch-1_p-5': { translation: '孔子說：治理有千輛兵車的國家，要嚴肅辦事並守信用，節省開支而愛護人民，按農時役使人民。', analysis: '政治德目包括信用、節用、愛民與不妨害民生。' },
  'lun-yu_ch-1_p-6': { translation: '孔子說：年輕人在家孝順，出外敬長，謹慎守信，博愛眾人並親近仁者；做到這些還有餘力，再學習典籍文章。', analysis: '德行實踐優先於知識技能，兩者並非對立。' },
  'lun-yu_ch-1_p-7': { translation: '子夏說：重視賢德勝過重視容貌，侍奉父母盡力，事奉君主肯盡其身，交友言而有信；即使說他未受過學，我也說他已經學了。', analysis: '學習的標準在品格與責任，不只在書本知識。' },
  'lun-yu_ch-1_p-8': { translation: '孔子說：君子不莊重就沒有威嚴，學習也不牢固；以忠信為主，不交不如自己的人；有過失不要怕改正。', analysis: '修養包含莊重、忠信、擇友與改過四項自我要求。' },
  'lun-yu_ch-1_p-9': { translation: '曾子說：慎重對待父母的喪事，追念久遠的祖先，人民的德性就會歸於厚道。', analysis: '對生命與祖先的敬意被視為培養社會厚德的方式。' },
  'lun-yu_ch-1_p-10': { translation: '子禽問：老師到一國總能聽到政事，是自己求來的還是人家給的？子貢說：老師以溫和、善良、恭敬、節儉、謙讓得到；他的求法和一般人不同。', analysis: '孔子以人格而非攀附取得信任與資訊。' },
  'lun-yu_ch-1_p-11': { translation: '孔子說：父親在世時看他的志向，父親去世後看他的行為；三年不改變父親合乎正道的作法，可以稱為孝。', analysis: '重點在承繼正當的家道，不能理解成不分是非地守舊。' },
  'lun-yu_ch-1_p-12': { translation: '有子說：禮的作用，以和諧最可貴，先王之道以此為美，大小事情都依循它；但只知求和而不用禮節約束，也行不通。', analysis: '和不是沒有原則的和氣，必須由禮節調節。' },
  'lun-yu_ch-1_p-13': { translation: '有子說：信用接近義，說出的話才可實踐；恭敬接近禮，便能遠離恥辱；所依靠的人不失其親近的根本，也可以尊奉。', analysis: '信、恭與關係選擇都要以義禮為準，而非流於形式。' },
  'lun-yu_ch-1_p-14': { translation: '孔子說：君子吃飯不求飽足，居住不求安逸，做事勤敏、說話謹慎，親近有道的人來校正自己，才算好學。', analysis: '好學不是累積知識，而是節制欲望並願意受正直者指正。' },
  'lun-yu_ch-1_p-15': { translation: '子貢問：貧窮不諂媚、富貴不驕傲如何？孔子說可以，但不如貧窮仍快樂、富貴仍愛好禮。子貢以切磋琢磨比喻，孔子稱許他能由已知推知未來。', analysis: '德行不止避免缺點，還要在不同處境中主動追求更高修養。' },
  'lun-yu_ch-1_p-16': { translation: '孔子說：不要憂慮別人不了解自己，要憂慮自己不了解別人。', analysis: '把焦點由求認可轉向理解他人與自我能力。' },
  'lun-yu_ch-2_p-1': { translation: '孔子說：以德行治理政治，就像北極星安居其位，眾星都環繞它。', analysis: '德治的力量在感召與定向，不只在外在命令。' },
  'lun-yu_ch-2_p-2': { translation: '孔子說：《詩經》三百篇，用一句話概括，就是思想純正而不邪僻。', analysis: '「思無邪」強調詩教使情感趨於正直。' },
  'lun-yu_ch-2_p-3': { translation: '用政令引導、刑罰整齊人民，人民只求免罰卻沒有羞恥心；用德行引導、禮來整齊，人民有羞恥心也會走上正道。', analysis: '孔子區分外在服從與內在自覺。' },
  'lun-yu_ch-2_p-4': { translation: '孔子說：十五歲立志求學，三十歲能自立，四十歲不再迷惑，五十歲明白天命，六十歲能聽進不同意見，七十歲隨心所欲也不越過規矩。', analysis: '這不是固定年齡表，而是人格成熟由學習到自由而自律的歷程。' },
  'lun-yu_ch-2_p-5': { translation: '孟懿子問孝。孔子答不要違背禮；並解釋父母活著時依禮侍奉，去世後依禮安葬祭祀。', analysis: '孝的重點在敬與合禮，不是只做形式。' },
  'lun-yu_ch-2_p-6': { translation: '孟武伯問孝。孔子說：父母只為子女的疾病憂心。', analysis: '可理解為子女要照顧身體、使父母少憂。' },
  'lun-yu_ch-2_p-7': { translation: '子游問孝。孔子說：現在所謂孝只是能供養父母；犬馬也能被供養，若沒有敬意，和供養犬馬有何分別？', analysis: '孝不能化約為物質奉養，核心是敬。' },
  'lun-yu_ch-2_p-8': { translation: '子夏問孝。孔子說最難的是和顏悅色；有事年輕人代勞，有酒食給長者，難道這就算孝嗎？', analysis: '日常態度比單一服務更能表現孝敬。' },
  'lun-yu_ch-2_p-9': { translation: '孔子說：我整天和顏回說話，他從不反駁，像很愚鈍；但私下觀察他，足以發揮所學，所以顏回並不愚鈍。', analysis: '學習不等於當場爭辯，理解要看能否內化發揮。' },
  'lun-yu_ch-2_p-10': { translation: '孔子說：看一個人做事的動機，觀察他走過的途徑，察看他安於什麼；人怎能隱藏得住呢？', analysis: '評人要看動機、方法與長期安好，不可只看表面。' },
  'lun-yu_ch-2_p-11': { translation: '孔子說：溫習舊知識而有新的體會，可以做老師。', analysis: '教師資格在能由舊知開新知。' },
  'lun-yu_ch-2_p-12': { translation: '孔子說：君子不只是像一件只能做單一用途的器具。', analysis: '君子應有通達的判斷與德性，不被狹窄功能限定。' },
  'lun-yu_ch-2_p-13': { translation: '子貢問君子。孔子說：先做到自己要說的話，然後再說出來。', analysis: '言行一致，行動先於宣稱。' },
  'lun-yu_ch-2_p-14': { translation: '孔子說：君子能普遍與人合作卻不結黨偏私；小人結黨偏私卻不能普遍合作。', analysis: '「周」是公正包容，「比」是私相依附。' },
  'lun-yu_ch-2_p-15': { translation: '孔子說：只學習不思考會迷惘；只思考不學習會危險。', analysis: '學與思需要相互校正。' },
  'lun-yu_ch-2_p-16': { translation: '孔子說：專攻不正當或偏狹的學說，危害就大了。', analysis: '「異端」在此指偏離正道而固執的主張，非泛指一切不同意見。' },
  'lun-yu_ch-2_p-17': { translation: '孔子對子路說：知道的就承認知道，不知道的就承認不知道，這才是真正的知。', analysis: '知識以誠實承認界限為起點。' },
  'lun-yu_ch-2_p-18': { translation: '子張想求取俸祿。孔子說：多聽而保留疑問，慎說其餘，便少過失；多看而保留危險，慎行其餘，便少後悔。說少過失、做少後悔，俸祿自然在其中。', analysis: '求仕的正路是審慎學習與行動，不是鑽營。' },
  'lun-yu_ch-2_p-19': { translation: '哀公問怎樣使人民服從。孔子答：提拔正直的人，放在邪曲的人之上，人民就服；提拔邪曲的人，放在正直者之上，人民便不服。', analysis: '用人是政治信任的關鍵。' },
  'lun-yu_ch-2_p-20': { translation: '季康子問怎樣使人民敬畏、忠誠、勤勉。孔子答：以莊重面對人民，他們就敬；以孝慈對待，他們就忠；舉用善者並教育能力不足者，他們就勤勉。', analysis: '政治感召來自上位者的態度、德行與教化。' },
  'lun-yu_ch-2_p-21': { translation: '有人問孔子為何不從政。孔子引用《書經》說：孝敬父母、友愛兄弟，推及政治，這也是從政，何必只有做官才算從政？', analysis: '政治包含日常倫理的外溢，不限於官職。' },
  'lun-yu_ch-2_p-22': { translation: '孔子說：人若沒有信用，不知怎麼能立身；大車沒有車轅橫木，小車沒有轅端的鍵，怎麼行走？', analysis: '信是社會交往得以運作的基本結構。' },
  'lun-yu_ch-2_p-23': { translation: '子張問十代以後能否預知。孔子說：商承襲夏禮，周承襲商禮，增減之處可知；後世若繼承周，也可由禮的原則推知。', analysis: '歷史有制度傳承與變化的規律，不是全然不可理解。' },
  'lun-yu_ch-2_p-24': { translation: '孔子說：祭祀不該祭的鬼神是諂媚；看見合乎義的事卻不做，是沒有勇氣。', analysis: '禮要真誠合分，勇則在見義能行。' },
  'lun-yu_ch-3_p-1': {
    translation: '孔子批評季氏說：「他竟在自家庭院使用八佾舞的規格；這種越禮的事若都能容忍，還有什麼不能容忍呢？」',
    analysis: '八佾是天子專用的舞列。孔子藉此指出：禮不只是外表排場，也是在維持身分、權責與政治秩序的界線。',
  },
  'lun-yu_ch-3_p-2': {
    translation: '孟孫、叔孫、季孫三家，在祭祀結束撤下祭品時，竟使用《雍》詩的樂章。孔子說：「詩中說『諸侯輔佐天子，天子神態莊嚴』，怎麼能用在你們三家的宗廟裡？」',
    analysis: '孔子以詩與祭祀制度批評三家僭用天子之禮；問題不在音樂本身，而在權力逾越名分。',
  },
  'lun-yu_ch-3_p-3': {
    translation: '孔子說：「一個人若沒有仁心，禮對他有什麼意義？一個人若沒有仁心，音樂對他又有什麼意義？」',
    analysis: '仁是禮樂的內在根本。若只有儀式和聲音、沒有真誠的仁心，禮樂便失去教化人的作用。',
  },
  'lun-yu_ch-3_p-4': {
    translation: '林放請教禮的根本。孔子說：「這問得很好。禮儀與其過度奢華，寧可節儉；喪禮與其每個程序都做得很周全，寧可真誠哀傷。」',
    analysis: '孔子不是反對禮，而是把真情與節制放在繁文縟節之前：禮要回到敬意，喪要回到哀思。',
  },
  'lun-yu_ch-3_p-5': {
    translation: '孔子說：「即使夷狄有君主，也還不如諸夏沒有君主那樣。」',
    analysis: '此句反映春秋時代以禮樂文明判別政治秩序的觀點；重點是批評失去禮義與制度的混亂，而非可直接套用為現代的族群高下判斷。',
  },
  'lun-yu_ch-3_p-6': {
    translation: '季氏要到泰山舉行祭祀。冉有阻止不了，孔子說：「難道連泰山的神都不如林放懂禮嗎？」',
    analysis: '泰山祭祀有嚴格的身分規範。孔子責備冉有未能勸止季氏，也再次批評權臣越過應有的禮制。',
  },
  'lun-yu_ch-3_p-7': {
    translation: '孔子說：「君子沒有什麼事要與人爭；若一定要爭，大概只有射箭比賽吧。比賽前後彼此作揖、相讓，結束後一起飲酒，這樣的競爭才是君子的競爭。」',
    analysis: '孔子並未否定競爭，而是要求競爭受到禮節節制：較量技藝，不傷和氣，也不損害人格。',
  },
  'lun-yu_ch-3_p-8': {
    translation: '子夏問《詩經》「巧笑倩兮，美目盼兮，素以為絢兮」的意思。孔子說：「先有白底，才能繪上彩色。」子夏說：「那麼禮是在人的本質之後才形成的嗎？」孔子說：「商啊，能啟發我了；現在可以同你談《詩》了。」',
    analysis: '白底比喻質樸的本性，彩繪比喻文飾與禮。孔子肯定子夏理解到：禮應建立在真實的人性與德性上。',
  },
  'lun-yu_ch-3_p-9': {
    translation: '孔子說：「夏代的禮，我能說明，但杞國的文獻不足以證實；殷代的禮，我能說明，但宋國的文獻也不足以證實。這是因為文獻和賢才都不夠；若足夠，我便能據此證明。」',
    analysis: '孔子重視歷史傳承，也重視可查考的文獻與能承傳制度的人；論禮不能只靠傳說或個人臆測。',
  },
  'lun-yu_ch-3_p-10': {
    translation: '孔子說：「禘祭從第一次灌酒之後的儀節，我不想再看了。」',
    analysis: '禘祭是隆重祭禮。孔子對當時儀禮失真深感不滿，所以以「不欲觀」表達批評，而非單純厭惡祭祀。',
  },
  'lun-yu_ch-3_p-11': {
    translation: '有人問孔子禘祭的道理。孔子說：「我不知道。知道這道理而能治理天下的人，看天下就會像把東西放在手掌上一樣容易。」他指著手掌說。',
    analysis: '孔子以不輕率作答示範慎言；並藉禘祭說明，掌握祭祀背後的敬祖、名分與秩序原理，關乎治國的根本。',
  },
  'lun-yu_ch-3_p-12': {
    translation: '孔子祭祖時，好像祖先就在面前；祭神時，好像神明就在面前。他又說：「我若沒有親自參與祭祀，就等於沒有祭祀。」',
    analysis: '「如在」不是要求迷信，而是要求祭者全心在場。儀式的價值取決於敬意與親身投入。',
  },
  'lun-yu_ch-3_p-13': {
    translation: '孔子說：「與其討好掌管內室的神，不如討好掌管灶頭的神。」又說：「若得罪了天，便沒有地方可以祈求了。」',
    analysis: '前句是當時俗語；孔子把話鋒轉向最高原則：若違背天理與正道，靠鑽營、討好任何人都無法補救。',
  },
  'lun-yu_ch-3_p-14': {
    translation: '孔子說：「周朝借鑑夏、殷兩代的制度，文化多麼豐盛啊！我遵從周朝的制度。」',
    analysis: '孔子所說的「從周」並非盲目復古，而是肯定周禮綜合前代經驗、能承載倫理秩序的價值。',
  },
  'lun-yu_ch-3_p-15': {
    translation: '孔子進入太廟後，每件事都要詢問。有人說：「誰說鄹人的兒子懂禮？進太廟每件事都問。」孔子說：「這正是禮啊。」',
    analysis: '知禮不是自以為無所不知。面對莊重場合願意查問、避免武斷，正是敬慎的禮貌。',
  },
  'lun-yu_ch-3_p-16': {
    translation: '孔子說：「射箭不以射穿靶心的皮革為主要標準，因為每個人的力氣不同；這是古時相傳的規矩。」',
    analysis: '禮的目的不是用單一結果羞辱或淘汰人，而是在公平條件下觀察技藝、態度與分寸。',
  },
  'lun-yu_ch-3_p-17': {
    translation: '子貢想把每月初一告祭所用的活羊省去。孔子說：「賜啊，你愛惜那隻羊；我愛惜的是這項禮。」',
    analysis: '孔子承認節省資源的考量，卻提醒不能只看成本；制度若承載共同記憶與敬意，廢除前要理解它真正失去的是什麼。',
  },
  'lun-yu_ch-3_p-18': {
    translation: '孔子以最周全的禮節侍奉國君，別人卻以為他是在諂媚。',
    analysis: '恭敬容易被誤會為討好。孔子藉此區分：合乎原則的敬與為私利逢迎，動機並不相同。',
  },
  'lun-yu_ch-3_p-19': {
    translation: '定公問：「君主如何使用臣子，臣子如何侍奉君主？」孔子回答：「君主要依禮使用臣子；臣子要以忠心侍奉君主。」',
    analysis: '孔子提出雙向責任：君主不能任意使喚，臣子也不能失職。政治倫理不是單方面要求服從。',
  },
  'lun-yu_ch-3_p-20': {
    translation: '孔子評論《關雎》說：「它歡樂卻不放蕩，哀傷卻不傷害人。」',
    analysis: '孔子欣賞情感能真實流露又保持節制；這也是儒家所說「中和」在文學與生活中的表現。',
  },
  'lun-yu_ch-3_p-21': {
    translation: '哀公問宰我關於社祭的事。宰我說：「夏后氏栽松，殷人栽柏，周人栽栗，意思是要使百姓戰慄。」孔子聽後說：「已成的事不必再說，已做的事不必再勸，過去的事不必再追究。」',
    analysis: '孔子不贊同以恐懼解釋或操弄祭祀；後三句也表達處理既成過失時，應把力氣放在當下的修正，而非無止盡追責。',
  },
  'lun-yu_ch-3_p-22': {
    translation: '孔子談到管仲說：「他器量小。」有人問：「管仲很節儉嗎？」孔子說：「他有三處住宅，家臣不兼任職務，怎能說節儉？」又問：「他懂禮嗎？」孔子說：「國君設屏風，管仲也設；國君招待諸侯設的酒器，管仲也設；若說管仲懂禮，那誰不懂禮？」',
    analysis: '孔子肯定管仲的功業，仍能批評其生活僭奢與禮制失當；評價人物不可因一項成就而掩蓋其他問題。',
  },
  'lun-yu_ch-3_p-23': {
    translation: '子語魯國太師談音樂說：「奏樂是可以明白的：開始合奏時，聲音要齊整；展開後要和諧、清楚，各部分依序相續，這樣才完成。」',
    analysis: '孔子以音樂說明秩序不是僵硬的一致：有共同起點，也有各聲部的和諧與條理，正如理想的社會協作。',
  },
  'lun-yu_ch-3_p-24': {
    translation: '儀地的封人請求見孔子，說：「凡是有君子來到這裡，我從未沒有見到。」隨從安排他相見。出來後他對眾人說：「諸位何必擔心沒有官位？天下長久失道，天將要讓夫子成為傳布教化的木鐸。」',
    analysis: '「木鐸」是發布政令時搖的鈴，這裡比喻傳道者。此段寄望孔子能在失序時代傳揚正道與教化。',
  },
  'lun-yu_ch-4_p-1': { translation: '孔子說：「住在有仁德風氣的地方最好；若選住處卻不選有仁德的地方，怎能算有智慧？」', analysis: '環境會影響人的習慣與志向。孔子以「里仁」提醒人主動選擇有助於德行的生活圈。' },
  'lun-yu_ch-4_p-2': { translation: '孔子說：「不仁的人不能長久安於困境，也不能長久安於安樂。仁者安於仁，不仁者只是把仁當作有利可圖的事。」', analysis: '仁不是情況好時才採取的策略；它是能在順逆處境都安頓自己的內在價值。' },
  'lun-yu_ch-4_p-3': { translation: '孔子說：「只有仁者能真正喜愛人，也能真正厭惡人。」', analysis: '有仁心的人不被私心蒙蔽，才能在愛憎之間維持公正，知道該親近什麼、拒絕什麼。' },
  'lun-yu_ch-4_p-4': { translation: '孔子說：「一個人若立志於仁，就不會去做壞事。」', analysis: '志向具有方向性。以仁為最高目標，並不保證毫無過失，卻能使人不以惡為選擇。' },
  'lun-yu_ch-4_p-5': { translation: '孔子說：「富貴是人人想要的；若不用正當方法取得，君子不會接受。貧賤是人人厭惡的；若不能用正當方法擺脫，君子也不逃避。君子離開仁，怎能成名為君子？即使倉促間、顛沛流離時，也不能違背仁。」', analysis: '富貴與困厄都會考驗人。君子的底線是：不能為了處境而放棄正道與仁。' },
  'lun-yu_ch-4_p-6': { translation: '孔子說：「我從未見過真正喜愛仁、真正厭惡不仁的人。喜愛仁的人把仁看得最高；厭惡不仁的人不讓不仁之事接近自己。有人能把力量全用在仁上一天嗎？我還沒見過力量不夠的人；也許有，只是我沒見到。」', analysis: '孔子認為實踐仁未必欠缺能力，常欠缺的是堅定的愛好與持續的投入。' },
  'lun-yu_ch-4_p-7': { translation: '孔子說：「人的過失各有類型；觀察一個人犯什麼錯，也能知道他是否有仁心。」', analysis: '不必把過錯浪漫化，但錯誤常會暴露人的價值取向：是出於貪利、怯懦，還是出於可理解卻失當的執著。' },
  'lun-yu_ch-4_p-8': { translation: '孔子說：「早晨聽聞了正道，晚上死去也沒有遺憾。」', analysis: '「聞道」指真正理解並願意遵行人生正道。此句強調精神方向的重要，並非鼓勵輕視生命。' },
  'lun-yu_ch-4_p-9': { translation: '孔子說：「讀書人若心繫正道，卻以穿得不好、吃得不好為恥，就不值得和他談正道。」', analysis: '孔子反對把物質體面置於價值追求之前；這不是否定生活需求，而是指出羞恥感應有更高的標準。' },
  'lun-yu_ch-4_p-10': { translation: '孔子說：「君子處世，沒有一定要怎樣、一定不要怎樣；只以合乎義為依歸。」', analysis: '「義」是判斷合宜與正當的原則。君子不固執成見，也不隨波逐流。' },
  'lun-yu_ch-4_p-11': { translation: '孔子說：「君子心裡想的是義；小人心裡想的是利。」', analysis: '這是兩種優先順序的對比：不是說君子不能談利益，而是不能讓私利主宰判斷。' },
  'lun-yu_ch-4_p-12': { translation: '孔子說：「一味依照私利行事，怨恨就會很多。」', analysis: '若人人只計較得失，關係容易陷入競逐與傷害；義能為利益行為設下界線。' },
  'lun-yu_ch-4_p-13': { translation: '孔子說：「能以禮讓治理國家，還有什麼困難？若不能以禮讓治理國家，禮又有什麼用呢？」', analysis: '禮不只是儀式，還包含尊重、克制與讓步；它若不能化為政治實踐，便只剩空殼。' },
  'lun-yu_ch-4_p-14': { translation: '孔子說：「不在那個職位，就不謀劃那個職位上的政事。」', analysis: '這提醒人尊重責任分工，不越權妄議；也意味著在自己職責內應確實承擔。' },
  'lun-yu_ch-4_p-15': { translation: '孔子說：「參啊！我的道是一以貫之的。」曾子說：「是。」孔子出去後，門人問曾子是什麼意思。曾子說：「老師的道，不過是忠與恕罷了。」', analysis: '「忠」是盡己之心，「恕」是推己及人。兩者把修身與待人連成孔子思想的核心線索。' },
  'lun-yu_ch-4_p-16': { translation: '孔子說：「君子明白的是義，小人明白的是利。」', analysis: '「喻」是了解、領會。孔子再次指出，長期的判斷習慣會形成不同的人格方向。' },
  'lun-yu_ch-4_p-17': { translation: '孔子說：「見到賢人，要想著向他看齊；見到不賢的人，要回頭檢查自己是否也有同樣問題。」', analysis: '學習不只向好榜樣取經，也把他人的失誤當作自我反省的鏡子。' },
  'lun-yu_ch-4_p-18': { translation: '孔子說：「侍奉父母時，若要勸諫，應委婉和氣；若見父母不接受，仍要恭敬，不可違逆；即使辛勞憂心，也不要怨恨。」', analysis: '孔子要求孝不等於盲從，而是在親情與倫理間，以敬意和耐心進行勸諫。' },
  'lun-yu_ch-4_p-19': { translation: '孔子說：「父母在世時，子女不要遠遊；若一定要出門，必須有固定去處。」', analysis: '在交通與訊息不便的時代，這是使父母安心、便於相互照應的要求；可理解其核心為責任與聯繫。' },
  'lun-yu_ch-4_p-20': { translation: '孔子說：「三年內不改變父親的做法，可以稱得上孝。」', analysis: '這句重在守喪期間承續父志與家庭秩序，不宜理解為明知父親做錯仍永不改正；儒家另有「幾諫」的要求。' },
  'lun-yu_ch-4_p-21': { translation: '孔子說：「父母的年紀不可不知道：一方面因長壽而歡喜，一方面也因年老而憂心。」', analysis: '孝不止是供養，也包含對父母生命歷程的感念、陪伴與及時關懷。' },
  'lun-yu_ch-4_p-22': { translation: '孔子說：「古人不輕易說出口，是因為覺得做不到會感到羞愧。」', analysis: '慎言不是沉默，而是讓承諾與行動相稱，避免用漂亮話取代實際責任。' },
  'lun-yu_ch-4_p-23': { translation: '孔子說：「因為節制而犯錯的人很少。」', analysis: '「約」指節制、收斂。克制欲望與言行雖不能取代判斷，卻能減少越界與失當。' },
  'lun-yu_ch-4_p-24': { translation: '孔子說：「君子說話遲緩，行動卻敏捷。」', analysis: '與上一句相呼應：少些誇言，多些實踐，讓可見的行動為言語負責。' },
  'lun-yu_ch-4_p-25': { translation: '孔子說：「德行不孤單，必定會有同道的人相伴。」', analysis: '真正持守德行的人未必立刻得到眾人稱許，但其價值會吸引能理解並共同實踐的人。' },
  'lun-yu_ch-4_p-26': { translation: '子游說：「侍奉國君時，勸諫太多會招致羞辱；與朋友相處時，勸告太多也會逐漸疏遠。」', analysis: '勸諫要有分寸與時機。關心他人不等於反覆施壓，否則反而損害關係與善意。' },
  'lun-yu_ch-5_p-1': { translation: '孔子說公冶長可以娶妻；他雖曾被囚禁，並不是他的罪過，於是把女兒嫁給他。孔子又說南容在國家有道時不會被棄置，無道時能免於刑戮，便把姪女嫁給他。', analysis: '孔子選女婿看重人格與處世能力，不以一時遭遇判斷人，也看重人在亂世能守住原則。' },
  'lun-yu_ch-5_p-2': { translation: '孔子評論子賤說：「這人真是君子！魯國若沒有君子，他從哪裡學得這樣的品格？」', analysis: '個人成長離不開師友與社群。孔子藉稱讚子賤，也肯定魯國尚有可承傳的君子風氣。' },
  'lun-yu_ch-5_p-3': { translation: '子貢問自己怎麼樣。孔子說：「你像一件器皿。」子貢問是什麼器皿，孔子說：「是祭祀用的瑚璉。」', analysis: '瑚璉是珍貴禮器，表示子貢才幹可貴；但「器」也暗示專才與完整的君子人格仍有差別。' },
  'lun-yu_ch-5_p-4': { translation: '有人說冉雍有仁心但不善言辭。孔子說：「何必善辯？靠伶牙俐齒應付人，常會惹人厭惡。不知道他是否仁，何必要求口才呢？」', analysis: '孔子不把口才當成德行的證明，提醒人分辨能言善道與真正的仁。' },
  'lun-yu_ch-5_p-5': { translation: '孔子勸漆雕開出仕。他回答：「我對這件事還沒有足夠把握。」孔子很高興。', analysis: '知道自己尚未準備好，比急於求仕更可貴。孔子欣賞這種誠實的自知與謹慎。' },
  'lun-yu_ch-5_p-6': { translation: '孔子說：「我的道行不通了，只好坐木筏漂到海外。跟隨我的大概是仲由吧？」子路聽了很高興。孔子說：「由的勇敢超過我，只是找不到可用來造筏的木材。」', analysis: '孔子以玩笑表達政治理想受挫，也藉此提醒子路：勇敢須受判斷與才能節制。' },
  'lun-yu_ch-5_p-7': { translation: '孟武伯問子路、冉求、公西赤是否仁。孔子分別說：子路可管理千乘之國的軍政，冉求可治理千戶邑或百乘之家，公西赤可穿禮服接待賓客；但他不知道三人是否達到仁。', analysis: '行政、經濟、外交才能都不等於仁。孔子把專業能力與最高德性清楚分開。' },
  'lun-yu_ch-5_p-8': { translation: '孔子問子貢與顏回誰更好。子貢說自己不敢比，顏回聽到一點能推知十點，自己只能推知兩點。孔子說：「是不如他；我和你都不如他。」', analysis: '孔子坦率承認顏回的悟性，也用「我和你」減輕比較的羞辱，示範謙遜與誠實。' },
  'lun-yu_ch-5_p-9': { translation: '宰予白天睡覺。孔子說：「腐朽的木頭不能雕刻，糞土砌的牆不能粉飾，對宰予又何必責罰？」又說：「從前我聽人說話便相信他的行為；如今我聽人說話，還要看他的行為。這是因宰予而改變的。」', analysis: '後段比前段更重要：孔子由事件修正自己的識人方法，主張以行動驗證言語。' },
  'lun-yu_ch-5_p-10': { translation: '孔子說：「我沒有見過剛毅的人。」有人說申棖，孔子說：「申棖多欲，怎能算剛毅？」', analysis: '剛毅不是逞強；若被欲望牽著走，便缺少自主與內在定力。' },
  'lun-yu_ch-5_p-11': { translation: '子貢說：「我不願別人加在我身上的事，我也不願加在別人身上。」孔子說：「賜啊，這還不是你能完全做到的。」', analysis: '這是「恕」的高標準。孔子不是否定理想，而是提醒子貢不要把容易說的原則當成已做到的德行。' },
  'lun-yu_ch-5_p-12': { translation: '子貢說：「老師在文章禮樂方面的話，我們可以聽到；老師談人的本性與天道的話，卻很少能聽到。」', analysis: '孔子教學多從可實踐的倫理與制度入手，對抽象形上問題說得較少、也更審慎。' },
  'lun-yu_ch-5_p-13': { translation: '子路一聽到道理，還沒能做到，就怕又聽到新的道理。', analysis: '子路重視立即實踐，不願以累積知識掩蓋行動不足；但也需避免魯莽。' },
  'lun-yu_ch-5_p-14': { translation: '子貢問孔文子為何得到「文」的諡號。孔子說：「他敏捷又好學，且不以向地位較低的人請教為恥，所以稱為文。」', analysis: '真正的好學需要放下身分優越感；能下問是持續成長的條件。' },
  'lun-yu_ch-5_p-15': { translation: '孔子評論子產有君子之道四項：自己行事恭敬，侍奉上級恭敬，養育百姓有恩惠，使用百姓合乎義。', analysis: '孔子以四項具體標準評價政治人物，把個人修養與公共治理連結起來。' },
  'lun-yu_ch-5_p-16': { translation: '孔子說：「晏平仲很會和人交往；交情久了，仍能保持敬意。」', analysis: '關係長久後容易失去分寸；持續的尊重，是友誼能不被熟悉磨損的原因。' },
  'lun-yu_ch-5_p-17': { translation: '孔子說：「臧文仲把大龜安置在豪華的屋裡，柱頭刻山、短柱飾水草，這怎能算明智呢？」', analysis: '孔子批評把禮器與珍物過度奢飾，顯示智慧包含知道何處該節制，而非只會炫耀。' },
  'lun-yu_ch-5_p-18': { translation: '子張問子文三度任令尹不喜、三度被罷免不怨，且交代政務，是否仁。孔子說只能算忠。又問陳文子離開弒君的崔氏，到別國仍嫌其大夫像崔氏而離去，是否仁。孔子說只能算清白。', analysis: '孔子肯定忠誠與清白，卻不輕易稱為仁；仁是更全面、更難斷定的德性。' },
  'lun-yu_ch-5_p-19': { translation: '季文子每件事思考三次才行動。孔子聽了說：「想兩次就可以了。」', analysis: '審慎重要，但過度反覆會失去行動時機；合宜的判斷需要思慮與決斷兼具。' },
  'lun-yu_ch-5_p-20': { translation: '孔子說：「甯武子在國家有道時顯出智慧，無道時卻像愚人。他的智慧容易學到，這種裝愚自保卻難學。」', analysis: '亂世中不逞才露能，是一種保全原則與生命的政治智慧，不等於真正愚昧。' },
  'lun-yu_ch-5_p-21': { translation: '孔子在陳國說：「回去吧！回去吧！我們那裡的年輕人志氣高、文章燦爛，卻不知道怎樣加以裁成。」', analysis: '孔子想念弟子，也指出教育不能只欣賞才華，還要幫助其形成尺度與方向。' },
  'lun-yu_ch-5_p-22': { translation: '孔子說：「伯夷、叔齊不老是記著別人的舊惡，所以怨恨很少。」', analysis: '不念舊惡不是放棄是非，而是不讓報復與怨氣長久支配內心和關係。' },
  'lun-yu_ch-5_p-23': { translation: '孔子說：「誰說微生高正直？有人向他借醋，他卻向鄰居借來給人。」', analysis: '孔子認為這種為維持名聲而繞彎的做法不夠坦直；正直也包含真實說明自己的所有與限制。' },
  'lun-yu_ch-5_p-24': { translation: '孔子說：「花言巧語、裝出和善、過分恭敬，左丘明以此為恥，我也以此為恥；心裡藏著怨恨卻仍和對方交友，左丘明以此為恥，我也以此為恥。」', analysis: '孔子反對表面討好與內心不誠，主張言行和情感應盡量真實一致。' },
  'lun-yu_ch-5_p-25': { translation: '顏淵、子路侍坐。孔子要他們各說志向：子路願與朋友共享車馬衣裘，壞了也不抱怨；顏淵願不誇耀優點、不把勞苦加給人。孔子說自己的志向是讓老人安適、朋友信任、年少者懷念。', analysis: '三人的志向由共享財物、自我謙抑，推進到普遍關懷。孔子的理想是一種能安老、信友、育幼的社會關係。' },
  'lun-yu_ch-5_p-26': { translation: '孔子說：「算了吧！我還沒見過能看見自己的過錯，並在心裡責備自己的人。」', analysis: '改過的起點是內省。把責任完全推給外界，就難以真正修正。' },
  'lun-yu_ch-5_p-27': { translation: '孔子說：「十戶人家的小地方，必有像我這樣忠誠守信的人，只是不如我愛好學習罷了。」', analysis: '孔子不自誇德行獨特，而把自己可自許之處放在持續學習，展現謙遜與好學的價值。' },
  'lun-yu_ch-6_p-1': { translation: '孔子說冉雍可以面向南方做君主。仲弓問子桑伯子，孔子說他可以，為人簡約。仲弓說：內心敬慎而做事簡約以治理百姓可以；若自己散漫又做事簡約，恐怕太簡慢了。孔子認同。', analysis: '治理的簡約必須以敬慎為根；少繁瑣不等於草率。' },
  'lun-yu_ch-6_p-2': { translation: '哀公問誰最好學。孔子說顏回好學，他不遷怒於人、不重犯同樣過錯；可惜早逝，如今再沒聽說這樣好學的人。', analysis: '好學不只是讀書，而是能管理情緒並真正改過。' },
  'lun-yu_ch-6_p-3': { translation: '子華出使齊國，冉求替他母親求米。孔子先准一釜，再加一庾，冉求卻給五秉。孔子說子華出使時車馬衣服都很好，君子應救急而非錦上添花。原思辭謝薪米，孔子則要他收下並可分給鄉里。', analysis: '施與要看受助者實際需要，也鼓勵把資源再用於周濟鄰里。' },
  'lun-yu_ch-6_p-4': { translation: '孔子對仲弓說：「耕牛生的小牛若毛色赤、角長得好，即使想不用來祭祀，山川之神難道會捨棄它嗎？」', analysis: '孔子以祭牲比喻仲弓：出身不理想，不會掩蓋一個人的優秀德才。' },
  'lun-yu_ch-6_p-5': { translation: '孔子說：「顏回能長達三個月心裡不違背仁；其他人只是偶爾一日或一月做到。」', analysis: '難處不在偶然行善，而在長久穩定地以仁作為內心準則。' },
  'lun-yu_ch-6_p-6': { translation: '季康子問子路、子貢、冉求能否從政。孔子說子路果決、子貢通達、冉求多才藝，從政都沒有問題。', analysis: '孔子按各人特質評估任用，顯示政治需要多種能力。' },
  'lun-yu_ch-6_p-7': { translation: '季氏要任命閔子騫為費邑長官。閔子騫請人替他婉拒，若再來徵召，他必搬到汶水以北。', analysis: '閔子騫不願為季氏服務，寧可遠去，表現出對政治環境的道德選擇。' },
  'lun-yu_ch-6_p-8': { translation: '伯牛生病，孔子從窗戶握著他的手說：「要失去他了，這是命啊！這樣的人竟得了這樣的病！」', analysis: '孔子反覆哀嘆，呈現師生之間真切的關懷與面對病痛的無奈。' },
  'lun-yu_ch-6_p-9': { translation: '孔子說：「顏回真賢能！一竹筐飯、一瓢水，住在狹窄巷子，別人受不了這種憂苦，他卻不改變自己的快樂。」', analysis: '顏回的樂不依賴物質條件，而來自安於道與內在充實。' },
  'lun-yu_ch-6_p-10': { translation: '冉求說自己不是不喜歡孔子的道，只是力量不夠。孔子說真正力量不夠的人會走到半路才停；你現在是自己先畫下界線。', analysis: '孔子分辨客觀限制與自我設限，鼓勵人先突破放棄的心理。' },
  'lun-yu_ch-6_p-11': { translation: '孔子對子夏說：「你要做君子型的讀書人，不要做小人型的讀書人。」', analysis: '「君子儒」以道義和公共責任為學問目的；「小人儒」則把知識當成私利工具。' },
  'lun-yu_ch-6_p-12': { translation: '子游做武城長官。孔子問他得到什麼人才，子游說有澹臺滅明：走路不抄近路，沒有公事從不來自己家。', analysis: '子游以不取巧、不攀私人關係稱讚澹臺滅明的端正與公私分明。' },
  'lun-yu_ch-6_p-13': { translation: '孔子說孟之反不誇功。軍隊敗退時他殿後，快進城門才策馬說：「不是我敢落在後面，是馬跑不動。」', analysis: '他實際承擔危險卻不居功，孔子藉此肯定謙遜。' },
  'lun-yu_ch-6_p-14': { translation: '孔子說：「若沒有祝鮀的口才，卻有宋朝的美貌，在如今這個時代很難免於禍患。」', analysis: '這是孔子對當時社會現實的諷刺：美貌或才能若缺乏自保條件，可能反成危險。' },
  'lun-yu_ch-6_p-15': { translation: '孔子說：「誰出門不走門呢？為何人們卻不走這條正道？」', analysis: '道像門一樣是可走的路；困難常不在不知道，而在不願實踐。' },
  'lun-yu_ch-6_p-16': { translation: '孔子說：「質樸多於文飾就顯得粗野；文飾多於質樸就像文書官。文與質配合得宜，才是君子。」', analysis: '人格需要真實本質與文化修養平衡，任何一邊過度都會失衡。' },
  'lun-yu_ch-6_p-17': { translation: '孔子說：「人能立身靠正直；不正直的人能活下來，只是僥倖逃過罷了。」', analysis: '以欺瞞求得一時利益不等於可長久依靠；正直才是穩固的立身根本。' },
  'lun-yu_ch-6_p-18': { translation: '孔子說：「知道它的人，不如喜愛它的人；喜愛它的人，不如以它為樂的人。」', analysis: '學習最深的動力不是外在壓力，而是由理解、喜愛進到內在樂趣。' },
  'lun-yu_ch-6_p-19': { translation: '孔子說：「中等資質以上的人，可以和他談高深的道理；中等資質以下的人，不能立刻和他談高深道理。」', analysis: '教學應量材而教，從學生可理解、可實行的層次開始，而非一套內容套用所有人。' },
  'lun-yu_ch-6_p-20': { translation: '樊遲問智慧，孔子說：努力做好百姓應做的義務，敬鬼神而保持距離，可算智慧。問仁，孔子說：仁者先承擔困難，後考慮收穫。', analysis: '智慧重在處理人間責任；仁重在先盡責、後求利。' },
  'lun-yu_ch-6_p-21': { translation: '孔子說：「智者喜愛水，仁者喜愛山；智者活躍，仁者安靜；智者快樂，仁者長壽。」', analysis: '水與山是比喻：智慧偏向應變流動，仁德偏向安定厚重，並非絕對的人格分類。' },
  'lun-yu_ch-6_p-22': { translation: '孔子說：「齊國再改變一次，可達到魯國的程度；魯國再改變一次，就可達到正道。」', analysis: '孔子以兩國為例，認為政治文化能經由持續改革逐步接近理想。' },
  'lun-yu_ch-6_p-23': { translation: '孔子說：「觚不像觚，還算是觚嗎？還算是觚嗎？」', analysis: '觚是酒器。孔子以器物失其形制比喻名實不符：若職分與制度失去本義，名稱便成空話。' },
  'lun-yu_ch-6_p-24': { translation: '宰我問：若有人說井裡有仁者，仁者會跳下去嗎？孔子說何必如此？君子可以前往救援，卻不可被陷害；可以被暫時欺騙，卻不可完全蒙蔽。', analysis: '仁不等於盲從或不計後果。善意須有判斷力，才能真正救人而不落入陷阱。' },
  'lun-yu_ch-6_p-25': { translation: '孔子說：「君子廣泛學習文獻，再用禮來約束自己，就可以不違背正道了。」', analysis: '知識需要倫理規範來統整；「禮」使博學不流於散亂或自我放縱。' },
  'lun-yu_ch-6_p-26': { translation: '孔子去見南子，子路不高興。孔子發誓說：「若我做了不正當的事，願上天厭棄我！願上天厭棄我！」', analysis: '事件有不同歷史解讀，但文本重點是孔子向子路表明行事問心無愧。' },
  'lun-yu_ch-6_p-27': { translation: '孔子說：「中庸作為德行，大概是最高的了！人們缺少它已經很久。」', analysis: '中庸不是折衷討好，而是在具體情境中掌握恰當、平衡且不失原則的分寸。' },
  'lun-yu_ch-6_p-28': { translation: '子貢問：若有人廣泛施惠百姓、救濟眾人，能叫仁嗎？孔子說這何止是仁，恐怕是聖人，連堯舜都難做到。仁者想使自己立足，也幫人立足；想使自己通達，也幫人通達。能從自己近處的感受推想他人，就是仁的方法。', analysis: '孔子把宏大慈善與日常恕道連起來：仁的起點是推己及人，而非等待超凡的功業。' },
  'lun-yu_ch-7_p-1': { translation: '孔子說：「我只傳述古代的道理，不自創學說；我相信並喜愛古道，私下把自己比作老彭。」', analysis: '孔子強調承傳與整理古代文化；「述而不作」不是毫無創見，而是不以個人自創凌駕於道。' },
  'lun-yu_ch-7_p-2': { translation: '孔子說：「默默記住所學，學習而不厭倦，教人而不疲倦，這些我做到了多少呢？」', analysis: '這是自我反省，不是自滿；學與教都需要長久的耐心。' },
  'lun-yu_ch-7_p-3': { translation: '孔子說：「德行沒有修養、學問沒有研習，聽到義卻不能改向它，知道不善卻不能改正，都是我憂慮的事。」', analysis: '孔子把修德、求學、向義、改過列為終身功課。' },
  'lun-yu_ch-7_p-4': { translation: '孔子閒居時，神態舒展從容，面容和悅安詳。', analysis: '日常姿態也反映修養；孔子並非時時嚴肅緊張。' },
  'lun-yu_ch-7_p-5': { translation: '孔子說：「我衰老得很厲害了！很久沒有再夢見周公。」', analysis: '周公代表孔子所嚮往的禮樂政治理想；不再夢見象徵理想的感召似乎減弱。' },
  'lun-yu_ch-7_p-6': { translation: '孔子說：「志向立在道上，根據德行，依靠仁心，並在六藝中遊習。」', analysis: '學習有層次：以道為方向、德仁為根本，技藝與文化為具體養成。' },
  'lun-yu_ch-7_p-7': { translation: '孔子說：「只要有人帶著十條乾肉作見面禮來求學，我從未不教他。」', analysis: '孔子打破貴族教育的限制，重視學習意願而非身分財富。' },
  'lun-yu_ch-7_p-8': { translation: '孔子說：「學生不努力思考到想弄懂，我不啟發；不想說明到急著表達，我不引導。舉一角而不能推知另外三角，我便不再重複教。」', analysis: '啟發式教學要求學生主動投入，教師則在關鍵處點醒。' },
  'lun-yu_ch-7_p-9': { translation: '孔子在有喪事的人旁邊吃飯，從不吃飽；當天若哭過，就不唱歌。', analysis: '孔子以節制表達對他人哀傷的同理與敬意。' },
  'lun-yu_ch-7_p-10': { translation: '孔子對顏回說：「被任用便施展，不被任用便退藏，只有我和你能做到。」子路問若統率三軍會帶誰，孔子說不帶徒手鬥虎、徒步過河、死了也不後悔的人；必帶臨事謹慎、善於謀劃而能成功的人。', analysis: '孔子肯定進退有度，也明確反對匹夫之勇；勇敢要與敬慎和謀略結合。' },
  'lun-yu_ch-7_p-11': { translation: '孔子說：「富貴若能用正當方法求得，即使做拿鞭子的低職，我也做；若不能正當求得，就依從我的志趣。」', analysis: '孔子不否定富貴，拒絕的是不義的求取方式。' },
  'lun-yu_ch-7_p-12': { translation: '孔子特別慎重對待齋戒、戰爭和疾病。', analysis: '三者都涉及身心、生命或重大責任，因此不可輕忽。' },
  'lun-yu_ch-7_p-13': { translation: '孔子在齊國聽到《韶》樂，三個月吃肉都不覺得有滋味，說：「沒想到音樂能達到這樣的境界！」', analysis: '孔子體驗到音樂的高度美感與道德感化力。' },
  'lun-yu_ch-7_p-14': { translation: '冉有問孔子是否會幫助衛君，子貢進去問伯夷、叔齊是誰。孔子說是古代賢人，子貢問他們是否有怨，孔子說他們求仁而得仁，有何怨呢？子貢出來說，老師不會幫衛君。', analysis: '子貢藉提問了解孔子的價值判斷：不合義的權位爭奪，不值得支持。' },
  'lun-yu_ch-7_p-15': { translation: '孔子說：「吃粗飯、喝清水，彎著手臂當枕頭，樂趣也在其中；用不義得來的富貴，對我如浮雲。」', analysis: '安貧樂道不是美化貧困，而是指出人格不該被不義的富貴收買。' },
  'lun-yu_ch-7_p-16': { translation: '孔子說：「若多給我幾年，到五十歲再學《易》，就可以少犯大錯。」', analysis: '《易》被視為理解變化與處世的學問；孔子仍自認需要學習。' },
  'lun-yu_ch-7_p-17': { translation: '孔子在誦讀《詩》《書》與主持禮儀時，都使用標準雅正的語言。', analysis: '語言規範在經典傳授與公共禮儀中，有使溝通清楚、文化可傳的作用。' },
  'lun-yu_ch-7_p-18': { translation: '葉公向子路問孔子，子路沒答。孔子說：「何不說他發憤時忘了吃飯，快樂時忘了憂愁，連年老將至也不知道。」', analysis: '孔子用投入學問與志業的熱情描述自己，而非列舉名位。' },
  'lun-yu_ch-7_p-19': { translation: '孔子說：「我不是生來就懂的人，只是喜愛古道，勤敏地去求得它。」', analysis: '孔子把成就歸於好學與勤求，否定天才神話。' },
  'lun-yu_ch-7_p-20': { translation: '孔子不談怪異、暴力、禍亂和鬼神的事情。', analysis: '並非否定一切未知，而是把教學重心放在可實踐的人倫與秩序。' },
  'lun-yu_ch-7_p-21': { translation: '孔子說：「三人同行，必有可作我老師的人；選其優點學習，見其缺點便反省自己改正。」', analysis: '任何人都可成為學習材料；關鍵在於謙遜觀察與自我修正。' },
  'lun-yu_ch-7_p-22': { translation: '孔子說：「天把德賦予我，桓魋能把我怎樣？」', analysis: '在受威脅時，孔子以對使命與德行的信念保持鎮定。' },
  'lun-yu_ch-7_p-23': { translation: '孔子說：「你們以為我有所隱瞞嗎？我沒有。我的一切行為，沒有不與你們共同實踐的。」', analysis: '孔子的教學重身教；道理在公開可見的日常行為中。' },
  'lun-yu_ch-7_p-24': { translation: '孔子以四項教人：文獻學習、實際行為、盡心、守信。', analysis: '教育兼顧知識、實踐、內在責任與人際信用。' },
  'lun-yu_ch-7_p-25': { translation: '孔子說見不到聖人，能見君子便好；見不到善人，能見有恆心的人便好。把沒有說成有、空虛說成充實、窮困說成奢泰的人，很難有恆。', analysis: '孔子降低理想的期待層次，仍堅守真實與持久是人格的基本門檻。' },
  'lun-yu_ch-7_p-26': { translation: '孔子釣魚不用網一網打盡，射鳥不射巢中休息的鳥。', analysis: '這表現取用有節、保留生機的態度。' },
  'lun-yu_ch-7_p-27': { translation: '孔子說：「大概有人不懂卻憑空創作，我沒有這種情形。多聽而選好處遵從，多看而記住，這是較次一等的知。」', analysis: '孔子重視經驗、觀察與取捨，不主張無根據地自創。' },
  'lun-yu_ch-7_p-28': { translation: '互鄉的人難以溝通，孔子卻接見一名童子，門人困惑。孔子說：我許可他現在進步，不追究他過去；人潔淨自己而來，我肯定他的潔淨，不保證他的往後。', analysis: '教育應給願意改變的人機會，不能因其出身或過去一概拒絕。' },
  'lun-yu_ch-7_p-29': { translation: '孔子說：「仁離我們很遠嗎？我想要仁，仁就來到。」', analysis: '仁的起點在立志與當下實踐，不必等待外在條件完全成熟。' },
  'lun-yu_ch-7_p-30': { translation: '陳司敗問昭公懂禮嗎，孔子答懂。後來陳司敗質疑昭公娶吳國同姓女子，怎能算懂禮。孔子聽後說：「我真幸運，只要有過錯，人一定知道。」', analysis: '孔子不直接攻擊國君；得知批評後，以自省的語氣承認自己可能有判斷失誤。' },
  'lun-yu_ch-7_p-31': { translation: '孔子和人唱歌，若覺得唱得好，必請對方再唱一次，然後自己和唱。', analysis: '孔子樂於欣賞他人之長，也以真誠互動學習藝術。' },
  'lun-yu_ch-7_p-32': { translation: '孔子說：「文獻知識方面，我大概和別人差不多；親身做到君子之道，我還沒有把握。」', analysis: '孔子區分知識與實踐，對後者保持嚴格自省。' },
  'lun-yu_ch-7_p-33': { translation: '孔子說：「說到聖與仁，我哪裡敢當？只可說我做這些事不厭、教人不倦。」公西華說：「正是這點弟子學不到。」', analysis: '孔子拒絕聖仁的稱號，卻以持續實踐與教學作為可學的榜樣。' },
  'lun-yu_ch-7_p-34': { translation: '孔子病重，子路請求祈禱。孔子問有這種規定嗎？子路引誄文說可向上下神祇祈禱。孔子說：「我早已祈禱很久了。」', analysis: '孔子把一生依道而行視為最深的祈禱，而非臨病才求神。' },
  'lun-yu_ch-7_p-35': { translation: '孔子說：「奢侈會不恭敬，節儉會顯得寒酸；與其不恭敬，寧可寒酸。」', analysis: '兩端都有缺點，但孔子把敬意放在排場之前。' },
  'lun-yu_ch-7_p-36': { translation: '孔子說：「君子心境坦然寬廣，小人常常憂愁不安。」', analysis: '坦蕩來自問心無愧；長戚戚常是私欲與得失牽動的結果。' },
  'lun-yu_ch-7_p-37': { translation: '孔子溫和而有威嚴，有威嚴卻不凶猛，恭敬而安定。', analysis: '這是理想人格的平衡：既有力量與界線，也有溫厚從容。' },
  'lun-yu_ch-8_p-1': { translation: '孔子說：「泰伯可以說有最高的德行了！他三次把天下讓給別人，百姓甚至找不到適當的話來稱讚他。」', analysis: '孔子以泰伯不居功、不求名的讓位行為，稱讚德行的深厚。' },
  'lun-yu_ch-8_p-2': { translation: '孔子說：恭敬沒有禮會勞累，謹慎沒有禮會畏縮，勇敢沒有禮會作亂，直率沒有禮會尖刻。君子厚待親族，百姓便興起仁心；不遺棄老朋友，百姓便不薄情。', analysis: '禮使各種好品質有適當分寸；君子的私人關係也是社會風氣的示範。' },
  'lun-yu_ch-8_p-3': { translation: '曾子病重，叫弟子查看他的手腳，引用《詩經》說自己一生戰戰兢兢如臨深淵、如履薄冰；從今以後，知道可以免於損傷身體了。', analysis: '這與孝的身體觀有關，也表現曾子一生警醒自持。' },
  'lun-yu_ch-8_p-4': { translation: '曾子臨病對孟敬子說：鳥將死叫聲哀，人將死話語善。君子重視三事：容貌動作避免暴慢，臉色端正使人信任，言語聲氣遠離粗鄙乖戾；祭器細節自有專人管理。', analysis: '曾子把人格修養落在外在可見的敬、信與言辭，不把重點放在儀式瑣事。' },
  'lun-yu_ch-8_p-5': { translation: '曾子說：「有能力卻向沒能力的人請教，知道得多卻向知道得少的人請教；有學問像沒有，充實像空虛，受冒犯也不計較，我的朋友從前做得到這些。」', analysis: '此處稱許顏回式的謙遜、虛心與不報復。' },
  'lun-yu_ch-8_p-6': { translation: '曾子說：「能把幼主託付給他，能把百里國政交給他，面對大節操時不被奪志，這才是君子吧？這就是君子。」', analysis: '君子經得起權力、責任與危機的考驗，關鍵在不可奪的操守。' },
  'lun-yu_ch-8_p-7': { translation: '曾子說：「讀書人不可不胸襟寬廣、意志堅毅，因為責任重大、道路遙遠。以仁為自己的責任，不重嗎？到死才停止，不遠嗎？」', analysis: '仁被視為一生的公共責任，需要長久承擔。' },
  'lun-yu_ch-8_p-8': { translation: '孔子說：「由《詩》興發情感，由禮建立行為，由音樂完成修養。」', analysis: '詩、禮、樂分別培養感受、規範與和諧，構成完整教育。' },
  'lun-yu_ch-8_p-9': { translation: '孔子說：「百姓可以使他依循制度去做，卻不一定能使他全都了解其道理。」', analysis: '此句反映古代政治語境的治理現實，不應據此否定公民理解與參與；也可提醒制度要能實行。' },
  'lun-yu_ch-8_p-10': { translation: '孔子說：「喜好勇敢又痛恨貧窮，容易作亂；對不仁者厭惡得太過，也容易作亂。」', analysis: '好惡若沒有節制，正義感或勇氣都可能轉成破壞力。' },
  'lun-yu_ch-8_p-11': { translation: '孔子說：「即使有周公那樣的才華與優點，若驕傲又吝嗇，其他方面也不值得看了。」', analysis: '傲慢與吝嗇會腐蝕才華的價值；人格不能只看能力。' },
  'lun-yu_ch-8_p-12': { translation: '孔子說：「學習三年而不把目標放在俸祿上，這種人不容易得到。」', analysis: '孔子批評把學習立即工具化，重視求學的內在目的。' },
  'lun-yu_ch-8_p-13': { translation: '孔子說：「篤信好學，守死而善其道；危險的國家不進，混亂的國家不住。天下有道便出仕，無道便隱退。有道之國仍貧賤可恥，無道之國卻富貴也可恥。」', analysis: '讀書人要兼顧守道、選擇政治環境與對自身才德的責任。' },
  'lun-yu_ch-8_p-14': { translation: '孔子說：「不在那個職位，就不謀劃那個職位的政事。」', analysis: '尊重職責分工，同時要求在自己職位上負責。' },
  'lun-yu_ch-8_p-15': { translation: '孔子說：「從太師摯開始演奏，到《關雎》結尾，音樂浩蕩充滿耳中。」', analysis: '孔子稱讚禮樂演奏的整體秩序與豐沛感染力。' },
  'lun-yu_ch-8_p-16': { translation: '孔子說：「狂放而不直率，無知而不誠實，空空蕩蕩又不守信，我不知道這種人怎麼回事。」', analysis: '性格可各有不同，但真誠與信用是不可缺的底線。' },
  'lun-yu_ch-8_p-17': { translation: '孔子說：「學習要像追趕不上那樣，還要怕失去所學。」', analysis: '這形容持續精進與珍惜所學，不是焦慮式競爭。' },
  'lun-yu_ch-8_p-18': { translation: '孔子說：「舜和禹擁有天下，卻不像是在為自己占有天下。」', analysis: '孔子讚美把權位當公共責任、而非私有利益的政治理想。' },
  'lun-yu_ch-8_p-19': { translation: '孔子說：「堯作君主多麼偉大！只有天最大，只有堯能效法天，浩大得百姓難以形容。他功業偉大，文教燦爛。」', analysis: '此為傳統政治讚頌，強調君主應以廣大功業與文化教化服人。' },
  'lun-yu_ch-8_p-20': { translation: '舜有五位賢臣便天下大治；武王說自己有十位治亂之臣。孔子說人才難得，堯舜之際已算最多，其中有一位婦人，實際是九人。周朝擁有天下三分之二仍臣服於殷，周的德可說最高。', analysis: '孔子一面感嘆人才難得，一面稱許周在強盛時仍能守住名分與節制。' },
  'lun-yu_ch-8_p-21': { translation: '孔子說：「禹，我沒有可挑剔的。他飲食簡薄，祭祀鬼神卻盡孝敬；衣服樸素，祭服卻華美；宮室低矮，卻盡力治理溝渠水利。禹，我沒有可挑剔的。」', analysis: '孔子稱許禹公私分明：私生活節儉，公共祭祀與民生工程盡責。' },
  'lun-yu_ch-9_p-1': { translation: '孔子很少談利益、天命和仁。', analysis: '這些概念重要卻容易流於空談；孔子更多從具體行為教人。' },
  'lun-yu_ch-9_p-2': { translation: '達巷的人說孔子博學卻沒有一項專長成名。孔子聽後問弟子自己該專精駕車還是射箭，說還是學駕車吧。', analysis: '孔子以自嘲回應；博學不必受限於單一職業標籤。' },
  'lun-yu_ch-9_p-3': { translation: '孔子說：麻布禮帽合禮，現在用絲做較省，我隨從眾人；在堂下拜合禮，現在在堂上拜太倨傲，即使違眾我仍在堂下拜。', analysis: '禮可在不傷本義時調整節用，但涉及敬意的核心不可隨便省略。' },
  'lun-yu_ch-9_p-4': { translation: '孔子杜絕四種毛病：不憑空猜想、不固執必然、不拘泥成見、不自我中心。', analysis: '此為開放且自省的思考態度。' },
  'lun-yu_ch-9_p-5': { translation: '孔子在匡地遇險，說：文王死後，文化不就在我這裡嗎？天若要毀掉文化，後死的人便不能參與；天若不毀掉，匡人能把我怎樣？', analysis: '孔子以承傳文化的使命感安定自己，不因危險失去志向。' },
  'lun-yu_ch-9_p-6': { translation: '大宰問孔子是否聖人、為何多才。子貢說天使他接近聖人且多才。孔子說自己幼時貧賤，故會許多卑微技藝；君子不必多才。', analysis: '孔子把多能歸於生活經驗，並不把技能多寡當君子標準。' },
  'lun-yu_ch-9_p-7': { translation: '孔子說：「我有什麼知識嗎？其實沒有。有普通人問我，若我一時空白，就從問題兩端反覆探究，把道理說盡。」', analysis: '孔子示範以提問、分析與對話求知，而非假裝全知。' },
  'lun-yu_ch-9_p-8': { translation: '孔子說：「鳳鳥不來，黃河不出河圖，我大概不行了吧！」', analysis: '鳳鳥、河圖象徵太平祥瑞；孔子感嘆政治理想難實現。' },
  'lun-yu_ch-9_p-9': { translation: '孔子見到服喪者、穿禮服者或盲人，即使對方年輕也會站起來；經過時必快步表示敬意。', analysis: '孔子對哀傷、禮儀與身心不便者都以行動表達尊重。' },
  'lun-yu_ch-9_p-10': { translation: '顏回感嘆老師的學問越仰望越高、越鑽研越堅；看似在前又忽在後。孔子循序善誘，以文博我、以禮約我，使我想停也不能；竭盡才能後，見到高高立起的目標，卻找不到路追上。', analysis: '顏回描述孔子教學的深度、循序與強大感召。' },
  'lun-yu_ch-9_p-11': { translation: '孔子病重，子路讓門人假裝家臣。病好後孔子說子路長久行詐：我沒有家臣卻裝有，是欺誰？欺天嗎？寧可死在弟子手中，何必假借大臣之禮？', analysis: '孔子重視名實一致，即使出於好意也不可用虛假身分。' },
  'lun-yu_ch-9_p-12': { translation: '子貢問有美玉該收藏還是找好商人賣掉。孔子說：「賣吧！賣吧！我是在等好買主。」', analysis: '美玉比喻才德；孔子願服務社會，但等待合宜的任用時機。' },
  'lun-yu_ch-9_p-13': { translation: '孔子想住到九夷。有人說那裡簡陋怎麼辦？孔子說君子住在那裡，有什麼簡陋？', analysis: '地方的價值不只在物質條件，也在居者能否帶來文化與德行。' },
  'lun-yu_ch-9_p-14': { translation: '孔子說：「我從衛國回到魯國後，才把音樂整理正確，使雅、頌各得其位置。」', analysis: '孔子重視整理禮樂傳統，讓其形式與用途相符。' },
  'lun-yu_ch-9_p-15': { translation: '孔子說：「出外侍奉公卿，在家侍奉父兄；喪事不敢不盡力，不被酒困住，這些我做到了多少呢？」', analysis: '孔子把公共、家庭、喪禮與自律都列入自我檢核。' },
  'lun-yu_ch-9_p-16': { translation: '孔子站在河邊說：「流逝的時光就像這水，日夜不停。」', analysis: '以流水感嘆時間與生命不斷前行，催促人珍惜當下。' },
  'lun-yu_ch-9_p-17': { translation: '孔子說：「我沒有見過像喜歡美色那樣喜歡德行的人。」', analysis: '孔子批評人們對外在欲望的熱烈常超過對德性的追求。' },
  'lun-yu_ch-9_p-18': { translation: '孔子說：「譬如堆山，差一筐土不完成而停止，是我自己停止；譬如平地，即使只倒一筐土而前進，也是我自己前進。」', analysis: '成敗的關鍵在持續的自主行動，不能只歸咎外在。' },
  'lun-yu_ch-9_p-19': { translation: '孔子說：「聽我說話而不懈怠的，大概只有顏回吧！」', analysis: '孔子讚顏回的專注與持續實踐。' },
  'lun-yu_ch-9_p-20': { translation: '孔子評論顏回說：「可惜啊！我只見他不斷進步，沒見他停下。」', analysis: '顏回早逝令孔子惋惜；此句稱許其進德不止。' },
  'lun-yu_ch-9_p-21': { translation: '孔子說：「有幼苗不開花的，有開花卻不結果的。」', analysis: '成長有不同階段與風險，初露才華不等於最後能有成就。' },
  'lun-yu_ch-9_p-22': { translation: '孔子說：「後輩值得敬畏，怎知後來的人不如現在？到了四、五十歲還沒有成就，才不值得敬畏。」', analysis: '孔子鼓勵尊重年輕人的潛力，也提醒成長要以實際志業回應期待。' },
  'lun-yu_ch-9_p-23': { translation: '孔子說：「合乎規範的勸告，誰能不聽？能改正才可貴。委婉稱許的話，誰能不高興？能推究其理才可貴。高興卻不推究、聽從卻不改正，我就無可奈何了。」', analysis: '真正受教不是表面接受，而是理解後改變行動。' },
  'lun-yu_ch-9_p-24': { translation: '孔子說：「以忠信為主；不要交不如自己的人為友；有過錯不要怕改正。」', analysis: '重點不是傲慢比較，而是選擇能共同向善的朋友，並勇於改過。' },
  'lun-yu_ch-9_p-25': { translation: '孔子說：「三軍可以奪去主帥，普通人卻不可奪去志向。」', analysis: '外在權力可被改變，內在志節仍是個人最後可守住的自主。' },
  'lun-yu_ch-9_p-26': { translation: '孔子說子路穿破棉袍，和穿狐貉皮衣的人站在一起而不覺羞恥，正合《詩》所說不嫉妒、不貪求。子路一生誦這句，孔子說僅此還不算很值得稱許。', analysis: '安貧不妒是起點；孔子提醒德行不能停在自我欣賞。' },
  'lun-yu_ch-9_p-27': { translation: '孔子說：「到了寒冷季節，才知道松柏是最後凋零的。」', analysis: '逆境最能顯出堅貞不屈的品格。' },
  'lun-yu_ch-9_p-28': { translation: '孔子說：「智者不迷惑，仁者不憂愁，勇者不恐懼。」', analysis: '三者是理想方向而非天生特權：明理、仁心與勇氣能減少惑、憂、懼。' },
  'lun-yu_ch-9_p-29': { translation: '孔子說：「能一起學，未必能一起走向道；能走向道，未必能一起立定；能立定，未必能一起權衡變通。」', analysis: '修養有深淺：共同學習、確立原則與情境權衡，是逐步提升的能力。' },
  'lun-yu_ch-9_p-30': { translation: '詩說：「唐棣花搖曳反覆，難道我不想念你？只是住處太遠。」', analysis: '此句借花與距離寫思念，呈現《詩經》以自然景象寄託人情的方式。' },
  'lun-yu_ch-10_p-1': { translation: '孔子在鄉里時，恭順溫和，好像不太說話的人。', analysis: '在熟人社群中仍不放縱言語，表現謙和。' },
  'lun-yu_ch-10_p-2': { translation: '孔子在宗廟和朝廷中，能從容說話，但始終謹慎。', analysis: '公共場合需要清楚表達，也需要敬慎。' },
  'lun-yu_ch-10_p-3': { translation: '上朝時，孔子與職位較低的大夫交談和樂，與較高的大夫交談正直；國君在時，恭敬不安而舉止合宜。', analysis: '孔子隨對象調整禮節，但不失真誠與分寸。' },
  'lun-yu_ch-10_p-4': { translation: '國君召孔子接待賓客，他神色嚴整、腳步敏捷；向同列者作揖合乎左右次序，衣服整齊；快步前進如鳥張翼。賓客退去後，必回報國君賓客已不回頭。', analysis: '此段記錄外交禮儀中專注、整潔與負責到底的態度。' },
  'lun-yu_ch-10_p-5': { translation: '孔子進公門必躬身，站不正對門中央，走不踩門檻；經過國君座位神色肅敬。上堂提衣躬身屏息，出來下階後才恢復和悅，回到原位又恭敬。', analysis: '細節表達對公共權位與儀式場合的敬畏，非單純做作。' },
  'lun-yu_ch-10_p-6': { translation: '孔子拿著圭玉時躬身如承受不起，舉手如作揖、放下如交付，神色如戰慄、腳步有節。行饗禮時神色莊重，私下會見時則和悅。', analysis: '同一人依場合切換莊重與親和，顯示禮的情境性。' },
  'lun-yu_ch-10_p-7': { translation: '孔子衣飾不用某些顏色作鑲邊，不穿紅紫便服；夏天穿細葛衣必加外衣才出門。不同皮裘配不同衣色；便服皮衣較長、右袖較短；睡衣長一身半。除喪後佩飾恢復，弔喪不穿吉服；吉月必穿朝服上朝。', analysis: '這些是當時衣冠制度，重點在依身分、場合與哀吉之別保持合宜。' },
  'lun-yu_ch-10_p-8': { translation: '齋戒時，孔子必穿潔淨的布衣，改變飲食，連坐處也更換。', analysis: '齋戒是為祭祀作身心準備，以生活調整表達專注與敬意。' },
  'lun-yu_ch-10_p-9': { translation: '孔子講究食物精細，但變質、顏色氣味不好、沒煮熟或不合時令的不吃；切得不合規矩、沒有合適醬料的不吃。肉不多於主食；酒不定量但不喝醉；不吃市售酒與肉乾。吃薑不撤、但不過量；祭肉不久留。吃不說話，睡不說話；即使粗食菜湯，祭祀時也嚴肅。', analysis: '此段兼有衛生、節制與祭祀敬意，不能簡化為追求美食。' },
  'lun-yu_ch-10_p-10': { translation: '坐席沒有擺正，孔子不坐。', analysis: '小處守禮，是培養內在秩序與專注的方式。' },
  'lun-yu_ch-10_p-11': { translation: '鄉人飲酒時，拿拐杖的長者離席後，孔子才離席；鄉人舉行驅疫儀式時，他穿朝服站在東階。', analysis: '尊長與參與社群儀式，是當時禮俗的一部分。' },
  'lun-yu_ch-10_p-12': { translation: '替人向他國問候時，孔子再拜送行；季康子送藥，他拜謝收下，卻說自己不了解藥性，不敢服用。', analysis: '孔子既答謝好意，也在不確定時保持審慎。' },
  'lun-yu_ch-10_p-13': { translation: '馬廄失火，孔子下朝回來先問：「有人受傷嗎？」沒有先問馬。', analysis: '人在事故中的安全優先於財物，顯出仁的具體次序。' },
  'lun-yu_ch-10_p-14': { translation: '國君賜熟食，孔子端正坐席先嚐；賜生肉便煮熟祭薦；賜活物便飼養。陪國君吃飯，國君祭食後他先吃。生病時國君探望，他頭朝東、披朝服並垂下大帶；國君召見，不等車駕備好就出發。', analysis: '此段記錄臣子對君命與賞賜的禮節，也呈現對生命的珍惜。' },
  'lun-yu_ch-10_p-15': { translation: '孔子進入太廟，每一件事都詢問。', analysis: '明知仍問，是敬慎求實，也是避免自以為是。' },
  'lun-yu_ch-10_p-16': { translation: '朋友死了而無人料理，孔子說：「在我家停靈。」朋友贈送車馬等物，除非祭肉，孔子不行拜謝禮。', analysis: '孔子在朋友危難時承擔實際責任，並按物品性質區分禮節。' },
  'lun-yu_ch-10_p-17': { translation: '孔子睡覺不擺屍體般筆直的姿勢，在家不故作威儀；見服喪者、禮冠者、盲人，即使熟識也改變神色。見凶服者或背著公文板者會扶軾致敬；見盛饌必起身；雷暴必變色。上車端正站立握扶手；車中不回頭張望、不高聲說話、不用手亂指。', analysis: '日常起居保持自然，遇到他人哀傷、職責或自然威力則表敬畏。' },
  'lun-yu_ch-10_p-18': { translation: '鳥看見人的神色便飛起，盤旋後才落下。孔子說：「山梁上的雌雉，真是懂得時機啊！」子路把食物捧給牠，牠聞了三下便飛走。', analysis: '以雉鳥知進退作結，呼應孔子對時機與分寸的觀察。' },
  'lun-yu_ch-11_p-1': { translation: '孔子說：「先接受禮樂教化的人，原是民間質樸的人；後接受的人，原是貴族子弟。若要任用，我會選先進者。」', analysis: '孔子重視實質修養，不以出身決定人才。' },
  'lun-yu_ch-11_p-2': { translation: '孔子說，跟隨自己在陳蔡受困的弟子都不在身邊了，並列出弟子專長：顏回等長於德行，宰我子貢長於言語，冉有子路長於政事，子游子夏長於文學。', analysis: '孔子承認弟子各有專長，教育不只一種成才樣貌。' },
  'lun-yu_ch-11_p-3': { translation: '孔子說：「顏回不是幫助我的人，對我的話沒有不喜歡的。」', analysis: '此處不是貶顏回，而是說一味贊同不能形成有益的討論與切磋。' },
  'lun-yu_ch-11_p-4': { translation: '孔子說：「閔子騫真孝！人們對他父母兄弟稱讚他的話沒有異議。」', analysis: '孝行得到家人與旁人共同認可，顯示其真實而非表演。' },
  'lun-yu_ch-11_p-5': { translation: '南容多次誦讀《詩經》「白圭之玷，尚可磨也」一章，孔子便把姪女嫁給他。', analysis: '南容反覆體會言行有失難補，孔子看重其慎言自省。' },
  'lun-yu_ch-11_p-6': { translation: '季康子問誰好學，孔子說顏回好學，可惜早逝，現在沒有了。', analysis: '孔子對顏回的好學始終高度肯定，也流露哀惜。' },
  'lun-yu_ch-11_p-7': { translation: '顏回死後，顏路請求賣孔子的車替他做外槨。孔子說自己的兒子孔鯉死時也只有內棺沒有外槨，且自己隨大夫之後，不可徒步出行，所以不賣車。', analysis: '孔子雖深愛顏回，仍顧及家禮與身分責任，不以哀情破壞分寸。' },
  'lun-yu_ch-11_p-8': { translation: '顏回死了，孔子說：「唉！天要亡我！天要亡我！」', analysis: '孔子把失去最重要弟子視為重大的生命與理想損失。' },
  'lun-yu_ch-11_p-9': { translation: '顏回死後，孔子哭得很悲痛。隨從說老師太悲痛了，孔子說：「有嗎？不為這個人悲痛，又為誰悲痛？」', analysis: '孔子不壓抑真情，肯定深厚師生情誼。' },
  'lun-yu_ch-11_p-10': { translation: '顏回死後，門人想厚葬，孔子說不可，門人仍厚葬。孔子說顏回把我當父親，我卻不能把他當兒子，這不是我的意思，是你們的意思。', analysis: '孔子對禮制與師生情感之間的矛盾感到無奈。' },
  'lun-yu_ch-11_p-11': { translation: '子路問怎樣事奉鬼神。孔子說：「還不能事奉人，怎能事奉鬼神？」又問死，孔子說：「還不懂生，怎能懂死？」', analysis: '孔子把倫理實踐置於玄學探問之前，並非簡單否認鬼神或死亡。' },
  'lun-yu_ch-11_p-12': { translation: '閔子騫侍坐和氣，子路剛強，冉有子貢從容，孔子很高興，卻說子路恐怕不得善終。', analysis: '孔子從個性看見優點也看見風險；剛勇若不受節制，可能招禍。' },
  'lun-yu_ch-11_p-13': { translation: '魯國人要改建長府。閔子騫說沿用舊制如何，何必改建？孔子說：「這人平常不說話，一說就切中要點。」', analysis: '改革需有必要與理由，不能為改而改。' },
  'lun-yu_ch-11_p-14': { translation: '孔子說：「子路彈瑟何必在我門下？」門人因此不敬子路，孔子說：「子路已登堂，只是還未入室。」', analysis: '孔子先批評其技藝未臻精微，隨即制止門人的輕慢，承認子路已有相當成就。' },
  'lun-yu_ch-11_p-15': { translation: '子貢問子張和子夏誰賢。孔子說子張過頭，子夏不足。子貢問是否子張較好，孔子說過頭和不足一樣不好。', analysis: '「過猶不及」強調適度：超過標準不必然優於未達標準。' },
  'lun-yu_ch-11_p-16': { translation: '季氏比周公還富，冉求卻替他搜括財富。孔子說冉求不是我的學生，弟子可以鳴鼓攻擊他。', analysis: '孔子強烈批評助長權貴聚斂、加重百姓負擔的行為。' },
  'lun-yu_ch-11_p-17': { translation: '孔子評弟子：高柴愚直，曾參遲鈍，子張偏激，子路粗野。', analysis: '這是對性格偏向的描述，不等於全盤否定；每人仍有可發揮的長處。' },
  'lun-yu_ch-11_p-18': { translation: '孔子說顏回近乎達到理想，卻常常貧乏；子貢不安於命運而經商致富，預測行情常中。', analysis: '孔子對兩人不同生活道路作觀察，未將貧富直接等同德行。' },
  'lun-yu_ch-11_p-19': { translation: '子張問善人之道，孔子說：「不踏著前人足跡，卻也進不了內室。」', analysis: '創新不可脫離基本傳統與規範；不循基本路徑難入高深境界。' },
  'lun-yu_ch-11_p-20': { translation: '孔子說：「說話敦厚便值得稱許的，是君子嗎？還是只是表面莊重的人？」', analysis: '不能只根據言談外貌判斷品格，需觀察真實行為。' },
  'lun-yu_ch-11_p-21': { translation: '子路問聽到道理就做嗎，孔子說父兄在，應請教後再做；冉求問同樣問題，孔子說聽到就做。公西華困惑，孔子解釋冉求退縮所以鼓勵，子路好勝逞強所以抑制。', analysis: '同一原則須依個性調整教法；教育不是機械給相同答案。' },
  'lun-yu_ch-11_p-22': { translation: '孔子在匡地遇險，顏回後到。孔子說以為你死了，顏回說老師還在，我怎敢死？', analysis: '對話表達顏回對老師的敬愛與兩人的深厚關係。' },
  'lun-yu_ch-11_p-23': { translation: '季子然問子路、冉求算不算大臣。孔子說真正大臣以道事君，不可行便辭去；子路冉求只能算具備職務能力的臣。問他們會不會盲從，孔子說弒父弒君的事不會跟從。', analysis: '孔子區分職能型官員與能以道義制衡君主的大臣。' },
  'lun-yu_ch-11_p-24': { translation: '子路讓子羔當費邑長官。孔子說這是在害那孩子。子路說有百姓和社稷，何必讀書才算學習？孔子說所以我厭惡花言巧語的人。', analysis: '孔子認為未成熟者不宜倉促承擔政務；實踐重要，但不能用漂亮說法跳過學習準備。' },
  'lun-yu_ch-11_p-25': { translation: '子路、曾皙、冉有、公西華侍坐。孔子要他們說志向：子路想三年治理受戰亂饑荒的千乘國，使民勇敢知方向，孔子笑他不謙讓；冉有願治理六七十里或五六十里的小國，使百姓富足，禮樂待君子完成；公西華願學習在宗廟會盟中做小相；曾皙則願暮春與幾位成人、孩童到沂水洗浴、舞雩吹風，吟詠回家。孔子感嘆說贊同曾皙。', analysis: '四人志向分別展現勇、務實、禮儀專長與從容的太平生活。孔子不否定前三者，主要欣賞曾皙所呈現的禮樂和諧、安適自在的理想境界。' },
  'lun-yu_ch-12_p-1': { translation: '顏淵問仁。孔子說：「克制私欲、回到禮的規範就是仁。一日做到，天下便歸向仁。行仁在自己，難道靠別人嗎？」又說：「不合禮的不看、不聽、不說、不做。」顏淵表示願意實行。', analysis: '仁不是抽象情感，而是從感官、言語、行動中克己守禮的日常工夫。' },
  'lun-yu_ch-12_p-2': { translation: '仲弓問仁。孔子說：出門如同接待貴賓，使用百姓如同承辦大祭；自己不想要的，不加給別人；在國或在家都不招怨。', analysis: '此段以敬人與恕道說明仁：把每個人當作值得莊重對待的人。' },
  'lun-yu_ch-12_p-3': { translation: '司馬牛問仁。孔子說仁者說話遲緩謹慎。司馬牛問這就算仁嗎？孔子說實行很難，說話怎能不謹慎？', analysis: '慎言來自對實踐困難的清楚認識，不能輕易承諾。' },
  'lun-yu_ch-12_p-4': { translation: '司馬牛問君子。孔子說君子不憂不懼。問這就夠嗎？孔子說內省無愧，又有什麼可憂可懼？', analysis: '安定並非沒有問題，而是問心無愧帶來的內在力量。' },
  'lun-yu_ch-12_p-5': { translation: '司馬牛憂愁自己沒有兄弟。子夏說：死生有命、富貴在天；君子敬慎無過失，待人恭敬有禮，四海之內都是兄弟，何必怕沒有兄弟？', analysis: '子夏以道德共同體安慰他：血親之外，仍可在敬禮中建立深厚關係。' },
  'lun-yu_ch-12_p-6': { translation: '子張問明辨。孔子說：逐漸滲透的讒言、切身急迫的控訴都不能影響你，可算明；若都不能影響，還可算看得遠。', analysis: '明辨是抵抗情緒操弄與片面指控，能看穿長期影響。' },
  'lun-yu_ch-12_p-7': { translation: '子貢問政治。孔子說要糧食充足、兵力充足、百姓信任。若不得已先去兵，再去食；自古人皆會死，沒有信用與信任，國家便無法立足。', analysis: '孔子把民信置於國家存續核心；政策若失信，即使有資源也難以長久。' },
  'lun-yu_ch-12_p-8': { translation: '棘子成說君子只要質樸，何必文飾。子貢說話一出口便追不回；文與質互相需要，如把虎豹毛皮去掉，就和犬羊皮沒有差別。', analysis: '子貢反對把文與質對立：文化修養使本質得以顯現。' },
  'lun-yu_ch-12_p-9': { translation: '哀公問饑年財用不足怎麼辦。有若建議用十分之一稅率。哀公說收二成還不夠，何況一成。有若說百姓富足，君主怎會不足？百姓不足，君主怎會富足？', analysis: '政治財政應以民生為本，不能以加重人民負擔解決困境。' },
  'lun-yu_ch-12_p-10': { translation: '子張問怎樣崇德、辨惑。孔子說以忠信為主，遷向義就是崇德；愛一個人想他活、恨一個人想他死，前後矛盾就是惑。', analysis: '德行要有穩定原則，不能被愛憎情緒來回支配。' },
  'lun-yu_ch-12_p-11': { translation: '齊景公問政，孔子答：「君像君、臣像臣、父像父、子像子。」景公說若各自不像，即使有糧食也吃不到。', analysis: '「正名」指角色應承擔相稱責任，不是單向維護權威。' },
  'lun-yu_ch-12_p-12': { translation: '孔子說：「一句話就能判明案件的，大概是子路吧！」子路答應的事從不拖延到隔夜。', analysis: '子路果決守信，能迅速釐清事實；司法仍需以公正為前提。' },
  'lun-yu_ch-12_p-13': { translation: '孔子說：「審理訴訟，我和別人差不多；最重要的是使人不必訴訟。」', analysis: '理想治理不只提高斷案效率，更要減少造成衝突與不公的根源。' },
  'lun-yu_ch-12_p-14': { translation: '子張問政治。孔子說：「在職時不懈怠，推行時盡忠。」', analysis: '簡短兩句把行政倫理落在勤勉與盡責。' },
  'lun-yu_ch-12_p-15': { translation: '孔子說：「廣泛學習文獻，再以禮約束自己，就可以不背離正道。」', analysis: '博學需有倫理框架統整，才能成為修養而非雜知。' },
  'lun-yu_ch-12_p-16': { translation: '孔子說：「君子成全別人的好事，不成全別人的壞事；小人相反。」', analysis: '在人際與公共生活中，應協助善意計畫而不推波助瀾於惡。' },
  'lun-yu_ch-12_p-17': { translation: '季康子問政。孔子說：「政就是正。你帶頭正，誰敢不正？」', analysis: '領導者的示範力量大於命令；制度與個人操守都需要端正。' },
  'lun-yu_ch-12_p-18': { translation: '季康子憂心盜賊，孔子說：「若你自己不貪欲，即使獎賞偷竊，百姓也不會偷。」', analysis: '孔子把上位者貪欲視為社會風氣與犯罪的重要根源。' },
  'lun-yu_ch-12_p-19': { translation: '季康子問能否殺無道者以成就有道。孔子說你治理何必用殺？你想善，百姓便善；君子之德如風，小人之德如草，風吹草必倒。', analysis: '孔子反對以暴制暴，強調領導者道德風氣的感化作用。' },
  'lun-yu_ch-12_p-20': { translation: '子張問怎樣算通達，說在國在家都有名聲。孔子說這是聞名不是通達。通達者質直好義，能察言觀色，替人設想；聞名者表面取仁、行為違背，還自信不疑。', analysis: '孔子區分真實的通達與徒有聲名，批評表裡不一。' },
  'lun-yu_ch-12_p-21': { translation: '樊遲問崇德、修惡、辨惑。孔子說先做事後求收穫是崇德；攻克自己的惡、不攻擊別人的惡是修惡；一時憤怒忘了自身與父母，是惑。', analysis: '修養重在先責己、後責人，並防止怒氣破壞關係與責任。' },
  'lun-yu_ch-12_p-22': { translation: '樊遲問仁，孔子說愛人；問智，孔子說知人。又說提拔正直者放在邪曲者之上，能使邪曲者改正。子夏以舜舉皋陶、湯舉伊尹說明：任用正直賢能，會使不仁者遠離。', analysis: '仁與知在人事上落實為愛人、識人與正確任用，影響整個社會風氣。' },
  'lun-yu_ch-12_p-23': { translation: '子貢問交友。孔子說：「忠誠地勸告，善意地引導；若不被接受就停止，不要自取羞辱。」', analysis: '朋友間可勸諫，但須尊重界線，不能以關心之名強迫對方。' },
  'lun-yu_ch-12_p-24': { translation: '曾子說：「君子以文章學問結交朋友，以朋友互相輔助實踐仁。」', analysis: '友誼不只社交，也可成為共同學習與向善的支持網絡。' },
  'lun-yu_ch-13_p-1': { translation: '子路問政治。孔子說：「自己先做在前面，使百姓勞作。」子路再問，孔子說：「不要厭倦。」', analysis: '治理者要先示範、再帶領，且長久不懈。' },
  'lun-yu_ch-13_p-2': { translation: '仲弓做季氏家宰問政。孔子說先信任主管官員，寬赦小過，提拔賢才；不知道誰賢，就先提拔自己知道的，別人自然會推薦你未知的人。', analysis: '治理需要授權、寬容與建立人才網絡。' },
  'lun-yu_ch-13_p-3': { translation: '子路問若在衛國從政先做什麼，孔子說先正名。名不正，話不順；話不順，事不成；事不成，禮樂不興、刑罰失準，百姓無所適從。因此名稱必須能說明，說出必須能實行。', analysis: '正名要求角色、語言與責任一致，是制度能運作的前提。' },
  'lun-yu_ch-13_p-4': { translation: '樊遲想學種田種菜，孔子說不如老農老圃。樊遲走後，孔子說上位者好禮、好義、好信，百姓便敬服並真誠相待，四方百姓都會來，何必只談耕作？', analysis: '孔子非否定農業，而是區分政治領導所需的德行與技術專業。' },
  'lun-yu_ch-13_p-5': { translation: '孔子說：「背誦三百篇《詩經》，交給政事卻不能通達，出使四方不能獨立應對，讀得再多有何用？」', analysis: '經典學習必須轉化為判斷、溝通與實際能力。' },
  'lun-yu_ch-13_p-6': { translation: '孔子說：「自身端正，不下命令也能推行；自身不端正，即使下令也不會被遵從。」', analysis: '領導示範是政策可信度的根源。' },
  'lun-yu_ch-13_p-7': { translation: '孔子說：「魯國與衛國的政治，像兄弟一樣相近。」', analysis: '兩國文化制度相似，孔子作出政治比較。' },
  'lun-yu_ch-13_p-8': { translation: '孔子稱讚衛國公子荊善於持家：剛有財物說差不多夠了，稍多說差不多完整了，富有後說差不多美好了。', analysis: '公子荊知足而不炫富，財富增長仍保持節制。' },
  'lun-yu_ch-13_p-9': { translation: '孔子到衛國，見人口眾多；冉有問還要做什麼，孔子說使其富足；問富足後，孔子說教化他們。', analysis: '人口、富足、教育構成政治建設的次序。' },
  'lun-yu_ch-13_p-10': { translation: '孔子說：「若有人任用我，一年便可有起色，三年便有成果。」', analysis: '政治改革需要時間，但孔子相信正確治理能逐步見效。' },
  'lun-yu_ch-13_p-11': { translation: '孔子說：「善人治理國家一百年，也能克服殘暴、廢除殺戮，這話確實。」', analysis: '深層社會風氣的改變需要長期持續的善政。' },
  'lun-yu_ch-13_p-12': { translation: '孔子說：「即使有王者興起，也必須一世代後才可使人仁厚。」', analysis: '政治教化不會立即完成，制度與人心都需要時間。' },
  'lun-yu_ch-13_p-13': { translation: '孔子說：「自己端正，從政有何難？不能端正自己，怎能端正別人？」', analysis: '修身是政治要求的先決條件。' },
  'lun-yu_ch-13_p-14': { translation: '冉有退朝晚，孔子問為何遲。他說有政事，孔子說只是季氏的私事；若是真正國政，即使不任用我，我也會知道。', analysis: '孔子區分公共國政與權臣家政，批評公私混淆。' },
  'lun-yu_ch-13_p-15': { translation: '定公問一句話能興邦或亡邦嗎。孔子說不能如此簡單，但若君主知道為君困難，近於興邦；若只喜歡別人不違背自己，善事尚可，不善而無人敢違，便近於亡邦。', analysis: '國家興亡不靠口號，關鍵在君主能否自省並容納諫言。' },
  'lun-yu_ch-13_p-16': { translation: '葉公問政，孔子說：「近處的人喜悅，遠處的人願來。」', analysis: '善政先使本地人民安居，再形成吸引力。' },
  'lun-yu_ch-13_p-17': { translation: '子夏問政，孔子說：「不要急於求快，不要只看小利；求快反而不通，小利會妨礙大事。」', analysis: '治理要有長期視野，避免短視績效。' },
  'lun-yu_ch-13_p-18': { translation: '葉公說有個正直者，父親偷羊，兒子出面作證。孔子說自己鄉里的正直不同：父親替兒子隱瞞，兒子替父親隱瞞，直在其中。', analysis: '此句反映儒家親親倫理與當代法治見證義務的張力，應放在歷史脈絡理解，不可直接作現代法律建議。' },
  'lun-yu_ch-13_p-19': { translation: '樊遲問仁。孔子說：「居處恭敬，做事敬慎，待人盡忠；即使到夷狄之地，也不能丟棄。」', analysis: '仁是可攜帶到任何環境的生活原則。' },
  'lun-yu_ch-13_p-20': { translation: '子貢問怎樣算士。孔子說：行己知恥，出使不辱君命；其次是宗族稱孝、鄉黨稱悌；再其次是言必信、行必果，雖拘執也可算。至於當今從政者，孔子不屑評價。', analysis: '孔子按道德自覺、家庭德行與守信列出層次，也批評器量狹小的政治人物。' },
  'lun-yu_ch-13_p-21': { translation: '孔子說：「若找不到中道的人交往，至少選狂者或狷者；狂者進取，狷者有所不做。」', analysis: '兩種偏向仍有可取處：一者有理想衝勁，一者有不肯越界的底線。' },
  'lun-yu_ch-13_p-22': { translation: '孔子引南方諺語說人沒有恆心，連巫醫也做不了；《易》說德行不恆或會蒙羞。孔子說不必占卜也知道了。', analysis: '持久是學藝、修德與生活可信的基本條件。' },
  'lun-yu_ch-13_p-23': { translation: '孔子說：「君子和諧但不盲同，小人表面相同卻不和諧。」', analysis: '真正合作容許差異並追求共同善；盲目附和反而缺少信任。' },
  'lun-yu_ch-13_p-24': { translation: '子貢問全鄉人都喜歡或厭惡一人如何。孔子都說不夠，最好是鄉里的善人喜歡他、不善的人厭惡他。', analysis: '公眾評價需看評價者與理由，不能只看人氣。' },
  'lun-yu_ch-13_p-25': { translation: '孔子說君子容易侍奉卻難取悅：不合道討好他不高興，用人按才器；小人難侍奉卻易取悅：不合道也高興，用人則求全責備。', analysis: '好領導有原則且知人善任，不以私人好惡苛求部屬。' },
  'lun-yu_ch-13_p-26': { translation: '孔子說：「君子安泰而不驕傲，小人驕傲而不安泰。」', analysis: '真正安定不需傲慢支撐；驕傲常掩蓋內在不安。' },
  'lun-yu_ch-13_p-27': { translation: '孔子說：「剛毅、質樸、不善巧言的人，接近仁。」', analysis: '這些品質較少虛飾，容易成為仁的基礎，但仍需配合智慧與禮。' },
  'lun-yu_ch-13_p-28': { translation: '子路問士的相處，孔子說朋友間要切磋勸勉，兄弟間要和悅親愛。', analysis: '不同關係有不同分寸：朋友重互相提升，手足重親和。' },
  'lun-yu_ch-13_p-29': { translation: '孔子說：「善人教導百姓七年，也可使其承擔軍事任務。」', analysis: '文本重視先教後用，避免把未受訓的人投入危險職責。' },
  'lun-yu_ch-13_p-30': { translation: '孔子說：「用未受教的百姓作戰，就是拋棄他們。」', analysis: '無論古今，領導者不可把缺乏準備的人當作可犧牲的工具。' },
  'lun-yu_ch-14_p-1': { translation: '原憲問什麼是恥。孔子說：「國家有道時領俸祿，國家無道時仍領俸祿，這才可恥。」', analysis: '重點在亂世是否以職位俸祿換取對不義政治的附和。' },
  'lun-yu_ch-14_p-2': { translation: '有人問能克制好勝、自誇、怨恨、貪欲，是否算仁。孔子說這很難做到，是否就是仁則不知道。', analysis: '克制私欲是重要工夫，但孔子不把仁縮減為幾項消極禁制。' },
  'lun-yu_ch-14_p-3': { translation: '孔子說：「讀書人若只眷戀安逸生活，就不配稱讀書人。」', analysis: '士要有超越個人舒適的志業與責任。' },
  'lun-yu_ch-14_p-4': { translation: '孔子說：「國家有道時，言語正直、行為正直；國家無道時，行為正直，言語要謙遜。」', analysis: '亂世仍守正道，但表達要謹慎以避免無謂傷害與無效衝突。' },
  'lun-yu_ch-14_p-5': { translation: '孔子說：「有德的人必有值得說的話，能說話的人未必有德；仁者必有勇氣，勇者未必有仁。」', analysis: '孔子提醒不能把口才或勇敢直接當作德性的證明。' },
  'lun-yu_ch-14_p-6': { translation: '南宮适說羿善射、奡善於水戰，卻不得善終；禹和后稷親自耕作，卻得天下。孔子不答，等他出去後說：「這人真是君子，真崇尚德行！」', analysis: '南宮适比較武力與德行的不同結果，孔子讚其價值取向。' },
  'lun-yu_ch-14_p-7': { translation: '孔子說：「君子也可能不仁，卻沒有小人能真正仁。」', analysis: '君子仍可能失德；但以私利為本的小人，難以穩定實踐仁。' },
  'lun-yu_ch-14_p-8': { translation: '孔子說：「愛一個人，能不讓他辛勞嗎？忠於一個人，能不勸導他嗎？」', analysis: '真正的愛與忠包含責任和勸諫，不只是順從討好。' },
  'lun-yu_ch-14_p-9': { translation: '孔子說鄭國制定外交文書：裨諶起草，世叔討論，外交官子羽修飾，子產最後潤色。', analysis: '好決策是多角色協作：起草、討論、專業修訂與統整缺一不可。' },
  'lun-yu_ch-14_p-10': { translation: '有人問子產，孔子說他是施惠於人的人；問子西，孔子不置評；問管仲，孔子說他是有作為的人，因為奪去伯氏封邑後，伯氏仍吃粗食到老而無怨言。', analysis: '孔子對人物評價各有面向，並從其實際政治效果觀察。' },
  'lun-yu_ch-14_p-11': { translation: '孔子說：「貧窮而沒有怨恨很難；富有而不驕傲較容易。」', analysis: '物質處境都考驗人，尤其貧困中仍保持平和更不容易。' },
  'lun-yu_ch-14_p-12': { translation: '孔子說：「孟公綽做趙、魏兩大家的家臣很勝任，不能做滕、薛這種小國的大夫。」', analysis: '不同職位需要不同能力，不能只用一種標準看人才。' },
  'lun-yu_ch-14_p-13': { translation: '子路問完整的人。孔子說若兼有臧武仲的智慧、孟公綽的清心、卞莊子的勇敢、冉求的才藝，再以禮樂修飾，便可算完整。又說今日只要見利思義、見危敢獻身、久困仍不忘平日承諾，也可算完整。', analysis: '完整人格由能力、節制、勇敢與信義組成，並非單一才能。' },
  'lun-yu_ch-14_p-14': { translation: '孔子問公叔文子是否不說、不笑、不取。公明賈說傳話者誇大了：他在適當時才說，人不厭；高興時才笑，人不厭；合乎義才取，人不厭。孔子說也許如此。', analysis: '節制不是毫無表情或欲望，而是在合宜時表達與取用。' },
  'lun-yu_ch-14_p-15': { translation: '孔子說臧武仲以防地的請求來要求魯國立其後嗣，即使說不是要挾君主，我也不信。', analysis: '孔子批評藉權勢或條件逼迫政治決定的做法。' },
  'lun-yu_ch-14_p-16': { translation: '孔子說：「晉文公狡黠而不正，齊桓公正而不狡黠。」', analysis: '孔子用正與譎比較兩位霸主的政治手段與品格。' },
  'lun-yu_ch-14_p-17': { translation: '子路說齊桓公殺公子糾，召忽殉死，管仲未死，是否不仁。孔子說桓公多次會合諸侯而不用武力，是管仲之功，這就是仁。', analysis: '孔子從安定天下的公共成效評估管仲，沒有只以殉死作唯一標準。' },
  'lun-yu_ch-14_p-18': { translation: '子貢質疑管仲不為公子糾死還輔佐桓公，是否仁。孔子說管仲輔佐桓公稱霸、匡正天下，人民至今受益；若沒有他，我們恐怕還披髮左衽。怎能只要求匹夫匹婦守小信而自縊溝渠、無人知道？', analysis: '孔子把仁的判斷放在更大的公共責任與歷史效果，也引出道德原則與具體責任的張力。' },
  'lun-yu_ch-14_p-19': { translation: '公叔文子的家臣僎與文子一同被提拔為大夫。孔子聽說後說他可以得到「文」的諡號。', analysis: '能提拔有才的部屬、共享進身機會，是孔子稱許的政治品格。' },
  'lun-yu_ch-14_p-20': { translation: '孔子說衛靈公無道，季康子問為何不亡。孔子說因仲叔圉管賓客、祝鮀管宗廟、王孫賈管軍旅，怎會立刻亡國？', analysis: '即使君主失德，國家仍可能靠有能力的官員暫時維繫；這不等於問題已被解決。' },
  'lun-yu_ch-14_p-21': { translation: '孔子說：「說話毫不慚愧，實行起來就很難。」', analysis: '不知言語分量的人容易誇口，行動難以相稱。' },
  'lun-yu_ch-14_p-22': { translation: '陳成子殺齊簡公。孔子沐浴後上朝，請哀公討伐。哀公要他告訴三桓。孔子說自己列於大夫之後，不敢不報告；告訴三桓後他們不肯，孔子仍說自己已盡報告責任。', analysis: '孔子面對弒君之亂，堅持按身分盡到道義與程序責任，即使無法改變結果。' },
  'lun-yu_ch-14_p-23': { translation: '子路問如何事君。孔子說：「不要欺騙他，但可以冒犯他而直言勸諫。」', analysis: '忠不等於討好；不欺與敢諫是臣子的重要責任。' },
  'lun-yu_ch-14_p-24': { translation: '孔子說：「君子向上通達，小人向下通達。」', analysis: '君子追求道義與修養，小人偏向私利與低層欲望。' },
  'lun-yu_ch-14_p-25': { translation: '孔子說：「古人求學是為了修養自己，今人求學是為了給別人看。」', analysis: '孔子批評把學問變成名聲、表演或取悅他人的工具。' },
  'lun-yu_ch-14_p-26': { translation: '蘧伯玉派使者來，孔子問主人做什麼。使者說主人想減少過錯卻還做不到。使者走後，孔子連稱他真是好使者。', analysis: '孔子稱許主人能自省，也稱許使者能恰當傳達主人的修養。' },
  'lun-yu_ch-14_p-27': { translation: '孔子說：「不在那個職位，就不謀劃那個職位的政事。」', analysis: '不越權妄議，亦提醒人在自己職位上盡責。' },
  'lun-yu_ch-14_p-28': { translation: '曾子說：「君子的思考不超出自己的職位。」', analysis: '守分不是逃避關心，而是不以不負責任的姿態干預他人職責。' },
  'lun-yu_ch-14_p-29': { translation: '孔子說：「君子以言語超過行動為恥。」', analysis: '讓承諾少於或等於實行，是避免空談的自律。' },
  'lun-yu_ch-14_p-30': { translation: '孔子說君子有三道：仁者不憂、智者不惑、勇者不懼，自己都做不到。子貢說老師正是在說自己。', analysis: '孔子自謙，子貢則看見他已具備這三種德行。' },
  'lun-yu_ch-14_p-31': { translation: '子貢喜歡評論人物。孔子說：「賜很賢嗎？我可沒有這種閒暇。」', analysis: '孔子提醒少花時間評斷他人，多用於自身修養。' },
  'lun-yu_ch-14_p-32': { translation: '孔子說：「不要憂慮別人不了解自己，要憂慮自己沒有本事。」', analysis: '把注意力從求被看見轉向培養真實能力。' },
  'lun-yu_ch-14_p-33': { translation: '孔子說：「不預先猜人欺詐，不臆測人不可信；卻能先察覺，這才賢。」', analysis: '不以猜忌待人，同時保有敏銳判斷，是成熟的信任。' },
  'lun-yu_ch-14_p-34': { translation: '微生畝問孔子何以奔走不安，是否在逞口才。孔子說不是敢逞口才，而是厭惡固陋不通。', analysis: '孔子奔走是為改變閉塞局面，不是為求辯勝。' },
  'lun-yu_ch-14_p-35': { translation: '孔子說：「稱讚良馬不只稱它力氣大，而稱它的德性。」', analysis: '即使評馬也看整體品性與可用性；評人更不可只看單項才能。' },
  'lun-yu_ch-14_p-36': { translation: '有人問以德報怨如何。孔子說那用什麼報德？應以正直回應怨，以德回報德。', analysis: '孔子不主張報復，也不主張無差別寬縱；要以公平正直處理傷害。' },
  'lun-yu_ch-14_p-37': { translation: '孔子說：「沒有人了解我啊！」子貢問原因，孔子說不怨天、不怪人，從下學而向上通達；真正了解我的大概只有天。', analysis: '孔子以不怨尤的態度面對知音難得，堅持由具體學習通向高遠之道。' },
  'lun-yu_ch-14_p-38': { translation: '公伯寮在季孫前誣告子路。子服景伯說可把他處死。孔子說道將行或廢都是命，公伯寮怎能改變命？', analysis: '孔子拒絕以暴力反擊讒言，展現對道義與命運的安定。' },
  'lun-yu_ch-14_p-39': { translation: '孔子說：「賢者避開整個亂世；其次避開不宜居之地；再其次避開不善臉色；再其次避開不善言語。」', analysis: '面對無道環境有不同退避層次，重在保全人格與判斷時機。' },
  'lun-yu_ch-14_p-40': { translation: '孔子說：「隱居避世而有作為的人有七位了。」', analysis: '指當時選擇退隱的賢者，感嘆時代使人才離開公共舞台。' },
  'lun-yu_ch-14_p-41': { translation: '子路住在石門，守門人問從哪來。聽說從孔子那裡來，說：「就是那個明知不可為而仍去做的人嗎？」', analysis: '旁人看見孔子的理想主義；語帶感嘆，也承認其不輕易放棄。' },
  'lun-yu_ch-14_p-42': { translation: '孔子在衛國敲磬，有挑草筐的人經過說他有心事，又批評他過於執著，說深水涉水、淺水提衣即可。孔子說他果斷，這就沒什麼難了。', analysis: '對話呈現入世堅持與隨時而處兩種人生態度的張力。' },
  'lun-yu_ch-14_p-43': { translation: '子張問《書經》說高宗守喪三年不說話是何意。孔子說不只高宗，古人都如此；君主去世，百官三年聽命於冢宰。', analysis: '此為古代喪制與權力暫代制度，反映慎終與政治連續性的安排。' },
  'lun-yu_ch-14_p-44': { translation: '孔子說：「上位者喜好禮，百姓便容易引導。」', analysis: '禮能讓公共互動有可預期的規範，降低治理只靠強制的成本。' },
  'lun-yu_ch-14_p-45': { translation: '子路問君子。孔子說修養自己以敬；再進一步使人安；再進一步使百姓安。使百姓安，連堯舜都還感到困難。', analysis: '君子修養由自身擴及他人與人民，公共安定是極高而艱難的目標。' },
  'lun-yu_ch-14_p-46': { translation: '原壤張開腿坐著等孔子。孔子責備他年少不敬兄長、長大無所成就、年老還不死是害人，並用杖敲他小腿。', analysis: '此段帶有強烈時代語氣與師友戲謔／責備，反映孔子對不敬不學的批判，不宜照字面模仿。' },
  'lun-yu_ch-14_p-47': { translation: '闕黨一名童子替孔子傳話。有人問他是否求上進，孔子說看見他坐在成人位子、與長者並行，不是求進步，而是想很快成名。', analysis: '孔子批評急於成人、失去謙遜與次序的求進心。' },
  'lun-yu_ch-15_p-1': { translation: '衛靈公問軍陣，孔子說祭祀禮器略知，軍事沒學過，隔天離開。到了陳國斷糧，隨從病得起不來；子路不滿問君子也會窮困嗎？孔子說君子能固守窮困，小人窮困就放肆胡來。', analysis: '孔子拒絕把軍事功利當主要專長；困境考驗人是否守住原則。' },
  'lun-yu_ch-15_p-2': { translation: '孔子問子貢是否以為自己是博學而記住一切。子貢說是，孔子說不是，而是用一個原則貫串。', analysis: '「一以貫之」指以核心道理統整廣博知識，而非零散記憶。' },
  'lun-yu_ch-15_p-3': { translation: '孔子說：「由啊，懂得德的人太少了。」', analysis: '孔子感嘆人們多看外在利益，真正理解德行價值者少。' },
  'lun-yu_ch-15_p-4': { translation: '孔子說：「無為而治的，大概是舜吧？他做什麼呢？只要自己恭敬端正地坐在君位上。」', analysis: '無為不是不作為，而是領導者以端正德行使制度自然運行。' },
  'lun-yu_ch-15_p-5': { translation: '子張問如何立身。孔子說言語忠信、行為篤敬，即使在邊遠國家也行得通；若不忠信不篤敬，在本鄉也行不通。站立時好像看見這原則在眼前，乘車時好像靠在車前橫木上，這樣才行得通。', analysis: '忠信與敬不只是抽象規則，要成為隨時可自我提醒的行為準則。' },
  'lun-yu_ch-15_p-6': { translation: '孔子說史魚真直，國有道無道都像箭一樣直；蘧伯玉真是君子，有道便出仕，無道便把才德收藏心中。', analysis: '孔子分別肯定始終正直與知時退藏兩種德行。' },
  'lun-yu_ch-15_p-7': { translation: '孔子說：「可與他談卻不談，是錯失人才；不可與他談卻談，是浪費話語。智者不錯失人，也不錯失言。」', analysis: '溝通要判斷對象與時機，既珍惜人也珍惜言語。' },
  'lun-yu_ch-15_p-8': { translation: '孔子說：「有志之士、仁德之人，不會為求活命而傷害仁；必要時寧可犧牲生命來成全仁。」', analysis: '此為極端情境的價值宣言，強調不以生命換取作惡或背叛基本人道。' },
  'lun-yu_ch-15_p-9': { translation: '子貢問如何行仁。孔子說：「工匠想做好工作，先磨利工具。住在一國，要侍奉賢大夫，結交有仁的讀書人。」', analysis: '修仁也需環境與同伴：選擇好師友如同準備好工具。' },
  'lun-yu_ch-15_p-10': { translation: '顏淵問治國。孔子說採夏曆、用殷代車制、戴周代禮帽、用《韶》樂；排斥鄭聲，遠離佞人，因鄭聲浮靡、佞人危險。', analysis: '孔子以當時禮樂制度描述理想政教，核心在選擇端正文化、遠離媚俗與諂佞。' },
  'lun-yu_ch-15_p-11': { translation: '孔子說：「人若沒有長遠考慮，必有眼前憂患。」', analysis: '前瞻不是焦慮預言，而是對未來風險預作準備。' },
  'lun-yu_ch-15_p-12': { translation: '孔子說：「算了吧！我還沒見過喜好德行像喜好美色那樣的人。」', analysis: '孔子再度感嘆人對外在欲望的熱情常勝過德性追求。' },
  'lun-yu_ch-15_p-13': { translation: '孔子說：「臧文仲大概是竊據職位的人吧？知道柳下惠賢能，卻不讓他與自己並立。」', analysis: '占著位置卻不薦賢，是對公共職責的失職。' },
  'lun-yu_ch-15_p-14': { translation: '孔子說：「對自己要求嚴，對別人責備少，就能遠離怨恨。」', analysis: '先自責、少苛人有助降低衝突，也不表示放棄必要的批評。' },
  'lun-yu_ch-15_p-15': { translation: '孔子說：「對事情不常問『怎麼辦、怎麼辦』的人，我也不知道怎麼幫他。」', analysis: '願意面對問題並主動求解，是受教與成長的起點。' },
  'lun-yu_ch-15_p-16': { translation: '孔子說：「整天群居，談話不及義，只喜歡耍小聰明，這很難有成。」', analysis: '社交若只消耗在瑣碎炫技，難以形成真正學問或德行。' },
  'lun-yu_ch-15_p-17': { translation: '孔子說：「君子以義為本質，用禮實行，用謙遜表達，用信用完成，這才是君子。」', analysis: '義、禮、謙、信共同構成可實行、可被信任的人格。' },
  'lun-yu_ch-15_p-18': { translation: '孔子說：「君子憂慮自己沒有能力，不憂慮別人不了解自己。」', analysis: '焦點放在增進本領與德行，而不是追逐認可。' },
  'lun-yu_ch-15_p-19': { translation: '孔子說：「君子擔心一生過去，名聲仍不相稱。」', analysis: '「名」此處指與德行相符的名實與人生貢獻，不只是知名度。' },
  'lun-yu_ch-15_p-20': { translation: '孔子說：「君子從自己身上找原因，小人從別人身上找原因。」', analysis: '自省使人能改變可改變之處，推責則阻礙成長。' },
  'lun-yu_ch-15_p-21': { translation: '孔子說：「君子自重而不爭鬥，合群而不結黨。」', analysis: '自尊不等於競逐；合作不等於排他的私黨。' },
  'lun-yu_ch-15_p-22': { translation: '孔子說：「君子不因一個人說話就提拔他，也不因那個人不好就廢棄他說的話。」', analysis: '評人與評言要分開，以內容和實績判斷。' },
  'lun-yu_ch-15_p-23': { translation: '子貢問有沒有一句話可終身實行。孔子說：「大概是恕吧！自己不想要的，不加給別人。」', analysis: '恕是推己及人，是儒家處理關係的核心實踐。' },
  'lun-yu_ch-15_p-24': { translation: '孔子說：「我對人，毀謗誰、稱讚誰呢？若有稱讚，一定經過考驗。這些百姓，就是夏商周三代能依正道行事的基礎。」', analysis: '孔子評人重實證，也肯定人民能支持正直政治。' },
  'lun-yu_ch-15_p-25': { translation: '孔子說：「我還趕得上史官保留疑文、有人有馬便借人騎的時代；如今沒有了！」', analysis: '孔子懷念史官不妄補空缺與人際互信共享的風氣。' },
  'lun-yu_ch-15_p-26': { translation: '孔子說：「巧言會擾亂德行，小事不能忍耐會破壞大計。」', analysis: '花言巧語與衝動報復，都可能損害長遠原則與目標。' },
  'lun-yu_ch-15_p-27': { translation: '孔子說：「眾人厭惡一個人，必須查察；眾人喜愛一個人，也必須查察。」', analysis: '群眾意見是線索而非結論，仍需獨立判斷。' },
  'lun-yu_ch-15_p-28': { translation: '孔子說：「人能弘揚道，不是道自己弘揚人。」', analysis: '道必須靠人理解、實行與傳播，不能等待抽象原則自動發生。' },
  'lun-yu_ch-15_p-29': { translation: '孔子說：「有錯卻不改，這才叫真正的過錯。」', analysis: '犯錯可修正；拒絕修正才使錯誤固定下來。' },
  'lun-yu_ch-15_p-30': { translation: '孔子說：「我曾整天不吃、整夜不睡地思考，沒有好處，不如學習。」', analysis: '反思重要，但沒有材料與實踐的空想不如踏實學習。' },
  'lun-yu_ch-15_p-31': { translation: '孔子說：「君子謀求道不謀求食。耕田中有挨餓的可能，學習中也有俸祿；君子憂心道，不憂心貧窮。」', analysis: '孔子不否定謀生，但不讓生計焦慮取代對正道的追求。' },
  'lun-yu_ch-15_p-32': { translation: '孔子說：智慧足以得到職位，仁不足以守住，仍會失去；有智慧有仁，卻不莊重地面對百姓，百姓不敬；即使莊重，若不用禮來動員，也不算好。', analysis: '治理需要智、仁、威儀與合禮的行動，缺一不可。' },
  'lun-yu_ch-15_p-33': { translation: '孔子說：「君子不一定適合小事的精察，卻可承擔大任；小人不可承擔大任，卻可能精於小事。」', analysis: '此處區分格局與細務能力，並非否定細節的重要。' },
  'lun-yu_ch-15_p-34': { translation: '孔子說：「人民對仁的需要比水火更甚。水火我見過有人踏入而死，卻沒見有人實行仁而死。」', analysis: '仁是人類生活不可少的根本；孔子強調實踐仁不應被視為可怕負擔。' },
  'lun-yu_ch-15_p-35': { translation: '孔子說：「遇到該行仁的事，不必讓給老師。」', analysis: '在道義面前要勇於承擔，不能以尊師作為退讓藉口。' },
  'lun-yu_ch-15_p-36': { translation: '孔子說：「君子堅守正道，卻不拘守小信。」', analysis: '守正不等於死守細節承諾；面對衝突需以更高原則判斷。' },
  'lun-yu_ch-15_p-37': { translation: '孔子說：「侍奉國君，先恭敬完成職責，後考慮俸祿。」', analysis: '責任優先於報酬，是公共職務的倫理。' },
  'lun-yu_ch-15_p-38': { translation: '孔子說：「教育沒有類別之分。」', analysis: '孔子主張不因出身、族群或財富排除求學者，開啟平民教育精神。' },
  'lun-yu_ch-15_p-39': { translation: '孔子說：「道路不同，不能一起謀劃。」', analysis: '共同決策需要最低限度的價值共識；差異過大時強行合作難有結果。' },
  'lun-yu_ch-15_p-40': { translation: '孔子說：「言辭只要能清楚通達意思就夠了。」', analysis: '反對為炫耀而堆砌辭藻，重視表達的準確與有效。' },
  'lun-yu_ch-15_p-41': { translation: '盲樂師冕來見孔子，到臺階孔子說臺階在這裡，到席位說席位在這裡；眾人坐定後，逐一告訴他誰在何處。', analysis: '孔子主動提供空間與人物資訊，展現細緻的無障礙關懷。' },
  'lun-yu_ch-15_p-42': { translation: '師冕出去後，子張問這是與樂師說話的方法嗎？孔子說是，這本來就是幫助樂師的方法。', analysis: '尊重盲者不是憐憫，而是以適當資訊支持其自主行動。' },
  'lun-yu_ch-16_p-1': { translation: '季氏要攻打顓臾。冉有、子路告訴孔子。孔子責備冉有：顓臾是先王所封、在魯國境內的社稷之臣，何必攻伐？冉有說季氏想打，自己二人不想。孔子說輔臣應量力就職，危而不扶、顛而不持，要輔臣何用？又如虎兕逃出柵、龜玉在匣中毀壞，誰的過失？孔子說不患人口少而患分配不均，不患貧而患不安；遠人不服應修文德招來，來後要安置。如今你們不能招遠人、守國內分裂，卻想在國內動武，季氏真正憂患恐在蕭牆內。', analysis: '孔子反對權臣以藉口擴張，提出均、和、安與文化感召的政治原則，也追究輔臣的責任。' },
  'lun-yu_ch-16_p-2': { translation: '孔子說天下有道時，禮樂與征伐由天子發出；無道時由諸侯甚至大夫、家臣發出，權力越下移越難長久。天下有道，政權不在大夫手中，百姓也不必以議論政事補救失序。', analysis: '此為春秋封建秩序崩解的觀察，重點在權責名分與政治正當性。' },
  'lun-yu_ch-16_p-3': { translation: '孔子說俸祿離開魯國公室已有五代，政權落到大夫手中已有四代，所以三桓子孫將衰微。', analysis: '孔子從權力長期移轉推論政治家族的盛衰。' },
  'lun-yu_ch-16_p-4': { translation: '孔子說有益的三種朋友是正直、誠信、見聞多；有害的是諂媚逢迎、表面柔順、能言善辯卻不誠實。', analysis: '朋友品質會塑造判斷與品格，應看真誠與德行而非討喜。' },
  'lun-yu_ch-16_p-5': { translation: '孔子說有益的三種快樂是按禮樂調節生活、稱讚別人的善、結交許多賢友；有害的是驕奢的享樂、遊蕩的享樂、宴飲的享樂。', analysis: '孔子不反對快樂，區分能培養人與耗損人的娛樂。' },
  'lun-yu_ch-16_p-6': { translation: '孔子說侍奉君子有三種過失：還沒輪到說話就說叫急躁；該說卻不說叫隱瞞；未看對方神色就說叫盲目。', analysis: '說話須有時機、勇氣與觀察力。' },
  'lun-yu_ch-16_p-7': { translation: '孔子說君子有三戒：年少血氣未定，戒美色；壯年血氣旺盛，戒爭鬥；年老血氣衰退，戒貪得。', analysis: '不同生命階段有不同誘惑，修養需隨處境調整。' },
  'lun-yu_ch-16_p-8': { translation: '孔子說君子敬畏三件事：天命、有德位的大人、聖人的話。小人不懂天命而不敬畏，輕慢大人、侮辱聖人之言。', analysis: '「畏」是對更高原則、責任與智慧保持謙敬，不是盲目恐懼。' },
  'lun-yu_ch-16_p-9': { translation: '孔子說生來知道的是上等，學習才知道的是其次，困苦後才學又其次；困苦仍不學便是下等。', analysis: '重點不在固定階級，而在困境中仍拒絕學習會使人停滯。' },
  'lun-yu_ch-16_p-10': { translation: '孔子說君子有九種思考：看要清楚、聽要明白、臉色要溫和、儀容要恭敬、說話要忠誠、做事要敬慎、有疑問要請教、憤怒時想到後患、見利益想到義。', analysis: '九思將修養落在感官、情緒、言行與利益判斷的具體提醒。' },
  'lun-yu_ch-16_p-11': { translation: '孔子說見到善如怕趕不上，見不善如手探熱湯般避開；這樣的人我見過也聽過。隱居以守志、行義以通道，我聽過這話，卻沒見過真正做到的人。', analysis: '孔子區分宣稱與實踐，特別讚許對善惡的急切自覺。' },
  'lun-yu_ch-16_p-12': { translation: '齊景公有四千匹馬，死時百姓沒有可稱讚的德行；伯夷叔齊餓死首陽山下，百姓至今稱頌，大概說的就是這個道理。', analysis: '財富與排場不能留下真正聲名，德行與操守才會長存。' },
  'lun-yu_ch-16_p-13': { translation: '陳亢問孔鯉是否從孔子聽到特別教誨。孔鯉說沒有，只曾被問是否學《詩》與《禮》；孔子說不學詩無法說話，不學禮無法立身。陳亢高興說一問得三：知道詩、禮，也知道君子對兒子不偏私。', analysis: '孔子以公共標準教育兒子，沒有私授秘訣；詩與禮分別培養表達與立身。' },
  'lun-yu_ch-16_p-14': { translation: '本段說明諸侯妻子在君主、夫人本人、本國人與外國人面前的不同稱呼。', analysis: '這是古代外交與宮廷稱謂制度，顯示禮制對身分與說話對象的細密區分。' },
  'lun-yu_ch-17_p-1': { translation: '陽貨想見孔子，孔子不見；他送孔子小豬，孔子趁他不在回拜，路上相遇。陽貨問懷才卻讓國家迷亂是否仁、想做事卻老錯過時機是否智，並說時光不等人。孔子答應將出仕。', analysis: '陽貨以時機勸孔子入仕；此段呈現孔子在理想、現實與出仕時機間的拉扯。' },
  'lun-yu_ch-17_p-2': { translation: '孔子說：「人的本性本來相近，習染使人彼此相差很遠。」', analysis: '後天環境、習慣與教育深刻塑造人格。' },
  'lun-yu_ch-17_p-3': { translation: '孔子說：「只有最高的智慧與最下的愚昧不改變。」', analysis: '此句帶時代語氣；可理解為極端固執者最難受教育改變，非否定一般人的可塑性。' },
  'lun-yu_ch-17_p-4': { translation: '孔子到武城聽到琴瑟歌聲，笑說治理小地方何必用大本領。子游引孔子所說君子學道便愛人、小人學道便容易治理。孔子說子游說得對，先前只是玩笑。', analysis: '孔子肯定地方教化的重要，不因地方小就輕忽禮樂教育。' },
  'lun-yu_ch-17_p-5': { translation: '公山弗擾據費邑叛亂，召孔子，孔子想去。', analysis: '這是孔子面對非常規政治邀請的一段記錄。' },
  'lun-yu_ch-17_p-6': { translation: '子路不高興，說沒地方去就算了，何必去公山氏。孔子說召自己的人不會白召；若有人用我，也許能在東方重建周道。', analysis: '孔子寄望藉政治機會復興周禮，但此念也顯示理想與現實的風險。' },
  'lun-yu_ch-17_p-7': { translation: '子張問仁。孔子說能在天下實行五件事就是仁：恭敬、寬厚、守信、勤敏、施惠；恭不受侮，寬得眾，信使人任用，敏有功，惠能使人。', analysis: '仁在公共生活中具體表現為五種可實行的品格。' },
  'lun-yu_ch-17_p-8': { translation: '佛肸叛據中牟召孔子，孔子想去。子路提醒老師說過親身作惡者之地君子不入。孔子說自己如堅物磨不薄、白物染不黑，難道是只能掛著不能吃的匏瓜嗎？', analysis: '孔子渴望施展抱負；文本也保留弟子對其政治選擇的質疑。' },
  'lun-yu_ch-17_p-9': { translation: '孔子告訴子路：好仁不學會愚，好智不學會放蕩，好信不學會害人，好直不學會尖刻，好勇不學會作亂，好剛不學會狂妄。', analysis: '任何德性若缺乏學習與反省，都可能走向偏弊。' },
  'lun-yu_ch-17_p-10': { translation: '孔子說年輕人何不學《詩》？詩能興發情感、觀察社會、與人群相處、表達怨情；近可事父，遠可事君，還可認識鳥獸草木名稱。', analysis: '《詩》兼具情感、社會、政治與自然教育功能。' },
  'lun-yu_ch-17_p-11': { translation: '孔子對兒子伯魚說有沒有學《周南》《召南》；人不學它們，就像面對牆壁站著。', analysis: '《周南》《召南》是《詩經》入門，孔子以此強調基本文化教育。' },
  'lun-yu_ch-17_p-12': { translation: '孔子說：「說禮、說禮，難道只指玉帛嗎？說樂、說樂，難道只指鐘鼓嗎？」', analysis: '禮樂的核心是敬意與和諧，不是器物與排場。' },
  'lun-yu_ch-17_p-13': { translation: '孔子說：「外表嚴厲、內心軟弱的人，像小人中的穿牆小偷。」', analysis: '以強硬姿態掩飾怯弱與不正，是危險的虛假人格。' },
  'lun-yu_ch-17_p-14': { translation: '孔子說：「鄉原，是德行的賊。」', analysis: '鄉原指處處討好、看似忠厚卻沒有是非的人；他們會腐蝕真正的價值判斷。' },
  'lun-yu_ch-17_p-15': { translation: '孔子說：「路上聽來就到路上傳說，是拋棄德行。」', analysis: '未查證即傳播，既不負責也傷害自己的品格。' },
  'lun-yu_ch-17_p-16': { translation: '孔子說卑鄙的人能侍君嗎？未得到時怕得不到，得到後怕失去；一怕失去便什麼都做得出。', analysis: '把權位當唯一目標，會使人不擇手段。' },
  'lun-yu_ch-17_p-17': { translation: '孔子說古人也有缺點：狂是放達，矜是有節，愚是直率；今人的狂成放蕩，矜成暴戾，愚成欺詐。', analysis: '孔子借古今對照批評德性退化與真誠喪失。' },
  'lun-yu_ch-17_p-18': { translation: '孔子說：「巧言與媚色，很少有仁。」', analysis: '表面討好常掩蓋真誠不足，需以行為而非姿態判斷。' },
  'lun-yu_ch-17_p-19': { translation: '孔子說討厭紫色混淆正紅、鄭聲擾亂雅樂、利口的人顛覆國家。', analysis: '比喻真偽與正邪被混淆；文化與政治都須警惕花巧言語的破壞。' },
  'lun-yu_ch-17_p-20': { translation: '孔子說想不說話。子貢問老師不說，弟子傳述什麼。孔子說天何曾說話？四時運行、萬物生長，天何曾說話？', analysis: '孔子提醒最深的教化不全靠言語，也在自然秩序與身教中呈現。' },
  'lun-yu_ch-17_p-21': { translation: '孺悲想見孔子，孔子托病推辭；傳話的人出門後，孔子取瑟唱歌讓他聽見。', analysis: '此段記錄孔子有意不見對方的行為，可能含教育性責備，但具體原因文本未明。' },
  'lun-yu_ch-17_p-22': { translation: '宰我說三年喪期太久，禮樂三年不做會壞，新舊穀輪替一年便夠。孔子問他吃好米穿錦衣能安心嗎；宰我說安心，孔子說安心就去做。宰我走後，孔子責備他不仁：孩子出生三年才離父母懷抱，三年喪是天下通喪，難道宰我沒有受父母三年愛護？', analysis: '此為儒家孝喪倫理的強烈表述，核心是感念養育與哀思；現代哀傷實踐可有不同形式。' },
  'lun-yu_ch-17_p-23': { translation: '孔子說整天吃飽沒用心思，很難辦；不是有下棋投壺嗎？做那些也比完全無所事事好。', analysis: '即使休閒活動也比心智完全閒置好，鼓勵有所投入。' },
  'lun-yu_ch-17_p-24': { translation: '子路問君子重勇嗎。孔子說君子以義為上；君子有勇無義會作亂，小人有勇無義會成盜。', analysis: '勇氣需由義引導，否則力量會成為傷害。' },
  'lun-yu_ch-17_p-25': { translation: '子貢問君子有憎惡嗎。孔子說厭惡宣揚別人惡、居下毀謗上、勇而無禮、果敢而窒塞；子貢也厭惡把抄襲當智慧、把不遜當勇、把揭人短當直。', analysis: '這些「惡」都針對以假德行傷人的行為，非鼓勵任性厭人。' },
  'lun-yu_ch-17_p-26': { translation: '孔子說：「女子與小人最難相處：親近就不恭敬，疏遠就怨恨。」', analysis: '此句含明顯的古代性別與階層偏見，不應作為現代評價女性或任何群體的依據；可視為當時家內權力關係的片面表述。' },
  'lun-yu_ch-17_p-27': { translation: '孔子說：「到了四十歲還被人厭惡，這一生也就差不多了。」', analysis: '重點是長期累積的人格與人際後果；人仍可反省改變，不必把它理解成不可逆的宿命。' },
  'lun-yu_ch-18_p-1': { translation: '微子離開殷國，箕子淪為奴隸，比干因勸諫而死。孔子說殷有三位仁人。', analysis: '三人以離去、忍辱與死諫回應暴政，孔子肯定不同處境中的守仁。' },
  'lun-yu_ch-18_p-2': { translation: '柳下惠做獄官，三次被罷免。有人問何不離開，他說若按正道侍人，到哪裡不會三次被罷？若歪曲正道侍人，又何必離開父母之邦？', analysis: '柳下惠選擇守正，即使因此受挫；不以換地求仕取代原則。' },
  'lun-yu_ch-18_p-3': { translation: '齊景公說不能像對季氏那樣待遇孔子，只能給介於季孟之間的待遇，又說孔子老了不能用，孔子便離開。', analysis: '待遇與任用若不相稱，孔子選擇離去而非勉強依附。' },
  'lun-yu_ch-18_p-4': { translation: '齊國送女樂給魯國，季桓子接受後三天不上朝，孔子便離開。', analysis: '統治者沉溺享樂、荒廢政務，與孔子的政治理想衝突。' },
  'lun-yu_ch-18_p-5': { translation: '楚國狂人接輿唱歌經過孔子，感嘆鳳鳥德衰，說過去不可挽回、未來還可追，現在從政者危險。孔子下車想談，他快步避開。', analysis: '接輿以隱者立場勸孔子放棄政治，孔子則仍願溝通。' },
  'lun-yu_ch-18_p-6': { translation: '長沮、桀溺一起耕田，孔子派子路問渡口。桀溺說天下到處混亂，何必跟著避某些人的讀書人，不如跟避開整個亂世的隱士。孔子聽後悵然說不能和鳥獸同群，不與人群相處又和誰相處？天下若有道，我也不必去改變。', analysis: '此段呈現隱世與入世的根本分歧；孔子選擇留在人世努力改善。' },
  'lun-yu_ch-18_p-7': { translation: '子路落後遇到荷蓧老人。老人譏諷他不勤勞、不分五穀，怎算老師；但留他住宿、殺雞煮黍並引見兒子。孔子說他是隱者，派子路回去已不見。子路說不仕不合義：長幼之節不可廢，君臣之義怎可廢？君子出仕是為實行義，知道道不行仍要盡責。', analysis: '文本讓隱者與子路各自陳述立場，核心是潔身退隱與承擔人倫責任的張力。' },
  'lun-yu_ch-18_p-8': { translation: '列出伯夷、叔齊等逸民。孔子說伯夷叔齊不降低志向、不辱沒身分。', analysis: '孔子特別稱許二人不因現實壓力放棄志節。' },
  'lun-yu_ch-18_p-9': { translation: '孔子說柳下惠、少連雖降低志向、受辱，言行仍合倫理；虞仲、夷逸隱居放言，身守清白、退隱合權變；自己則不同，沒有一定可或不可。', analysis: '孔子承認不同退隱策略各有可取，自己選擇依情境與道義判斷。' },
  'lun-yu_ch-18_p-10': { translation: '魯國多位樂官分別逃往齊、楚、蔡、秦、河、漢、海等地。', analysis: '樂官流散反映魯國禮樂政治的衰敗。' },
  'lun-yu_ch-18_p-11': { translation: '周公告誡魯公：君子不遺棄親族，不使大臣抱怨未被任用；老朋友無大過不拋棄；不要求一人樣樣完美。', analysis: '用人與待人要兼顧親情、信義與不求全責備。' },
  'lun-yu_ch-18_p-12': { translation: '周朝有八位賢士：伯達、伯适、仲突、仲忽、叔夜、叔夏、季隨、季騧。', analysis: '此段保存八士名錄，表示周代人才的典範。' },
  'lun-yu_ch-20_p-1': { translation: '本段記堯授舜、舜授禹，強調誠實把握中道、四海困窮便失天祿；又記商湯禱告以己罪自任、周朝重賞善人，並提出校正度量法制、復興廢國絕世、舉用逸民，以及重視人民、食、喪、祭。最後說寬得眾、信得任、敏有功、公使人悅服。', analysis: '匯集古代理想政治的要點：中道、責任歸己、民生制度、尊賢與公信。' },
  'lun-yu_ch-20_p-2': { translation: '子張問如何從政。孔子說尊五美、屏四惡。五美是施惠不浪費、使人勞而不怨、有欲不貪、安泰不驕、有威不猛；四惡是不教而殺、未告誡就要求完成、命令怠慢卻催期限、分配財物過於吝嗇。', analysis: '孔子以具體行政行為說明好政府：順民所利、先教後責、命令清楚、資源公平。' },
  'lun-yu_ch-20_p-3': { translation: '孔子說：「不懂天命，不能成為君子；不懂禮，不能立身；不懂言語，不能了解人。」', analysis: '君子修養需要理解更高原則、行為規範與他人言語。' },
  'lun-yu_ch-19_p-1': { translation: '子張說：「讀書人遇到危險肯獻出生命，見到利益想到義，祭祀想到敬，喪事想到哀，這就可以了。」', analysis: '子張以危、利、祭、喪四種情境概括士的道德判斷。' },
  'lun-yu_ch-19_p-2': { translation: '子張說：「持守德行不寬廣，信奉道理不堅定，怎能算有？怎能算沒有？」', analysis: '德與道若沒有真實力量，名義上有無都失去意義。' },
  'lun-yu_ch-19_p-3': { translation: '子夏門人問怎樣交友。子張說子夏主張可交的就交、不可交的拒絕；自己聽到的是尊重賢者、包容眾人，嘉許善者、憐憫能力不足者。若自己極賢何人不能容？若不賢別人會拒我，何必先拒人？', analysis: '子張主張更寬廣包容的交友觀，也保留與子夏不同的教育取向。' },
  'lun-yu_ch-19_p-4': { translation: '子夏說：「即使小技藝也有可觀之處；但想走遠路恐怕被它束縛，所以君子不專門從事。」', analysis: '小道有價值，但不宜取代通向整體人生之道的學習。' },
  'lun-yu_ch-19_p-5': { translation: '子夏說：「每天知道自己還不懂什麼，每月不忘已會的本領，可以算好學。」', analysis: '好學兼具補足未知與鞏固已知。' },
  'lun-yu_ch-19_p-6': { translation: '子夏說：「廣博學習而志向堅定，切實發問而從近處思考，仁就在其中。」', analysis: '仁不是遠離生活的概念，而在扎實學問與近身反思中形成。' },
  'lun-yu_ch-19_p-7': { translation: '子夏說：「各種工匠在作坊完成工作，君子靠學習達成他的道。」', analysis: '如同技藝需練習，君子的道也需經由持續學習達致。' },
  'lun-yu_ch-19_p-8': { translation: '子夏說：「小人犯錯一定要加以文飾掩蓋。」', analysis: '掩飾錯誤阻礙改過；誠實承認是修養起點。' },
  'lun-yu_ch-19_p-9': { translation: '子夏說：「君子有三種變化：遠望威嚴，接近溫和，聽他說話嚴正。」', analysis: '理想人格兼有威儀、親和與原則。' },
  'lun-yu_ch-19_p-10': { translation: '子夏說：「君子要先得到百姓信任才使他們勞作，不然會被當成虐待；先得到信任才勸諫，不然會被當成毀謗。」', analysis: '信任是領導與諫言能發揮效果的前提。' },
  'lun-yu_ch-19_p-11': { translation: '子夏說：「大德不超越界限，小德偶有出入可以。」', analysis: '大原則不可破壞；細節可有彈性，但不可用此曲解為放棄倫理底線。' },
  'lun-yu_ch-19_p-12': { translation: '子游批評子夏門人只會灑掃應對等末節，沒有根本。子夏說子游說過頭：君子之道有先後難易，如草木分品類；誰能從頭到尾全教，只有聖人。', analysis: '教育有次第，基本禮節不是無用末節，但也要能通向更深修養。' },
  'lun-yu_ch-19_p-13': { translation: '子夏說：「做官有餘力就學習，學習有餘力就做官。」', analysis: '學與仕可相互滋養；不宜理解成讀書唯一目的是做官。' },
  'lun-yu_ch-19_p-14': { translation: '子游說：「喪事把哀痛做到充分就停止。」', analysis: '喪禮重真實哀思，而非無盡外在排場。' },
  'lun-yu_ch-19_p-15': { translation: '子游說：「我的朋友子張，能做很難的事，但還沒有仁。」', analysis: '才能與刻苦不必然等於仁，仁還需內在關懷與分寸。' },
  'lun-yu_ch-19_p-16': { translation: '曾子說：「子張氣勢堂堂，難和他一起實行仁。」', analysis: '子張的強勢人格可能使平等互敬的仁道難以展開。' },
  'lun-yu_ch-19_p-17': { translation: '曾子說：「我聽老師說，人沒有能充分表現自己的時候，必是在父母喪事時。」', analysis: '親喪最能考驗人是否真有孝與哀，不只是表面禮節。' },
  'lun-yu_ch-19_p-18': { translation: '曾子說：「孟莊子的孝其他人也可做到，唯有不改父親的臣子與政令最難。」', analysis: '在守喪期間承續父志與既有秩序，被視為一種難得的孝行。' },
  'lun-yu_ch-19_p-19': { translation: '孟氏任陽膚做獄官，問曾子。曾子說上位者失道，百姓離散很久；若查得案情，應哀憐同情，不要因此高興。', analysis: '司法不可把定罪當成成就，應理解犯罪與社會失序的背景。' },
  'lun-yu_ch-19_p-20': { translation: '子貢說：「紂王的不善未必像傳說那麼嚴重，因此君子討厭居於惡名最下游，天下的惡都會歸到他身上。」', analysis: '惡名容易累積傳說與投射；評價歷史人物仍需審慎。' },
  'lun-yu_ch-19_p-21': { translation: '子貢說：「君子的過錯像日月蝕：犯錯時人人看得見，改正後人人又仰望。」', analysis: '公開承認並改正錯誤，反能恢復信任與敬重。' },
  'lun-yu_ch-19_p-22': { translation: '衛國公孫朝問孔子向誰學。子貢說文王武王之道未墜於地，賢者記得大的，不賢者記得小的，人人都有一些；老師何處不能學，何必有固定老師？', analysis: '孔子的學問廣泛取資於文化傳承與眾人，不局限單一師承。' },
  'lun-yu_ch-19_p-23': { translation: '叔孫武叔說子貢賢於孔子。子貢說自己的牆只及肩，可見室家；孔子之牆數仞，找不到門進去便看不見宗廟之美與百官之盛，能進門的人很少，武叔這樣說也不奇怪。', analysis: '子貢以宮牆比喻孔子學問深廣，並表明外人難窺全貌。' },
  'lun-yu_ch-19_p-24': { translation: '叔孫武叔毀謗孔子。子貢說無用，孔子不可毀；他人的賢如丘陵還可越過，孔子如日月不可越過。有人想自絕於日月，又傷得到日月嗎？只是顯出不自量。', analysis: '子貢以強烈比喻維護孔子，重點是偉大價值不因毀謗而減損。' },
  'lun-yu_ch-19_p-25': { translation: '陳子禽說子貢只是謙恭，孔子怎會比他賢。子貢說一句話可顯智慧也可顯無知，不能不慎；孔子難以企及如天不可登階而上。若孔子得到國家，會使人安立、引導人前行、安撫來歸、動員而和；生時榮耀、死時哀痛，怎能及得上？', analysis: '子貢藉理想政治教化描繪孔子不可替代的影響力，也提醒慎言。' },
  'lun-yu_ch-3_p-25': { translation: '孔子評論《韶》樂說：「美極了，也善極了。」評論《武》樂說：「美極了，卻還沒有完全善。」', analysis: '孔子不只看藝術美感，也看音樂背後的政治倫理：相傳《韶》象徵禪讓，《武》象徵征伐。' },
  'lun-yu_ch-3_p-26': { translation: '孔子說：「居上位卻不寬厚，行禮卻不恭敬，面對喪事卻不哀傷，我還看什麼呢？」', analysis: '寬、敬、哀是政治、禮儀與喪葬的內在精神；缺少它們，外在形式便沒有意義。' },
  'meng-zi_ch-1_p-1': { translation: '孟子拜見梁惠王。王問他遠道而來能給魏國什麼利益。孟子答：「王何必只談利？只要談仁義就夠了。」若國君問怎麼利國、大夫問怎麼利家、士庶問怎麼利身，上下互相爭利，國家就危險。仁者不遺棄父母，義者不把君主放後面；王應說仁義，不必只說利益。', analysis: '孟子並非否定一切利益，而是反對讓私利成為政治與人際關係最高原則；仁義能避免上下互相侵奪。' },
  'meng-zi_ch-1_p-2': { translation: '梁惠王在池邊看鴻雁麋鹿，問賢者也喜歡這些嗎。孟子說賢者才真正能享樂，不賢者即使擁有也不快樂。文王建臺池雖用民力，百姓卻樂於參與，把它稱靈臺、靈沼，因文王與民同樂；夏桀使百姓苦到想和他同死，即使有臺池鳥獸也無法獨樂。', analysis: '統治者的享受是否正當，取決於是否建立在人民安樂與共同參與上。' },
  'meng-zi_ch-1_p-3': { translation: '梁惠王說自己很盡心：河內饑荒便遷民、運糧，河東也是如此，卻不見本國人口增加、鄰國人口減少。孟子用戰場比喻：有人逃一百步、有人逃五十步，五十步不能笑百步，都是逃。接著說若不違農時、保護水產山林，人民便能養生送死無憾；給家庭桑田、畜養時機與教育，使老人有衣食、百姓不飢寒，就是王道。若豬狗吃人食、路有餓死者卻說是年成的錯，和殺人說是兵器的錯一樣；不要怪年成，人民自然來。', analysis: '孟子批評梁惠王的救災只是程度較輕的失政，提出民生、資源永續、教育與責任政治的整套王道方案。' },
  'meng-zi_ch-1_p-4': { translation: '梁惠王願受教。孟子問用棍殺人和用刀殺人有何不同，王說沒有；再問用刀與用政策殺人有何不同，王也說沒有。孟子說廚房有肥肉、馬廄有肥馬，百姓面帶飢色、野外有餓死者，這是驅使野獸吃人。身為人民父母卻施政到此，怎能稱父母？', analysis: '政策造成的飢餓與直接暴力同樣有道德責任；孟子以尖銳比喻要求統治者正視結構性傷害。' },
  'meng-zi_ch-1_p-5': { translation: '梁惠王說魏國屢敗受辱，想替死者雪恥。孟子說百里之地也可行王道：施仁政、減刑罰、薄稅、讓民安心耕作；使壯者有餘暇修孝悌忠信。敵國剝奪人民農時，使其家人凍餓離散；若魏國救濟人民再出征，誰會替敵人作戰？所以仁者無敵。', analysis: '孟子把國防根基放在民心與民生，而非單靠武器；「仁者無敵」是政治正當性帶來的凝聚力。' },
  'meng-zi_ch-1_p-6': { translation: '孟子見梁襄王後說，他不像有威儀的君主。王突然問天下何時安定，孟子答安定在統一；能統一的是不喜殺人的人。天下如旱苗，若有雲雨便立刻復生；如今君主多嗜殺，若有不嗜殺者，人民會伸長脖子盼望並如水向下般歸附。', analysis: '孟子把停止嗜殺視為得到天下民心的基本條件，人民歸向被比作自然水勢。' },
  'meng-zi_ch-1_p-7': { translation: '齊宣王問齊桓、晉文霸業。孟子說不談霸術，只談王道：保護人民便無人能阻。孟子以王不忍見牛無罪赴死、改用羊為例，說這顆不忍之心足以行王道；問題不是不能施恩，而是恩只到禽獸、沒推及百姓。孟子區分真正不能與不願做，勸王把敬愛自家老幼的心推及他人，並批評擴張土地、稱霸諸侯是緣木求魚。最後提出制民之產、使家庭足以養親養子、再教導禮義，以及桑田畜養庠序教育等民生方案。', analysis: '此段是孟子王道政治的核心：惻隱之心須「推恩」至人民；國力根本是穩定生計、教育與民心，而非侵略擴張。' },
  'meng-zi_ch-2_p-1': { translation: '莊暴說齊王和他談愛好音樂，孟子說若王真愛音樂，齊國還有希望。孟子問王，王承認只愛世俗音樂。孟子說今樂古樂都可，關鍵是獨樂不如與人同樂、與少數同樂不如與眾人同樂。若王奏樂狩獵而百姓因徭役離散便怨恨；若百姓安樂便會關心王是否健康。能與民同樂，便可行王道。', analysis: '孟子不禁絕君主享樂，而要求享樂不以人民痛苦為代價，並成為共享福祉。' },
  'meng-zi_ch-2_p-2': { translation: '齊宣王問文王七十里園囿是否太大。孟子說百姓還嫌小，因可採柴、捕雉兔，與民共享。齊王四十里園囿卻像國中陷阱，殺鹿如殺人，百姓嫌大很合理。', analysis: '公共資源的正當性不在面積，而在是否開放共享、是否壓迫人民。' },
  'meng-zi_ch-2_p-3': { translation: '齊王問鄰國相處之道。孟子說仁者能以大事小，智者能以小事大；大事小是樂天，小事大是敬畏天命。王說自己好勇，孟子勸他不要只好匹夫之勇；文王、武王的一怒是為安天下人民。王若一怒而安民，人民會希望他有此大勇。', analysis: '孟子把勇重新定義為保民止亂的政治勇氣，不是逞強好鬥。' },
  'meng-zi_ch-2_p-4': { translation: '齊宣王在雪宮問賢者也有這種快樂嗎。孟子說有：人民得不到這種安樂會責怪君上；君上不與民同樂也不對。以天下人的樂為樂、憂為憂，便能行王道。孟子轉述晏子勸齊景公：先王巡遊是省察農事、補助不足，後世君主卻勞民荒遊、沉溺酒獵。景公聽從，整飭國政、補助不足。', analysis: '巡遊與休閒若服務民生可成善政，若勞民荒亡便是失政。' },
  'meng-zi_ch-2_p-5': { translation: '齊王問該毀明堂嗎。孟子說若想行王政就不必毀，並說文王施仁先照顧鰥寡孤獨。王稱善卻說自己好財、好色；孟子以公劉與太王為例說，君主好財可使百姓也有積蓄，好色可使社會沒有怨女曠夫。', analysis: '孟子不以君主欲望為原罪，而要求把私人偏好轉為人人可共享的生活條件。' },
  'meng-zi_ch-2_p-6': { translation: '孟子問齊王：朋友受託照顧妻子兒女，回來卻發現他們凍餓，該怎辦？王說拋棄朋友。又問獄官不能治官、四境不治怎辦，王對後者顧左右而言他。', analysis: '孟子以層層類比迫使君主面對治理失職的責任。' },
  'meng-zi_ch-2_p-7': { translation: '孟子說真正的故國不只古樹，還有世代賢臣。又教齊王任用、罷黜、處死都不能只聽左右或大夫，應在國人普遍意見後親自查察，確認賢不賢、可不可、罪不罪才決定。', analysis: '孟子要求重視公共意見與親自審察，尤其重大刑罰不可草率。' },
  'meng-zi_ch-2_p-8': { translation: '齊王問湯放桀、武王伐紂是否屬臣弒君。孟子說殘害仁者叫賊，殘害義者叫殘，殘賊之人只是一個獨夫；只聽說誅獨夫紂，沒聽說弒君。', analysis: '孟子以仁義作為統治正當性尺度，否定暴君仍具完整君位道德資格。' },
  'meng-zi_ch-2_p-9': { translation: '孟子說建大宅要信任工師找大木，玉石再貴也交玉工雕琢；治理國家卻要學者放下所學聽君主，和叫玉工不雕玉有何不同？', analysis: '治國應尊重專業與長期學習，不能任意以權力否定專長。' },
  'meng-zi_ch-2_p-10': { translation: '齊國攻燕獲勝，王問該不該占領。孟子說若燕民歡迎便可取，若不歡迎便不可；燕民拿飯食酒漿迎軍，是因想逃離水火，若齊國使水更深火更熱，也會被趕走。', analysis: '軍事行動的正當性取決於人民是否真正受益，不能把初期歡迎當永久授權。' },
  'meng-zi_ch-2_p-11': { translation: '齊占燕後諸侯要救燕，孟子說湯雖小卻因救民而天下盼望。如今燕民受虐，齊軍原可救水火；若殺父兄、擄子弟、毀宗廟、搬重器，便違背救民目的，且會招天下兵。應立刻歸還燕人、停止掠奪、與燕民商議立君後離去。', analysis: '孟子要求占領者以人民利益檢驗行動，提出歸還、止掠與政治自決的原則。' },
  'meng-zi_ch-2_p-12': { translation: '鄒魯交戰，魯穆公說官員死三十三人，百姓不救，殺百姓又殺不完。孟子說饑年時老弱流溝壑、壯者逃散，倉庫卻充實、官員不報，這是上慢下殘；如今百姓只是反過來回應，君主不必怪他們。行仁政，人民自然親近君上、願為長上效死。', analysis: '孟子從長期失政解釋民眾疏離，反對只在危機時責怪人民。' },
  'meng-zi_ch-2_p-13': { translation: '滕文公問小國夾在齊楚間該事誰。孟子說此策難答；若一定要說，就築城挖池，和百姓共同守衛，即使死也不離散，才有可為。', analysis: '小國自保的根本在與人民共守，而非單純選邊站。' },
  'meng-zi_ch-2_p-14': { translation: '滕文公怕齊國築薛威脅。孟子說太王在邠受狄人侵擾而遷岐山，不是想選新地而是不得已；只要努力行善，後世可能有王者，創業者只要留下可承繼基礎，成敗有天命，君主只需強力為善。', analysis: '面對外患，孟子強調長遠道德建設與可持續基礎，不保證立即成功。' },
  'meng-zi_ch-2_p-15': { translation: '滕文公說小國盡力事大國仍難免禍。孟子說太王以皮幣、犬馬、珠玉事狄都無效，狄人要土地，太王不願以養人的土地害人，便率眾遷岐，邠人如赴市般追隨；也有人主張死守。孟子要文公在兩者中選擇。', analysis: '此段讓君主在守土死戰與遷讓保民間做艱難選擇，價值核心是不能為土地犧牲人民。' },
  'meng-zi_ch-2_p-16': { translation: '魯平公本想見孟子，寵臣臧倉以孟子後喪逾前喪阻止。樂正子說前後身分與家境不同，棺槨衣衾較好不算僭越。孟子說行止有時運，自己不遇魯侯是天命，臧倉不能決定。', analysis: '孟子不把政治失意全歸咎小人，保持對時勢與自身處境的安定。' },
  'meng-zi_ch-3_p-1': { translation: '公孫丑問孟子若在齊國掌權，能否重現管仲晏子功業。孟子說以齊行王道易如反掌：當時齊地廣民眾、人民受虐政之苦，若行仁政，民眾歡悅如解倒懸，功效會超過古人。', analysis: '孟子不以霸業為目標，主張齊國具備行仁政的條件；王道困難不在資源，而在是否把握時勢施仁。' },
  'meng-zi_ch-3_p-2': { translation: '公孫丑問孟子若任齊相會不會動心。孟子說四十歲後不動心，並解釋真正大勇是自省有理時雖千萬人也敢前往；他擅長辨析言辭、培養浩然之氣。浩然之氣至大至剛，靠長久合乎義的行為培養，不能硬求或拔苗助長。孟子又說自己學孔子，而孔子是自有人類以來最卓越的聖人。', analysis: '此段核心是「浩然之氣」：由持續行義累積的道德力量，不是情緒亢奮，也不可急功近利。' },
  'meng-zi_ch-3_p-3': { translation: '孟子說靠武力假借仁義只能稱霸，必須有大國；以德行仁才能稱王，不必靠大國。武力使人服從是力量不足不得已，德行使人內心喜悅誠服。', analysis: '孟子區分霸道與王道：外在壓服短暫，內心認同才穩固。' },
  'meng-zi_ch-3_p-4': { translation: '孟子說仁會帶來榮耀，不仁帶來恥辱；厭惡恥辱卻住在不仁中，如同厭惡濕卻住低窪。應尊德尊士、讓賢能在位，趁國家安閒整頓政刑；若安閒時只娛樂怠惰，是自求禍患。', analysis: '禍福多由自身行為造成，政治要在平時預備而非危機才應對。' },
  'meng-zi_ch-3_p-5': { translation: '孟子說尊賢使能、降低市場關稅、便利旅人、減輕農民負擔、免除不合理居住稅，天下的士商旅農民便願意前來；鄰國人民仰望如父母。能如此便無敵於天下。', analysis: '孟子以人才、商業、交通、農業與稅制構成吸引民心的仁政方案。' },
  'meng-zi_ch-3_p-6': { translation: '孟子說人人都有不忍人之心。看見孩子將掉入井中，人人自然驚惕憐憫，不為討好父母或求名。惻隱、羞惡、辭讓、是非四心，分別是仁義禮智的開端；如同四肢，人應擴充它們，如火初燃、泉初湧，足以安天下。', analysis: '「四端」說明道德感有內在起點，但仍需擴充實踐，並非天生完成。' },
  'meng-zi_ch-3_p-7': { translation: '孟子說做箭的人怕箭傷不了人，做鎧甲的人怕鎧甲傷人，職業選擇不可不慎。仁是天賦的尊爵、人的安宅，不去仁是不智。若以受人役使為恥，不如行仁；仁者像射箭，先端正自己再發箭，射不中不怨勝者，只反求自己。', analysis: '孟子把仁視為最根本的自我安頓，並以射箭說明失敗先自省。' },
  'meng-zi_ch-3_p-8': { translation: '孟子說子路聽人指出過錯便高興；禹聽到善言便拜謝；舜最大之處是樂於和人共同為善，捨己從人，從耕作到當帝都向人取善。因此君子最大的事是和人一起為善。', analysis: '真正偉大不在自以為是，而在樂於受教、採納他人善意並共同成長。' },
  'meng-zi_ch-3_p-9': { translation: '孟子比較伯夷與柳下惠：伯夷不事惡君、不交惡人，極度厭惡污濁；柳下惠不以污君小官為恥，失職不怨、困窮不憫，能與人同處而不失自己。孟子說伯夷太狹隘，柳下惠不夠恭敬，君子不走這兩種極端。', analysis: '孟子肯定二人操守，仍主張君子避免過度潔癖與過度隨和，在原則和包容間取中。' },
  'meng-zi_ch-4_p-1': { translation: '孟子說：「天時不如地利，地利不如人和。」城小卻攻不下，說明天時不如地利；城高池深兵利糧多仍被棄，說明地利不如人和。治民不靠疆界，固國不靠山險，威天下不靠武器；得道者多助，失道者少助，少到親戚背叛，多到天下歸順。', analysis: '政治與戰爭最終取決於民心與正當性，而非地形或武力。' },
  'meng-zi_ch-4_p-2': { translation: '孟子因病未朝，齊王又召，他設法避免失禮。景丑責怪他不敬君命，孟子說齊人不敢以仁義勸王才是最大不敬；天下有爵、齒、德三種尊，德能輔世長民，不可因有爵而輕慢。想有大作為的君主，應親自就教於尊德樂道的臣。', analysis: '孟子強調德的尊嚴與君臣互相成就，拒絕把禮理解為君權對賢者的單向支配。' },
  'meng-zi_ch-4_p-3': { translation: '陳臻問孟子為何在齊不收百金、在宋薛卻收禮。孟子說都對：宋是遠行贐禮，薛是聞有戒備而給的兵餽；齊無特別理由就送錢，是把人當商品收買，君子不能被收買。', analysis: '收不收禮要看目的與情境，關鍵是保持人格獨立，不受賄賂。' },
  'meng-zi_ch-4_p-4': { translation: '孟子責平陸大夫：持戟士兵一天三次失職就罷，饑年卻有老弱死溝壑、壯者逃散，官員怎不負責？如替人放牛羊卻不供草料，當然有罪。後來齊王承認這是自己的罪。', analysis: '孟子以職責類比追究官員與君主對人民生計的責任。' },
  'meng-zi_ch-4_p-5': { translation: '孟子責蚔鼃請做可諫的士師卻數月不說話。蚔鼃諫而不被用便辭職。孟子說有職守者失職要去，有言責者言不被採納要去；自己沒有官守言責，進退較有餘裕。', analysis: '不同身分有不同責任與離職時機，不可一概而論。' },
  'meng-zi_ch-4_p-6': { translation: '孟子以齊卿身分赴滕弔喪，齊王派王驩陪行；來回路上未與他談政事。公孫丑問原因，孟子說既然已有別人處理，自己何必多說。', analysis: '孟子避免無效介入，表現對職責分工的判斷。' },
  'meng-zi_ch-4_p-7': { translation: '孟子葬母回齊，充虞問棺槨是否太美。孟子說古制棺槨有尺度，不只為好看，而是盡人心；有財且合古制便可用，且不讓土直接近親人肌膚，君子不因天下節儉父母。', analysis: '此段反映儒家厚葬親親觀，核心是哀敬與盡心，需放在古代禮制理解。' },
  'meng-zi_ch-4_p-8': { translation: '沈同私問燕可伐嗎，孟子答可，因子噲不能私授燕國、子之不能私受。齊伐燕後有人說孟子勸伐，孟子說只是回答「可伐」；若問誰可伐，會說有天命職責者才可，如殺人可殺但非人人可殺。', analysis: '孟子區分行為是否可受懲與誰有正當權力執行，反對把一般判斷當作任意動武授權。' },
  'meng-zi_ch-4_p-9': { translation: '燕人反叛，齊王慚愧。陳賈以周公任管叔卻反叛為例辯解。孟子說周公不知其會叛，兄弟間失察可理解；古君子有過就改，今君子有過卻順著錯再找藉口。', analysis: '過錯不可怕，拒絕承認、辯護錯誤才使問題擴大。' },
  'meng-zi_ch-4_p-10': { translation: '孟子辭齊卿回家，齊王想給他住處、厚養弟子，請人轉告。孟子說若想富，何必辭十萬收一萬？又以壟斷市場的人為例，說古市是互通有無，登高壟斷市利的人最可鄙。', analysis: '孟子拒絕優厚待遇，批評以公共市場謀私人壟斷利益。' },
  'meng-zi_ch-4_p-11': { translation: '孟子離齊住在晝地，有人想勸他留下，孟子不答而靠几睡，客人不悅。孟子說客人替長者打算卻不懂：魯君身邊若無能理解子思的人，便不能安子思；不是誰拒絕誰，而是缺少相應政治條件。', analysis: '賢者能否留下，不只看個人意願，也看統治者是否具備理解與安置賢者的條件。' },
  'meng-zi_ch-4_p-12': { translation: '尹士批孟子見王不遇就走，離晝還住三夜太拖延。孟子說見王是自己所願，不遇而去不得已；住三夜是希望王改變召回，若王肯用他，不只齊民安，天下也安。尹士聽後承認自己狹小。', analysis: '孟子離去並非賭氣，而是在保留最後勸諫與合作可能。' },
  'meng-zi_ch-4_p-13': { translation: '充虞見孟子離齊面有不悅，提醒君子不怨天不尤人。孟子說時勢不同：五百年必有王者與名世者，距周已久、時機似到；若天要平天下，當世除我還有誰？因此何必不悅。', analysis: '孟子以使命感理解失意，仍不把責任完全推給他人。' },
  'meng-zi_ch-4_p-14': { translation: '孟子離齊住休地，公孫丑問做官不受俸是否古道。孟子說不是；在崇地見王後已有離意，不想改變原則故不受，後又有軍令不能請辭，久留齊非本志。', analysis: '不受祿是特定政治處境下維持獨立的選擇，不是普遍規則。' },
  'meng-zi_ch-5_p-1': { translation: '滕文公做世子時兩度見孟子。孟子講性善，必提堯舜，並說道理只有一個：別人是丈夫、我也是丈夫，何必畏懼；舜是何人、我又是何人，有作為者也可如此。小小滕國約五十里，仍可成為善國；良藥不使人暈眩，病就不會好。', analysis: '孟子以性善與堯舜典範鼓勵世子：國小不妨礙行善政，改革的痛感可能正是療病必要過程。' },
  'meng-zi_ch-5_p-2': { translation: '滕定公去世，世子問孟子喪禮。孟子說父母喪要盡心，三年喪、粗衣粥食是三代通行之制。雖父兄百官反對，世子仍認為責任在自己，居喪五個月不下命令，最後葬禮時哀容哭聲感動四方來客。', analysis: '孟子強調孝喪不是形式，領導者先真誠盡哀，便能帶動群臣與社會。' },
  'meng-zi_ch-5_p-3': { translation: '滕文公問治國，孟子說民生不可緩：人民有固定產業才有穩定心志，否則易陷罪而再受刑是罔民。賢君恭儉禮下、取民有制，採什一稅；要設庠序教育人倫。又說仁政應先正經界，規劃公私田與祿制，讓鄰里互助扶持，公田工作完成後才做私田。', analysis: '孟子把仁政落在土地、稅制、社會保障、教育與社區互助的制度設計。' },
  'meng-zi_ch-5_p-4': { translation: '許行主張賢君應與民並耕。陳相轉學許行之說，批評滕君靠倉廩府庫養自己。孟子逐問許行是否自己織衣、做鍋、造農具，指出他其實以穀物交換百工產品；百工分工並非剝削。治理天下也需要勞心與勞力分工，堯舜禹后稷等聖人正因治水、教農、教人倫而不能親耕。又批評許行以所有物品同價的想法違反物品差異，會擾亂市場。', analysis: '孟子承認勞動尊嚴，卻反對把「人人自給自足」推成治理理想；社會需分工、專業與倫理教育。' },
  'meng-zi_ch-5_p-5': { translation: '墨者夷之想見孟子。孟子質疑墨家主張薄葬，夷之卻厚葬父母，是以自己所輕視的方式事親。夷之說愛不分差等、但施行從親人開始。孟子反問親兄之子能否等同鄰家嬰兒，說天生萬物有一個根本，不是二本；又以人見父母遺體被狐蠅吃而自然不忍、回去掩埋為例，說厚葬有出於人心的道理。夷之聽後沉默而有所領悟。', analysis: '孟子以親親之情與自然惻隱反駁無差等愛，主張人倫關懷有由近及遠的次第。' },
  'meng-zi_ch-6_p-1': { translation: '陳代勸孟子為行王道而暫時屈己見諸侯，說彎一尺可直八尺。孟子以虞人不受非禮召喚、王良拒絕以詭道取獵物為例，說若為利而屈道，甚至彎八尺直一尺也可嗎？自己彎曲的人不能使別人正直。', analysis: '孟子反對為求政治效果犧牲基本原則；手段本身會塑造治理結果。' },
  'meng-zi_ch-6_p-2': { translation: '景春稱公孫衍張儀一怒諸侯懼、安居天下息為大丈夫。孟子說那只是妾婦順從之道。真正大丈夫住仁的廣宅、立禮義正位、行天下大道；得志與民共行，不得志獨行其道，富貴不能迷惑、貧賤不能改變、威武不能屈服。', analysis: '孟子重定義大丈夫：不是權勢與威懾，而是獨立人格與仁義。' },
  'meng-zi_ch-6_p-3': { translation: '周霄問古君子是否急於做官。孟子說想仕是為行職責，如農夫耕作，但又說君子厭惡不循正道求仕，像未經父母媒妁私奔一樣可恥。', analysis: '孟子區分有責任感的出仕與不擇手段求官。' },
  'meng-zi_ch-6_p-4': { translation: '彭更問孟子後車眾多、到諸侯處受供養是否過分。孟子說不合道一飯不可受，合道則舜受天下也不算過分；社會有分工，工匠以技藝受食，守先王仁義之道並教後學者也有功，何可輕視？', analysis: '孟子為讀書傳道者的社會支持辯護，強調應按實際貢獻而非猜測動機評價。' },
  'meng-zi_ch-6_p-5': { translation: '萬章問小宋國行王政若被齊楚攻打怎辦。孟子以湯征葛、周人受歡迎為例說，討伐殘暴者是救民於水火；只要行王政，四海人民都盼望歸附，齊楚雖大不必畏。', analysis: '孟子把國家安全根本放在人民支持與正當性，而非只看軍力大小。' },
  'meng-zi_ch-6_p-6': { translation: '孟子問戴不勝：楚大夫想讓兒子學齊語，應找齊人還是楚人教？若一齊人教、眾楚人干擾，再打也難成；若放在齊地數年，想要他說楚語也難。孟子說一個薛居州再善，也無法獨自改變宋王周遭全是不善者的環境。', analysis: '環境與群體風氣對人的影響強大，政治改革需改變整個用人與近侍結構。' },
  'meng-zi_ch-6_p-7': { translation: '公孫丑問孟子為何不見諸侯。孟子說古時不做臣便不見；段干木、泄柳避得太過，但被逼迫可見。陽貨以禮送豚，孔子依禮回拜，不能不見。這可看出君子有所養成，不願脅肩諂笑或未同道便苟合。', analysis: '不見諸侯不是傲慢，而是維持獨立與合禮交往的界線。' },
  'meng-zi_ch-6_p-8': { translation: '戴盈之說什一稅和免關市稅今年做不到，先減輕、明年再完全取消如何。孟子說像每天偷鄰雞的人，知道不義卻說每月少偷一隻等明年才停；既知不義，應立刻停止。', analysis: '孟子批評用漸進改革作為明知不義仍持續的藉口。' },
  'meng-zi_ch-6_p-9': { translation: '公都子問孟子為何好辯。孟子說不是好辯而是不得已：歷史治亂循環，禹治洪水、周公除暴、孔子作春秋以正人心；當時楊朱為我、墨翟兼愛之說充滿天下，孟子怕邪說堵塞仁義，故辯楊墨以承繼先聖。', analysis: '孟子把辯論視為守護仁義秩序的責任，不是求口才勝負；此亦反映儒家對楊墨的強烈批判。' },
  'meng-zi_ch-6_p-10': { translation: '匡章稱陳仲子為廉士，餓極才吃蟲蛀李子。孟子說他在齊士中可稱突出，但若把操守推到底，得像蚯蚓才可能：他住的屋、吃的米不知是否也來自不義者；他嫌兄長俸祿不義而離兄母，卻又接受妻子與母親提供的食物，標準矛盾。', analysis: '孟子批評脫離現實關係、無法一致實行的極端廉潔，主張道德判斷須能自洽。' },
  'meng-zi_ch-7_p-1': { translation: '孟子說再明的離婁、再巧的公輸子不用規矩不能畫方圓；堯舜之道不用仁政不能治天下。只有善心不足以為政，只有法令也不能自行；應遵先王之道。上位者若無道揆、下位者無法守，禮學廢弛，國亡只是時間問題。責難君主叫恭，陳善閉邪叫敬，說君主不能叫害君。', analysis: '仁心、制度、規範與敢諫缺一不可；孟子反對只有口頭善意或只有冷硬法令。' },
  'meng-zi_ch-7_p-2': { translation: '孟子說規矩是方圓極則，聖人是人倫極則；君臣都應效法堯舜。治理不仁會使國亡身危，惡名百世難改，應以夏亡為殷的借鑑。', analysis: '仁與不仁是政治存亡的根本分野，歷史可作道德警鐘。' },
  'meng-zi_ch-7_p-3': { translation: '孟子說三代以仁得天下、以不仁失天下，國家興亡也是如此；君主、大夫、士庶若不仁，各自都難保。厭惡死亡卻喜不仁，如厭惡醉卻硬喝酒。', analysis: '不仁是自我毀滅的根源，不能同時求其後果避免。' },
  'meng-zi_ch-7_p-4': { translation: '孟子說愛人卻不被親近，要反省自己的仁；治理不成，要反省智慧；以禮待人不回應，要反省敬。事情不成皆先反求自己，身正天下自然歸附。', analysis: '自省不是自責一切，而是先檢查自身可改變的德行與方法。' },
  'meng-zi_ch-7_p-5': { translation: '孟子說人常說天下國家，天下根本在國，國根本在家，家根本在自身。', analysis: '公共秩序由個人修身、家庭關係逐層建立。' },
  'meng-zi_ch-7_p-6': { translation: '孟子說為政不難，重點是不得罪巨室；巨室所景仰，一國景仰，一國景仰，天下景仰，德教便遍及四海。', analysis: '此反映當時宗族士大夫的擴散影響；治理需處理關鍵社會網絡。' },
  'meng-zi_ch-7_p-7': { translation: '孟子說有道時小德服務大德、小賢服務大賢；無道時小國弱者受大國強者支配。若以此為恥，應效法文王行仁；國君好仁便天下無敵，不以仁求無敵如手熱不去洗。', analysis: '孟子把強弱困局的出路放在仁政與道德典範。' },
  'meng-zi_ch-7_p-8': { translation: '孟子說不仁者安於危險、以災害為利、以亡國之事為樂，難與言。人必先自侮才遭人侮，家先自毀才被毀，國先自伐才被伐；天災可避，自作孽不可活。', analysis: '外患常有內在失政的條件；自我破壞會招致更大傷害。' },
  'meng-zi_ch-7_p-9': { translation: '孟子說桀紂失天下是失民心；得民心的方法是使人民想要的得以聚集、厭惡的不加給他們。人民歸仁如水向下；獺趕魚入淵、鷹趕鳥入林，桀紂則把人民趕向湯武。', analysis: '民心不是宣傳取得，而是以滿足合理需要、不施加痛苦而來。' },
  'meng-zi_ch-7_p-10': { translation: '孟子說自暴者不能同談，自棄者不能同做；說話違禮義是自暴，認為自己不能居仁行義是自棄。仁是安宅，義是正路，捨宅不住、捨路不走很可悲。', analysis: '最大的障礙有時是人先否定自己可以向善與實踐正道。' },
  'meng-zi_ch-7_p-11': { translation: '孟子說道在近處卻向遠處找，事本容易卻求得困難；人人親愛父母、敬重長者，天下便平。', analysis: '宏大政治倫理從日常親親敬長開始。' },
  'meng-zi_ch-7_p-12': { translation: '孟子說下位者要獲上信任才可治民；要得上信任先得朋友信任，要得朋友信任先使父母喜悅，要使父母喜悅先誠於自身，要誠身先明白善。誠是天道，求誠是人道。', analysis: '信任鏈從內在誠善擴及家庭、朋友、政治，不可跳過根本。' },
  'meng-zi_ch-7_p-13': { translation: '伯夷、太公避紂而居北海東海，聽聞文王善養老人便前往；天下兩位大老歸附，如天下父親歸附，其子自然隨往。諸侯若行文王之政，七年內必能主政天下。', analysis: '尊老與仁政可吸引最有道德聲望者，進而形成民心歸附。' },
  'meng-zi_ch-7_p-14': { translation: '冉求做季氏宰不能改其不仁，還加倍徵糧，孔子說可鳴鼓攻擊。孟子說君主不行仁政卻使其富都被孔子棄絕，何況為他強行作戰？爭地爭城殺人盈野盈城，是率土地吃人肉，罪不容死；善戰者罪最重。', analysis: '孟子嚴厲譴責以土地利益發動戰爭與替權貴聚斂。' },
  'meng-zi_ch-7_p-15': { translation: '孟子說觀人沒有比看眼睛更好。眼睛藏不住惡：內心正則明亮，內心不正則昏亂；聽其言、看其眼，人怎能藏得住？', analysis: '此為傳統觀人說法，應謹慎理解：現代判斷人仍需依事實與行為，不能只憑眼神。' },
  'meng-zi_ch-7_p-16': { translation: '孟子說恭敬的人不侮辱人，節儉的人不掠奪人；侮辱掠奪人民的君主只怕人民不順從，怎能稱恭儉？恭儉豈是聲音笑容可裝出來的？', analysis: '真正恭儉要看是否尊重人民權益，不能只看儀態與口號。' },
  'meng-zi_ch-7_p-17': { translation: '淳于髡問男女授受不親是否合禮，孟子說是；又問嫂嫂溺水可否拉手救，孟子說不救如豺狼，平常不親是禮，救溺拉手是權變。髡又問天下人都溺水，孟子為何不救，孟子說天下溺要以道援救，嫂溺才以手救，難道要用手救天下嗎？', analysis: '孟子用「經」與「權」說明原則需因情境調整，但社會問題須以制度與道理處理。' },
  'meng-zi_ch-7_p-18': { translation: '公孫丑問君子為何不親自教子。孟子說父親教子必以正，子不從便怒，父子互相傷害；古人易子而教。父子間不以責善相逼，否則疏離，是最大不祥。', analysis: '孟子關注親子關係中的權力與情感，主張教育可由他人協助以保全親情。' },
  'meng-zi_ch-7_p-19': { translation: '孟子說事親最大，守身最大；失去自身德行便不能真正事親。曾子奉養父親，撤下酒肉必請父親分給誰，問有餘必說有，重在承親志；曾元只想把剩食再端上，是養口體。', analysis: '孝不只是供養，還要守住人格並理解父母心志。' },
  'meng-zi_ch-7_p-20': { translation: '孟子說一般人不值得爭辯，政事不值得細究；只有大人能改正君主內心的不正。君主仁、義、正，國家就安定。', analysis: '孟子把改變政治的關鍵放在君主道德轉化，但也可能有其時代侷限。' },
  'meng-zi_ch-7_p-21': { translation: '孟子說有意外的讚譽，也有求全責備的毀謗。', analysis: '外界評價常失準，不可全然依賴。' },
  'meng-zi_ch-7_p-22': { translation: '孟子說人輕易說話，是因沒有人要求他負責。', analysis: '言語若不用承擔後果，便容易浮誇失實。' },
  'meng-zi_ch-7_p-23': { translation: '孟子說人的毛病在於喜歡做別人的老師。', analysis: '過度好為人師易忽略自身學習與對方需要。' },
  'meng-zi_ch-7_p-24': { translation: '樂正子隨子敖到齊後才來見孟子。孟子問他也來見我嗎，得知已來多日，便責他不應等住處安定才求見長者；樂正子認錯。', analysis: '孟子強調求學者應主動尊師，不可把生活安排置於求道之前。' },
  'meng-zi_ch-7_p-25': { translation: '孟子對樂正子說，你跟子敖來只是為吃喝，我沒想到你學古道卻為飲食而來。', analysis: '批評讀書人若把依附權貴、求口腹當成目的，就背離了學道。' },
  'meng-zi_ch-7_p-26': { translation: '孟子說不孝有三，沒有後代最重大；舜未告父母就娶妻，是因怕無後，君子仍認為等於告知。', analysis: '此段反映古代宗祧傳承觀與舜的特殊處境，不能簡化為現代婚姻或生育義務。' },
  'meng-zi_ch-7_p-27': { translation: '孟子說仁的實質是事親，義的實質是敬從兄長；智是知道二者不離，禮是調節修飾二者，樂是樂於二者，快樂到手舞足蹈。', analysis: '孟子把仁義禮智樂的根基放在家庭倫理的親親敬長。' },
  'meng-zi_ch-7_p-28': { translation: '孟子說天下都喜悅歸附舜，舜卻視為草芥；他認為不得父母歡心便不算人，不順父母便不算子。舜盡力事親，使瞽瞍喜悅，天下父子關係因而安定，這叫大孝。', analysis: '舜的典範在於把親子和解視為比天下歸附更根本的價值。' },
  'meng-zi_ch-8_p-1': { translation: '孟子說舜是東夷人，文王是西夷人，地域相隔千里、時代相差千年，但在中國行其志時如符節相合；先聖後聖，準則相同。', analysis: '聖人價值不受地域與時代限制，仁義有可共通的標準。' },
  'meng-zi_ch-8_p-2': { translation: '子產用自己的車在溱洧渡人。孟子說這是惠而不知為政：應在固定時節建人行橋與車橋，使人民不苦於涉水；怎能逐一渡每個人？逐一討好每人，一天也不夠。', analysis: '善政要建立普遍可用的公共設施，而非只靠個別恩惠。' },
  'meng-zi_ch-8_p-3': { translation: '孟子對齊王說：君待臣如手足，臣待君如腹心；待臣如犬馬，臣待君如國人；待臣如土芥，臣待君如寇仇。若君主採納諫言、惠澤百姓、容臣有故離去並保留田里，舊臣可服喪；若諫不行言不聽、無惠民、離去還被逼迫奪田，就是寇仇，何服之有。', analysis: '孟子提出君臣關係的互惠責任，忠誠以仁政與禮待為基礎。' },
  'meng-zi_ch-8_p-4': { translation: '孟子說無罪殺士，大夫可以離去；無罪殺民，讀書人可以遷徙。', analysis: '面對無道暴政，不合作與離開可成為道德選擇。' },
  'meng-zi_ch-8_p-5': { translation: '孟子說君主仁，臣民沒有不仁；君主義，臣民沒有不義。', analysis: '領導者的示範會深刻影響整個政治社會風氣。' },
  'meng-zi_ch-8_p-6': { translation: '孟子說不合禮的禮、不合義的義，大人不做。', analysis: '形式或名稱不能取代實質正當性。' },
  'meng-zi_ch-8_p-7': { translation: '孟子說合乎中道者應教養不合中道者，有才者應教養無才者，所以人樂有賢父兄；若賢者拋棄不肖者，彼此差別就小得不可計。', analysis: '賢能的價值在於扶持他人，而非藉優越感排斥。' },
  'meng-zi_ch-8_p-8': { translation: '孟子說人先有不做的事，然後才可有所作為。', analysis: '道德界線使行動有方向；拒絕不義是積極作為的前提。' },
  'meng-zi_ch-8_p-9': { translation: '孟子說談論別人的不善，應想想日後會有什麼後患。', analysis: '批評他人需審慎，避免傳播傷害與製造不可收拾的關係後果。' },
  'meng-zi_ch-8_p-10': { translation: '孟子說孔子不做過分的事。', analysis: '聖人行事有分寸，不在本分之外任意加碼。' },
  'meng-zi_ch-8_p-11': { translation: '孟子說大人說話不必句句守信、行動不必每件果決，只看是否合義。', analysis: '信與果需受更高的義節制，不能死守承諾而造成不義。' },
  'meng-zi_ch-8_p-12': { translation: '孟子說大人是不失去赤子之心的人。', analysis: '赤子之心指真誠、惻隱與未被私欲扭曲的本心。' },
  'meng-zi_ch-8_p-13': { translation: '孟子說供養父母在世不足以算大事，真正能承擔大事的是辦好父母身後之禮。', analysis: '此為古代孝喪觀，強調慎終；不應忽略在世照顧同樣重要。' },
  'meng-zi_ch-8_p-14': { translation: '孟子說君子依道深入學習，是要自己真正得到；自得便安住，安住便根基深，根基深便左右取用都能找到源頭。', analysis: '深學不是背誦，而是內化到能自在應用。' },
  'meng-zi_ch-8_p-15': { translation: '孟子說廣博學習、詳細闡說，最後是要回歸到簡要的道理。', analysis: '學問由博返約，重在掌握統整原理而非資訊堆積。' },
  'meng-zi_ch-8_p-16': {
    translation: '孟子說：以善行壓服別人，未必能使人真心服從；以善行涵養、成全別人，才能使天下人心服。若天下人不心服，便不可能成為真正的王者。',
    analysis: '孟子把仁政理解為「養人」而非道德施壓；政治正當性須建立在民心的實際感受上。',
  },
  'meng-zi_ch-8_p-17': {
    translation: '孟子說：話說得沒有實在根據，是不祥的事；遮蔽、壓抑賢能的人，也要承擔這種罪過。',
    analysis: '言論必須負責，人才也不可遭到埋沒；此處把失實與蔽賢都視為傷害公共秩序的行為。',
  },
  'meng-zi_ch-8_p-18': {
    translation: '徐子問孔子為何常稱讚水。孟子說：有源頭的泉水滾滾湧出，日夜不停，盈滿水窪後再流向四海；有根本的人也是如此。若名聲超過實際德行，就像七、八月的暴雨，雖能填滿溝渠，卻很快乾涸。',
    analysis: '水的譬喻說明德行與學問要有持久根源；沒有根本而只追逐聲名，終究不能長久。',
  },
  'meng-zi_ch-8_p-19': {
    translation: '孟子說：人和禽獸的差別本來只有一點點；一般人常把它丟掉，只有君子能保存它。舜並非天生有異，只是依循仁義去實行。',
    analysis: '人之可貴在能守住仁義，不在於先天身分。舜是實踐的典範，而非遙不可及的例外。',
  },
  'meng-zi_ch-8_p-20': {
    translation: '禹厭惡甘美的酒，喜歡正直有益的話；湯執守中道；文王愛民如同照看受傷者，望向天下如同害怕有人跌入深淵。武王也用這些道理治理天下。周公想到天下尚有人未得其所，便像自己推人落入溝中一樣不安。',
    analysis: '這段以聖王相承，描寫理想領導者的節制、納諫與同理心；「不安」表示對人民處境的責任感。',
  },
  'meng-zi_ch-8_p-21': {
    translation: '孟子說：聖王的事跡消失後，詩的教化也衰微，於是《春秋》出現。《春秋》所記，大抵是齊桓公、晉文公一類的事；孔子說那是他的心志所在。',
    analysis: '孟子將《春秋》視為政治與道德秩序衰落時的褒貶之書，藉歷史評價保存價值判準。',
  },
  'meng-zi_ch-8_p-22': {
    translation: '孟子說：君子的恩澤傳到第五代便會衰斷；小人的恩澤也到第五代而斷。孔子去世已久，我沒有親受其教，只能私下仰慕、學習他的學問。',
    analysis: '孟子說明自己與孔子沒有直接師承，仍以經典與志向承接儒家傳統；重點在學統的自覺延續。',
  },
  'meng-zi_ch-8_p-23': {
    translation: '孟子說：可以拿的卻不拿，會傷害人的惠澤；不可以拿卻去拿，會傷害廉恥。可以給卻不給，會傷害人的仁愛；不可以給卻給了，會傷害恩義。可以死卻不死，會傷害勇；不可以死卻去死，也會傷害勇。',
    analysis: '德行不是僵硬地選擇「拿、給、死」的一端，而要辨別情境是否合宜；不合宜的善行也可能傷德。',
  },
  'meng-zi_ch-8_p-24': {
    translation: '逢蒙向羿學射，學成後以為天下只有羿勝過自己，便殺了羿。後來庾公之斯追殺子濯孺子，得知子濯是自己老師的老師，便不忍以師道加害；他抽出箭頭，只用無鏃的箭輕扣車輪，隨即離去。',
    analysis: '故事對比忘恩害師與敬師守義：技藝可傳，德義才決定一個人如何使用技藝。',
  },
  'meng-zi_ch-8_p-25': {
    translation: '孟子說：西施即使很美，若沾滿不潔之物，人們也會掩鼻；人即使本來惡劣，只要齋戒沐浴，仍可用來祭祀上帝。',
    analysis: '以祭祀潔淨作比喻，說明人能透過自我整飭改變狀態；不是以出身或一時名聲永久定人。',
  },
  'meng-zi_ch-8_p-26': {
    translation: '孟子說：天下談性，都要從既有的事實和常理去求；智的可貴在於不穿鑿附會。禹治水只是順著水勢疏導；智者處事也應掌握事物本來的道理。',
    analysis: '孟子反對脫離事實的玄談，主張智慧須順應事理；禹治水是因勢利導的典型。',
  },
  'meng-zi_ch-8_p-27': {
    translation: '孟子在公行子的喪禮上沒有同右師交談。弟子不解，孟子說：依禮，彼此不經過對方的位次，也不跨越臺階相見；右師既然沒有依禮來見，我又怎能主動違禮交談？',
    analysis: '此段不是鼓勵冷漠，而是說明在正式禮儀場合，交往的方式也要符合雙方身分與程序。',
  },
  'meng-zi_ch-8_p-28': {
    translation: '孟子說：君子保存仁心，以禮待人。仁者愛人，有禮者敬人；愛人者常受人愛，敬人者常受人敬。若有人橫逆相加，君子先反省自己是否不仁、無禮；反省而無過，便說對方大概是狂妄之人。君子一生憂心的是不能像舜那樣，至於一時的困難，則不必憂慮。',
    analysis: '先反求諸己是修養方法，但並非把所有惡意都歸咎於自己；完成自省後，仍可辨識對方的無理。',
  },
  'meng-zi_ch-8_p-29': {
    translation: '禹、稷三次經過家門而不進去，並非不孝，因為天下正遭洪水與飢荒；顏子住在陋巷也不改其樂，並非不盡力，因為當時天下安定。情勢不同，所做的事也不同，但他們所守的道理相同。',
    analysis: '孟子主張道德實踐要回應處境：公共危難時優先救民，平世則可專心修養；不能只看表面行為。',
  },
  'meng-zi_ch-8_p-30': {
    translation: '匡章被齊人認為不孝，孟子卻與他往來。孟子說，世人所說的不孝有五種，而最嚴重的是貪圖享受、不顧父母供養；匡章的情形不是如此。他只是急於以善相責，父子互相責備善行，反而傷害親情，所以才與父親不相見。',
    analysis: '孟子細辨「不孝」的實質，不以流言定罪；同時提醒親子之間雖重視向善，也要避免以苛責傷害恩情。',
  },
  'meng-zi_ch-8_p-31': {
    translation: '曾子住在武城，越寇來攻，他先讓人撤走，自己最後才離開；子思住在衛國，齊寇來攻，卻說自己不能離開。孟子說，兩人互換位置，也都會做出對方那樣的選擇。',
    analysis: '是否去留取決於職分與局勢，不可只用單一準則評斷。孟子藉此反對離開具體處境的道德比較。',
  },
  'meng-zi_ch-8_p-32': {
    translation: '儲子問：孟子為何和一般人不同？孟子回答：堯、舜和一般人有什麼不同呢？',
    analysis: '孟子的回答意在打破聖凡絕對區隔：聖人並非另一種人，而是把人本有的可能充分實踐。',
  },
  'meng-zi_ch-8_p-33': {
    translation: '齊國有個人，妻妾都以為他能和權貴同飲同食；其實他每天向掃墓祭祀的人乞討殘餘酒肉，吃飽後又向妻妾誇耀。孟子說，世上為求富貴而使妻妾以他為榮的人，回頭看其實沒有不令人羞愧的。',
    analysis: '以諷刺故事揭露假借權勢與名利的虛榮；批評的是欺瞞親近者、失去自尊的求祿方式。',
  },
  'meng-zi_ch-9_p-1': {
    translation: '萬章問舜在田間仰天哭泣是為何，孟子說是因為既怨又思慕父母。舜雖盡力耕作、盡子職，仍因父母不愛他而無所歸依；即使得到天下士人擁戴、娶得帝女、富有天下、尊為天子，都不能解除這份憂傷，只有得到父母順愛才可以。人年少慕父母，成年後各有所慕；大孝者終身思慕父母，孟子在舜身上看見這一點。',
    analysis: '孟子以「怨慕」解釋孝：不是沒有痛苦或情緒，而是在受傷中仍保有親愛與盼望。舜的孝不等於父母必然慈愛。',
  },
  'meng-zi_ch-9_p-2': {
    translation: '萬章問舜為何不告知父母就娶妻。孟子說，若告知便不能成婚，而男女成室是人生大倫，因此舜不得不如此。又問舜明知弟弟象曾企圖害他，為何仍真心歡迎象。孟子以子產受騙放魚的故事說明：君子可在合乎常理的事情上被人欺騙，卻不會被無道理的詭計蒙蔽；象以愛兄的姿態來見，舜便依此真誠相待。',
    analysis: '此段同時處理倫理衝突與信任：孟子承認禮法可能受現實阻礙，也強調舜保持善意並非不知危險，而是不預設以惡回應他人。',
  },
  'meng-zi_ch-9_p-3': {
    translation: '萬章問象極不仁，舜為何不處罰反而封他在有庳。孟子說，仁人對弟弟不積怒、不留怨，只想親愛他；希望弟弟富貴，所以封他。所謂「放」象，是指象不能自行治理封國，由天子派官吏管理並收取貢賦；這既不讓象害民，也讓舜仍能常常見到弟弟。',
    analysis: '孟子試圖兼顧親情與公共治理：對親人可有愛，但不能把人民置於危險中；封而不使其專政，是文本中的制度性安排。',
  },
  'meng-zi_ch-9_p-4': {
    translation: '咸丘蒙說傳聞稱盛德之士連君父都不能把他當臣子兒子，並問堯是否曾北面朝舜。孟子否認，說這是荒誕傳言：堯年老時舜只是攝政，堯死後舜還率諸侯為他服喪三年。對「普天之下，莫非王土」等詩句，也不能只扣字面，應依上下文理解說話人的心志。舜身為天子，反而用天下來奉養父親，正是尊親、養親的極致。',
    analysis: '本段提出重要的讀詩原則：「不以文害辭，不以辭害志，以意逆志」；解釋經典須看語境與意旨，不能斷章取義。',
  },
  'meng-zi_ch-9_p-5': {
    translation: '萬章問堯是否把天下直接交給舜。孟子說，天子不能把天下私相授受；所謂天給舜，是以舜辦事有成、百姓安服來顯示。舜服喪後避居，不去逼近堯的兒子；諸侯朝見、百姓訟獄、民間歌詠卻都歸向舜，他才就位。這正是「天視自我民視，天聽自我民聽」的意思。',
    analysis: '孟子以民眾的實際歸向作為「天命」的可見表現，反對將政治正當性理解為君主的私人贈與。',
  },
  'meng-zi_ch-9_p-6': {
    translation: '孟子否認禹以後便只傳位給兒子而不傳賢人的說法：天若屬意賢者就給賢者，若屬意兒子就給兒子。禹死後，益避讓啟，百姓因啟是禹之子而歸向他；舜、禹施惠日久，啟又能承接禹道，情勢不同於益。伊尹放逐失德的太甲，太甲悔改三年後再迎回；益、伊尹、周公都未奪位。孔子所說禪讓與世襲，根本義理是一致的。',
    analysis: '孟子把繼承是否合法繫於德行、民心與時勢，不以禪讓或世襲的形式本身作唯一標準。',
  },
  'meng-zi_ch-9_p-7': {
    translation: '萬章問伊尹是否靠廚藝求見湯。孟子否認：伊尹在有莘耕作，樂於堯舜之道；不合義道，即使給他天下也不顧，一點不義之物也不取不與。湯多次聘請後，他想到若能使君主和百姓行堯舜之道，便負起先覺者教化後覺者的責任，於是輔佐湯伐夏救民。',
    analysis: '孟子藉伊尹說明入仕的條件：不是以技藝和私利求進，而是以公共教化與救民為承擔，且不可先委屈義理。',
  },
  'meng-zi_ch-9_p-8': {
    translation: '萬章問孔子在衛、齊是否依附地位卑下的人。孟子說這是好事者捏造。孔子在衛依靠顏讎由；彌子瑕雖許以官位，孔子只說有命。他進退依禮義，得不得官都安於命；若依附癰疽或侍人，便是無義也無命。考察一個人的近臣，要看他所事奉的人；孔子遭難時所依靠的也都是合義之士。',
    analysis: '孟子藉駁傳聞維護孔子的人格，並提出判斷人物交遊的原則：看其所依與所行，而非聽取獵奇傳言。',
  },
  'meng-zi_ch-9_p-9': {
    translation: '萬章問百里奚是否賣身餵牛，以五張羊皮求取秦穆公。孟子說不是。百里奚知道虞公不可勸而離開，又知道秦穆公可共事才輔佐他，使秦國君主顯名於天下。若一個鄉里自愛的人都不會賣身求進，怎能說賢者會這樣做？',
    analysis: '孟子以百里奚的知人與擇主，反駁把賢者說成不擇手段攀附權勢的故事；重點仍是合義與自重。',
  },
}

